window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q06"]=window.__LIBQ["pham-nhan-tu-tien"]["q06"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q06"]["factions"]={"updatedAt":"2026-07-16","count":170,"factions":[{"id":"quy-linh-mon","name":"Quỷ Linh Môn","cn":"鬼靈門","aliases":[],"type":"tong-mon","typeLabel":"Tông môn","diaBan":"Thiên Nam","nhanVatChinh":[],"blurb":"Tông môn phát hiện phương pháp nhập Trụy Ma Cốc, ban đầu muốn độc chiếm bảo vật nhưng bị các tông phái lớn bức bách phải phát hành Trụy Ma Lệnh bài thu linh thạch, tổ chức đợt nhập cốc quy mô vài trăm tu sĩ.","detail":"Nửa năm trước truyền ra tin tìm được phương pháp vào Trụy Ma Cốc. Ban đầu cường ngạnh từ chối cho người ngoài cùng nhập cốc, muốn độc chiếm bảo vật. Bị các tông phái (cả sáu tông lớn, ma đạo) bức bách, cuối cùng phải nhượng bộ — đề ra phương pháp phát Trụy Ma Lệnh bài thu linh thạch. Ngoài ra tung hơn một trăm lệnh bài cho tông phái nhỏ và tán tu. Có trưởng lão từng vào Trụy Ma Cốc, chỉ nguyên anh trốn về còn thân thể bỏ lại trong cốc.","nguonGoc":"Chưa rõ","trangThai":"hưng","tabs":{"tienTrinh":[{"chuong":"@c0793","loai":"mo-rong","importance":"major","giaiDoan":"Phát hiện phương pháp nhập Trụy Ma Cốc, tổ chức đợt nhập cốc","trangThaiMoc":"hưng","text":"Truyền tin tìm ra phương pháp vào Trụy Ma Cốc. Bị các tông phái lớn bức bách phải phát hành Trụy Ma Lệnh bài, thu linh thạch, cho phép vài trăm tu sĩ cùng nhập cốc.","anchor":"Quỷ Linh Môn bọn họ cũng đã tung ra hơn một trăm cái lệnh bài cho các tông phái nhỏ và các vị tán tu"}]},"capNhatToi":"@c0793","nguon":["@c0793"]},{"id":"thien-truc-giao","name":"Thiên Trúc Giáo","cn":"","type":"giao-phai","typeLabel":"Giáo phái","diaBan":"Không rõ","nhanVatChinh":["Đại Diễn Thần Quân","Hàn Lập"],"blurb":"Giáo phái do Đại Diễn Thần Quân khai sáng và lập ra năm xưa. Hiện trạng không rõ.","detail":"Thiên Trúc Giáo được Đại Diễn Thần Quân khai sáng và lập ra. Ngoài thông tin này, hiện trạng và quy mô của giáo phái chưa được tiết lộ thêm.","nguonGoc":"Do Đại Diễn Thần Quân khai sáng","lanhDaoHienThoi":"Không rõ (Đại Diễn Thần Quân là người sáng lập, hiện chỉ còn tinh hồn)","lanhDaoMoc":[{"ten":"Đại Diễn Thần Quân","tuChuong":"@c0795","denChuong":""}],"tabs":{"tienTrinh":[{"chuong":"@c0795","loai":"nhac-toi","importance":"major","giaiDoan":"Lần đầu được nhắc đến","trangThaiMoc":"Không rõ hiện trạng","text":"Hàn Lập vạch trần thân phận Đại Diễn Thần Quân là người khai sáng và lập ra Thiên Trúc Giáo năm xưa.","anchor":"ngươi lại là Đại Diễn Thần Quân khai sáng và lập ra Thiên Trúc Giáo năm đó"},{"chuong":"@c0969","loai":"nhắc tới","importance":"major","giaiDoan":"Di nguyện đoạt lại","text":"Đại Diễn Thần Quân yêu cầu Hàn Lập sau này tới cực tây chi địa đoạt lại Thiên trúc giáo và đưa đệ tử kế thừa y bát lên làm giáo chủ.","anchor":"Bây giờ người cầm quyền tại thiên trúc giáo, căn bản không phải xuất thân từ môn hạ của lão phu"}]},"capNhatToi":"@c0795","nguon":["@c0795","@c0969"],"trangThai":"đang chờ Hàn Lập đoạt lại theo di nguyện","thanhVien":[{"ten":"Đại Diễn Thần Quân","chucVu":"người khai tông lập phái liên quan truyền thừa","tuChuong":"@c0969","trangThai":"đã tọa hóa"}]},{"id":"tan-quoc-ma-tong","name":"Tần quốc Ma Tông","cn":"","type":"ma-tong","typeLabel":"Ma tông","diaBan":"Tần quốc","nhanVatChinh":[],"blurb":"Tông phái ma đạo ở Tần quốc, từng có trưởng lão Nguyên Anh Trung Kỳ bị Hàn Lập giết chết.","detail":"Được nhắc đến khi Nam Lũng Hầu và Lỗ Vệ Anh bàn về danh tiếng Hàn Lập — hắn đã giết một vị trưởng lão Nguyên Anh Trung Kỳ đỉnh giai của tông phái này.","nguon":["@c0801"]},{"id":"yem-nguyet-tong","name":"Yểm Nguyệt Tông","cn":"掩月宗","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Thiên Nam","nhanVatChinh":["Trưởng lão Yểm Nguyệt Tông","Nam Cung Uyển"],"blurb":"Tông môn ở Thiên Nam, trưởng lão là sư tỷ của Nam Cung Uyển, tu vi Nguyên Anh kỳ.","detail":"Trưởng lão Yểm Nguyệt Tông là nữ tử sắc mặt tái nhợt băng lãnh, sư tỷ của Nam Cung Uyển. Cùng Lệnh Hồ lão tổ (Hoàng Phong Cốc) và một lão giả lạ mặt hướng đến Trụy Ma Cốc.","thanhVien":[{"ten":"Trưởng lão Yểm Nguyệt Tông","chucVu":"Trưởng lão","tuChuong":"@c0802","trangThai":"gan-bo"},{"ten":"Nam Cung Uyển","chucVu":"Đệ tử","tuChuong":"@c0802","trangThai":"gan-bo"}],"tabs":{"tienTrinh":[{"chuong":"@c0802","loai":"nhắc tới","importance":"bridge","giaiDoan":"Trưởng lão đến Trụy Ma Cốc","text":"Trưởng lão Yểm Nguyệt Tông cùng Lệnh Hồ lão tổ phi hành hướng Trụy Ma Cốc.","anchor":"bên cạnh hắn là một nữ tử sắc mặt tái nhợt, chính là nữ tử băng lãnh, trưởng lão Yểm Nguyệt Tông sư tỷ của Nam Cung Uyển"}]},"nguon":["@c0802"]},{"id":"lam-hai-tong","name":"Lam Hải tông","cn":"蓝海宗","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Vọng Thủy Quốc","nhanVatChinh":[],"blurb":"Tông môn đã bị diệt sát toàn bộ tu sĩ bởi Phi Thiên Tử Vân hạt xuất hiện ở Vọng Thủy Quốc.","detail":"Lam Hải tông là một tông môn ở Vọng Thủy Quốc, toàn bộ tu sĩ đã bị đám Tử Vân hạt diệt sát. Sự kiện này dẫn đến cuộc vây sát Tử Vân hạt có sự tham gia của nhiều thế lực, trong đó có Thiên Cực Môn với đại biểu là Lỗ Vệ Anh khi còn trẻ.","trangThai":"đã bị diệt","nguon":["@c0814"]},{"id":"phat-tong","name":"Phật Tông","cn":"佛宗","type":"faction","typeLabel":"Tông phái","diaBan":"","nhanVatChinh":["Đại Diễn Thần Quân","Hàn Lập","Lão tăng Phật tông lông mày trắng","Đại hòa thượng gầy như củi","Đại hòa thượng béo như heo"],"blurb":"Tông phái tu luyện Phật đạo, sở hữu các pháp trận đặc thù như Tiểu tu di kim cương trận.","detail":"Phật Tông được nhắc đến khi Lỗ Vệ Anh nhận ra ký hiệu trên vách tường đại sảnh dưới lòng đất là Tiểu tu di kim cương trận — một pháp trận thuộc Phật Tông. Điều khiến lão bất ngờ là pháp trận Phật Tông lại xuất hiện trong bảo tàng được phong ấn bởi Huyết chú chi môn (cấm chế tà môn), gợi ý lai lịch phức tạp của chủ nhân nơi này.","nguon":["@c0823","@c0885","@c0924","@c0948"],"tabs":{"tienTrinh":[{"chuong":"@c0885","loai":"nhắc tới","importance":"normal","giaiDoan":"Giải sát khí","text":"Đại Diễn Thần Quân nói công pháp Phật tông thường có phật lực và thất sắc linh quang, hữu hiệu với việc giải sát khí.","anchor":"công pháp Phật tông hầu hết đều là tu luyện pháp lực ẩn chứa phật lực"},{"chuong":"@c0924","loai":"nhắc tới","importance":"normal","giaiDoan":"liên quan Minh Vương Quyết","text":"Phật tông được nhắc là bên cải biến công pháp yêu tộc thành Minh Vương Quyết và có thể có cách giảm đau khi luyện pháp quyết này.","trangThaiMoc":"được nhắc","anchor":"Phật tông nếu đã có biện pháp đem yêu tộc công pháp biến thành như vậy"},{"chuong":"@c0948","loai":"nhắc tới","importance":"normal","giaiDoan":"Đấu giá hội ngày đầu","text":"Phật tông được thể hiện qua ba cao tăng áo xám và được Hàn Lập đánh giá là thế lực có địa vị ngang Đạo Nho tại Đại Tấn.","anchor":"Phật tông tại Đại Tấn có thể cùng Đạo Nho ngang hàng"}]},"trangThai":"Được nhắc như nguồn bí thuật giải sát khí","aliases":["Phật môn"],"thanhVien":[{"ten":"Lão tăng Phật tông lông mày trắng","chucVu":"cao tăng","tuChuong":"@c0948","trangThai":"đang hoạt động"},{"ten":"Đại hòa thượng gầy như củi","chucVu":"cao tăng","tuChuong":"@c0948","trangThai":"đang hoạt động"},{"ten":"Đại hòa thượng béo như heo","chucVu":"cao tăng","tuChuong":"@c0948","trangThai":"đang hoạt động"}]},{"id":"thien-nam-tu-dai-the-luc","name":"Thiên Nam tứ đại thế lực","cn":"天南四大势力","type":"lien-minh","typeLabel":"Liên minh","diaBan":"Thiên Nam","nhanVatChinh":[],"blurb":"Bốn thế lực lớn nhất vùng Thiên Nam, cao tầng của họ từng giao dịch với Mộ Lan tộc để cho phép Mộ Lan pháp sĩ vào Trụy Ma Cốc.","detail":"Được Trọng Thần Sư nhắc đến: cơ hội Mộ Lan tộc vào Trụy Ma Cốc là do giao dịch với cao tầng Thiên Nam tứ đại thế lực. Thành phần cụ thể và nội dung giao dịch chưa rõ.","nguon":["@c0824"]},{"id":"thanh-gioi","name":"Thánh giới","cn":"","type":"the-luc-ngoai-gioi","typeLabel":"Thế lực giới khác","diaBan":"Không rõ — ngoài giới hiện tại","nhanVatChinh":["Thánh tổ (nhắc tên, chưa xuất hiện)","Tà hồn tự xưng “bổn tôn” (đoạt xá Nam Lũng Hầu)"],"blurb":"Thế lực bí ẩn từ giới khác, được kẻ đoạt xá thoát ra từ viên bát cổ bảo nhắc đến, tuyên bố giới này phải thuộc về thánh giới.","detail":"Thế lực hoàn toàn xa lạ với tu sĩ đương thời, lần đầu được nhắc đến qua lời tà hồn thoát khỏi phong ấn viên bát cổ bảo trong điện thờ dưới đáy thủy đàm. Sau khi đoạt xá thành công thân xác Nam Lũng Hầu (thần thức Nguyên Anh Trung Kỳ) chỉ trong thời gian cực ngắn, kẻ này tự xưng “bổn tôn”, nhắc đến “thánh tổ” như bậc lãnh đạo tối cao và tuyên bố một giới này nhất định phải thuộc về thánh giới. Lỗ Vệ Anh — tu sĩ Nguyên Anh Trung Kỳ — nghe đến “thánh tổ”, “thánh giới” thì kinh sợ, hoàn toàn không biết các khái niệm này, cho thấy quy mô và nguồn gốc của thế lực vượt ngoài hiểu biết của giới tu tiên hiện hữu. Thành viên thoát phong ấn thể hiện thực lực kinh khiếp: biến dị thân xác thành quỷ trảo hắc khí, tay không gạt pháp khí, tốc độ vượt độn thuật, một quyền xuyên thủng Hạo dương sa hộ thân.","nguon":["@c0829"]},{"id":"hoang-phong-coc","name":"Hoàng Phong cốc","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Thiên Nam","nhanVatChinh":["Lệnh Hồ lão tổ"],"blurb":"Tông môn có liên hệ với Lệnh Hồ lão tổ. Trong biến cố ở Trụy Ma cốc, Lệnh Hồ lão tổ lo nếu bỏ mặc Ngụy Vô Nhai thì Hoàng Phong cốc có thể gặp đại họa.","detail":"Khi cân nhắc có cứu Ngụy Vô Nhai hay không, Lệnh Hồ lão tổ không chỉ nghĩ đến an nguy cá nhân mà còn sợ Ngụy Vô Nhai sống sót sẽ truy cứu, kéo theo hậu quả cho Hoàng Phong cốc.","nguon":["@c0843"]},{"id":"linh-gioi-tu-si","name":"Linh giới tu sĩ","type":"khac","typeLabel":"Nhóm tu sĩ","diaBan":"Linh giới","nhanVatChinh":[],"blurb":"Đây là cách Hàn Lập suy đoán về chủ thể có thể đã bố trí lớp cấm chế bạc trong tàn tích Linh Miểu Viên. Chương này mới dừng ở mức suy đoán, chưa xác nhận cụ thể người lập cấm chế.","detail":"Khi quan sát lớp ngân sa cấm chế ở đỉnh không gian, Hàn Lập cho rằng chỉ những tồn tại thuộc Linh giới mới có khả năng bố trí loại cấm chế như vậy. Tuy nhiên, danh tính thực sự của người bày cấm chế và tổ chức đứng sau vẫn chưa được xác định.","nguonGoc":"Suy đoán của Hàn Lập về người bố trí cấm chế trong tàn tích Linh Miểu Viên","quyMo":"Không rõ","trangThai":"Chưa xác minh cụ thể","capNhatToi":"@c0854","nguon":["@c0854"]},{"id":"gia-toc-ho-hoang-linh-lan-son","name":"Gia tộc họ Hoàng Linh Lân sơn","cn":"","aliases":["Hoàng gia Linh Lân sơn","Gia tộc họ Hoàng"],"type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"Linh Lân sơn, Trữ Châu, Đông Dụ quốc","nhanVatChinh":["Hoàng Nguyên Minh"],"blurb":"Gia tộc mạnh nhất trong ba nhà tu tiên nhỏ ở Linh Lân sơn. Dù đứng đầu khu vực, họ cũng chỉ có hai tu sĩ Trúc Cơ và dựa nhiều vào linh tuyền vô danh.","detail":"Gia tộc họ Hoàng cùng hai nhà Lý, Vương chia giữ ba ngọn núi quanh linh mạch Linh Lân sơn. Trưởng lão Hoàng Nguyên Minh có tu vi Trúc Cơ Trung Kỳ, được xem là đệ nhất tu sĩ Linh Lân sơn và chủ trì nghi thức mở linh tuyền.","quyMo":"Tiểu gia tộc tu tiên, có hai tu sĩ Trúc Cơ @c0855","caoThuManhNhat":"Hoàng Nguyên Minh @c0855","thanhVien":[{"ten":"Hoàng Nguyên Minh","chucVu":"Trưởng lão","tuChuong":"@c0855","trangThai":"đang thuộc"}],"quanHe":"Cùng hai gia tộc họ Lý và họ Vương thông hôn, liên kết giữ linh tuyền @c0855","trangThai":"đang tồn tại @c0855","tabs":{"tienTrinh":[{"chuong":"@c0855","loai":"nhắc tới","importance":"normal","giaiDoan":"Mạnh nhất ba nhà","text":"Gia tộc họ Hoàng được giới thiệu là nhà mạnh nhất trong ba gia tộc Linh Lân sơn, có trưởng lão Hoàng Nguyên Minh giữ địa vị cao nhất khu vực.","anchor":"Trong các gia tộc này nhà họ Hoàng là mạnh nhất nhưng không muốn nói Kết Đan Tu Sĩ"}]},"capNhatToi":"@c0855","nguon":["@c0855"]},{"id":"gia-toc-ho-ly-linh-lan-son","name":"Gia tộc họ Lý Linh Lân sơn","cn":"","aliases":[],"type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"Linh Lân sơn, Trữ Châu, Đông Dụ quốc","nhanVatChinh":[],"blurb":"Một trong ba gia tộc tu tiên nhỏ cùng chiếm linh mạch Linh Lân sơn. Gia tộc này liên kết với họ Hoàng và họ Vương để giữ linh tuyền vô danh.","detail":"Gia tộc họ Lý cùng hai nhà còn lại chia nhau ba ngọn núi trong khu vực linh mạch nhỏ hơn mười dặm. Chương cho biết hai nhà Lý, Vương yếu hơn họ Hoàng và mỗi bên chỉ miễn cưỡng bồi dưỡng được một tu sĩ Trúc Cơ, nhưng chưa chỉ rõ lão già nào thuộc họ Lý.","quyMo":"Tiểu gia tộc tu tiên, có Trúc Cơ chống giữ @c0855","quanHe":"Liên kết và thông hôn với họ Hoàng, họ Vương để giữ linh tuyền @c0855","trangThai":"đang tồn tại @c0855","tabs":{"tienTrinh":[{"chuong":"@c0855","loai":"nhắc tới","importance":"normal","giaiDoan":"Giữ linh tuyền","text":"Gia tộc họ Lý được giới thiệu là một trong ba tiểu gia tộc cùng giữ linh tuyền Linh Lân sơn.","anchor":"Hai nhà này so với gia tộc họ Hoàng không bằng, miễn cưỡng cũng mới chỉ có thể bồi dưỡng ra được một gã Trúc Cơ Kỳ tu sĩ"}]},"capNhatToi":"@c0855","nguon":["@c0855"]},{"id":"gia-toc-ho-vuong-linh-lan-son","name":"Gia tộc họ Vương Linh Lân sơn","cn":"","aliases":[],"type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"Linh Lân sơn, Trữ Châu, Đông Dụ quốc","nhanVatChinh":[],"blurb":"Một trong ba gia tộc tu tiên nhỏ cùng cư trú tại Linh Lân sơn. Gia tộc này cùng họ Hoàng và họ Lý phong kín, canh giữ linh tuyền vô danh.","detail":"Gia tộc họ Vương cùng hai nhà còn lại dựa vào linh mạch nhỏ tại Linh Lân sơn để tu hành. Chương chỉ nêu hai nhà Lý, Vương yếu hơn họ Hoàng và mỗi bên có một tu sĩ Trúc Cơ chống giữ, chưa xác định trưởng lão nào thuộc họ Vương.","quyMo":"Tiểu gia tộc tu tiên, có Trúc Cơ chống giữ @c0855","quanHe":"Liên kết và thông hôn với họ Hoàng, họ Lý để giữ linh tuyền @c0855","trangThai":"đang tồn tại @c0855","tabs":{"tienTrinh":[{"chuong":"@c0855","loai":"nhắc tới","importance":"normal","giaiDoan":"Giữ linh tuyền","text":"Gia tộc họ Vương được giới thiệu là một trong ba tiểu gia tộc cùng giữ linh tuyền Linh Lân sơn.","anchor":"Hai nhà này so với gia tộc họ Hoàng không bằng, miễn cưỡng cũng mới chỉ có thể bồi dưỡng ra được một gã Trúc Cơ Kỳ tu sĩ"}]},"capNhatToi":"@c0855","nguon":["@c0855"]},{"id":"ba-gia-toc-hoang-ly-vuong-linh-lan-son","name":"Ba gia tộc Hoàng, Lý, Vương Linh Lân sơn","cn":"","aliases":["Ba tộc Hoàng, Lý, Vương","Ba gia tộc thủ hộ Linh tuyền"],"type":"lien-ket","typeLabel":"Liên kết gia tộc","diaBan":"Linh Lân sơn, Trữ Châu, Đông Dụ quốc","nhanVatChinh":["Hoàng Nguyên Minh","Lão già áo xám","Lão già thanh bào"],"blurb":"Liên kết ba gia tộc tu tiên nhỏ cùng chiếm giữ linh mạch và linh tuyền trên Linh Lân sơn. Họ thông hôn gần trăm năm, cùng phong kín linh tuyền và mười năm mở một lần cho đệ tử trẻ.","detail":"Ba gia tộc họ Hoàng, họ Lý và họ Vương chia nhau chủ phong cùng hai ngọn núi phụ cận tại Linh Lân sơn. Vì linh tuyền vô danh có thể hỗ trợ tẩy tủy dịch kinh cho đệ tử Luyện Khí cấp thấp, ba nhà duy trì quy chế chung, tích nước mười năm rồi cử hành nghi thức mở tuyền.","tonChi":"Cùng giữ linh tuyền và duy trì lợi ích tu luyện cho đệ tử trẻ @c0855","quyMo":"Ba tiểu gia tộc, mỗi nhà có lực lượng Luyện Khí và Trúc Cơ chống giữ @c0855","thanhVien":[{"ten":"Hoàng Nguyên Minh","chucVu":"Trưởng lão họ Hoàng","tuChuong":"@c0855","trangThai":"đang thuộc"},{"ten":"Lão già áo xám","chucVu":"Trúc Cơ trưởng lão","tuChuong":"@c0855","trangThai":"đang thuộc"},{"ten":"Lão già thanh bào","chucVu":"Trúc Cơ trưởng lão","tuChuong":"@c0855","trangThai":"đang thuộc"}],"tranPhai":"Pháp trận phong kín linh tuyền @c0855","trangThai":"đang tồn tại @c0855","tabs":{"tienTrinh":[{"chuong":"@c0855","loai":"nhắc tới","importance":"normal","giaiDoan":"Mở linh tuyền","text":"Ba gia tộc cùng cử hành nghi thức mở linh tuyền theo chu kỳ mười năm để chuẩn bị linh trà cho đệ tử trẻ.","anchor":"Chính Linh tuyền này đã khiến cho ba nhà không thể không ràng buộc gắn bó với nhau"}]},"capNhatToi":"@c0855","nguon":["@c0855"]},{"id":"cac-dai-phai-tu-tien-dong-du-quoc","name":"Các đại phái tu tiên Đông Dụ quốc","cn":"","aliases":[],"type":"tong-mon","typeLabel":"Các môn phái tu tiên","diaBan":"Đông Dụ quốc","nhanVatChinh":[],"blurb":"Tập hợp các môn phái tu tiên tại Đông Dụ quốc được lão giả mặt tròn nhắc tới. Các môn phái này thường tuyển đệ tử từ gia tộc tu tiên hoặc khu vực do môn phái khống chế.","detail":"Theo lời giải thích với Hàn Lập, Đông Dụ quốc có nhiều môn phái tu tiên, nhưng tiểu gia tộc mạt lưu khó được họ coi trọng. Vì vậy, các gia tộc nhỏ thường không dám dễ dàng đưa đệ tử kiệt xuất sang tông môn khác.","quyMo":"nhiều môn phái","trangThai":"đang tồn tại","tabs":{"tienTrinh":[{"chuong":"@c0856","loai":"nhắc tới","importance":"normal","giaiDoan":"lão giả mặt tròn giải thích tình hình Đông Dụ quốc","text":"Các đại phái Đông Dụ quốc được mô tả là đông đảo nhưng thường có nguồn tuyển đệ tử riêng, khiến tiểu gia tộc khó chen vào.","anchor":"Tại Đông Dụ quốc chúng ta, các môn phái tu tiên mặc dù đông đảo"}]},"capNhatToi":"@c0856","nguon":["@c0856"]},{"id":"diet-ma-doi","name":"Diệt ma đội","cn":"","aliases":["đội quân diệt ma"],"type":"lien-minh","typeLabel":"Liên minh diệt ma","diaBan":"Thiên Nam","nhanVatChinh":["Tam đại tu sĩ","Đại Thượng Sư Mộ Lan"],"blurb":"Liên minh được lập để vây diệt yêu ma thoát khỏi Trụy Ma cốc. Ban đầu do tam đại tu sĩ tập hợp hơn mười Nguyên Anh trung kỳ, sau có thêm Đại Thượng Sư Mộ Lan tham gia.","detail":"Diệt ma đội truy sát yêu ma sau khi nó liên tục đánh lén cao giai tu sĩ và thôn phệ Nguyên Anh. Khi yêu ma chuyển sang tàn sát gia tộc và tiểu phái, đội quân này lần theo bí thuật của một trưởng lão Ma đạo tới Lạc Hồn sơn.","quyMo":"hơn mười Nguyên Anh trung kỳ cùng cao thủ Mộ Lan","trangThai":"đang truy diệt yêu ma trong lời kể","thanhVien":[{"ten":"Tam đại tu sĩ","chucVu":"người tổ chức","tuChuong":"@c0856","trangThai":"tham gia"},{"ten":"Đại Thượng Sư Mộ Lan","chucVu":"cao thủ tham chiến","tuChuong":"@c0856","trangThai":"tham gia"}],"tabs":{"tienTrinh":[{"chuong":"@c0856","loai":"lập","importance":"major","giaiDoan":"họa yêu ma lan rộng","text":"Tam đại tu sĩ tập hợp hơn mười Nguyên Anh trung kỳ lập đội quân diệt ma, sau đó có thêm Đại Thượng Sư Mộ Lan tham gia để liên thủ vây diệt yêu ma.","anchor":"tổ chức một cái đội quân diệt ma liên thủ vây diệt yêu ma này"}]},"capNhatToi":"@c0856","nguon":["@c0856"]},{"id":"mo-lan-nhan","name":"Mộ Lan nhân","cn":"","aliases":[],"type":"toc-quan","typeLabel":"Thế lực Mộ Lan","diaBan":"không rõ trong chương này","nhanVatChinh":["Đại Thượng Sư Mộ Lan","Mộ Lan thần sư"],"blurb":"Phe Mộ Lan được nhắc trong họa yêu ma sau Trụy Ma cốc. Sau khi bị yêu ma ra tay, họ phái một nhóm Đại Thượng Sư tham gia Diệt ma đội.","detail":"Mộ Lan nhân không đứng ngoài cuộc vây quét vì yêu ma cũng tập kích phía họ. Việc họ phái Đại Thượng Sư tham gia khiến chiến tuyến diệt ma mở rộng ngoài riêng tu sĩ Thiên Nam.","trangThai":"tham gia diệt ma","thanhVien":[{"ten":"Đại Thượng Sư Mộ Lan","chucVu":"cao thủ được phái tham gia Diệt ma đội","tuChuong":"@c0856","trangThai":"tham gia"}],"tabs":{"tienTrinh":[{"chuong":"@c0856","loai":"liên minh","importance":"normal","giaiDoan":"yêu ma tấn công cả Mộ Lan nhân","text":"Mộ Lan nhân phái một nhóm Đại Thượng Sư tham gia Diệt ma đội sau khi yêu ma cũng ra tay với họ.","anchor":"Mộ Lan nhân cũng phái một nhóm Đại Thượng Sư tham gia Diệt ma đội"}]},"capNhatToi":"@c0856","nguon":["@c0856"]},{"id":"tam-dai-tu-si-thien-nam","name":"Tam đại tu sĩ Thiên Nam","cn":"","aliases":["Tam đại tu sĩ"],"type":"nhom-tu-si","typeLabel":"Nhóm tu sĩ đỉnh cấp","diaBan":"Thiên Nam","nhanVatChinh":["Chí Dương thượng nhân","Ngụy Vô Nhai"],"blurb":"Nhóm ba tu sĩ Nguyên Anh Hậu Kỳ nổi bật ở Thiên Nam. Họ được nhắc là đã liên thủ mở Đoạt đảo đại hội sau khi Đại tuyền qua và bảy đảo linh mạch xuất hiện.","detail":"Sau dị biến Đại tuyền qua ở Vô Biên Hải, tam đại tu sĩ liên thủ mở Đoạt đảo đại hội với nhiều tông môn tham gia để phân chia quyền sở hữu các đảo linh mạch. Một thành viên là Chí Dương thượng nhân từng đích thân xuống xoáy nước dò xét nhưng phải quay lên vì áp lực cực lớn.","dinhDanh":"goc","capBac":"tu sĩ đỉnh cấp","quyMo":"ba tu sĩ Nguyên Anh Hậu Kỳ","thanhVien":[{"ten":"Chí Dương thượng nhân","chucVu":"thành viên","tuChuong":"@c0857","trangThai":"đang hoạt động"},{"ten":"Ngụy Vô Nhai","chucVu":"thành viên","tuChuong":"@c0857","trangThai":"được nhắc tới"}],"tabs":{"tienTrinh":[{"chuong":"@c0857","loai":"nhắc tới","importance":"normal","giaiDoan":"Mở Đoạt đảo đại hội","text":"Tam đại tu sĩ được nhắc là liên thủ mở Đoạt đảo đại hội để các tông môn tranh quyền sở hữu bảy đảo quanh Đại tuyền qua.","trangThaiMoc":"đang có ảnh hưởng lớn ở Thiên Nam","anchor":"thậm chí tam đại tu sĩ phải liên thủ mở ra Đoạt đảo đại hội với không ít tông môn cũng tham gia"}]},"capNhatToi":"@c0857","nguon":["@c0857"]},{"id":"that-gia-tu-tien-dai-phai","name":"Thất gia tu tiên đại phái","cn":"","aliases":["Bảy đại phái tu tiên"],"type":"lien-minh-long-le","typeLabel":"Nhóm đại phái tu tiên","diaBan":"Bảy đảo quanh Đại tuyền qua","nhanVatChinh":[],"blurb":"Bảy đại phái tu tiên giành được quyền sở hữu các đảo linh mạch nổi lên quanh Đại tuyền qua. Sự xuất hiện của họ gắn với Đoạt đảo đại hội do tam đại tu sĩ mở ra.","detail":"Sau khi Đại tuyền qua xuất hiện và bảy đảo nhỏ trồi lên với linh khí dày đặc, nhiều tông môn tham gia tranh đoạt. Kết quả là bảy đại phái tu tiên giành được quyền sở hữu các hòn đảo này.","dinhDanh":"goc","quyMo":"bảy đại phái tu tiên","tabs":{"tienTrinh":[{"chuong":"@c0857","loai":"mở rộng/mất địa bàn","importance":"normal","giaiDoan":"Giành đảo linh mạch","text":"Bảy đại phái tu tiên giành quyền sở hữu các đảo linh mạch quanh Đại tuyền qua sau Đoạt đảo đại hội.","trangThaiMoc":"nắm giữ các đảo linh mạch","anchor":"Kết quả là thất gia tu tiên đại phái giành được quyền sở hữu mấy hòn đảo này"}]},"capNhatToi":"@c0857","nguon":["@c0857"]},{"id":"nhac-duong-cung","name":"Nhạc Dương cung","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Đại Tấn","nhanVatChinh":["Nữ tu trẻ ở Nhạc Dương cung"],"blurb":"Tông môn tại Đại Tấn được Đại Diễn Thần Quân nhắc tới như manh mối tìm Hạo Dương Điểu.","detail":"Khi từng du lịch Đại Tấn, Đại Diễn Thần Quân gặp một nữ tu trẻ ở Nhạc Dương cung có nuôi Hạo Dương Điểu. Vì lông Hạo Dương Điểu là tài liệu khó kiếm để luyện Tam Diễm Phiến, nơi này trở thành một đầu mối khả dĩ cho Hàn Lập nếu tới Đại Tấn tìm tài liệu.","nguon":["@c0858"]},{"id":"tu-tien-gioi-dai-tan","name":"Tu tiên giới Đại Tấn","cn":"","type":"khu-vuc-tu-tien","typeLabel":"Khu vực tu tiên","diaBan":"Đại Tấn quốc","nhanVatChinh":["Đại Diễn Thần Quân"],"blurb":"Khu vực tu tiên được Đại Diễn Thần Quân xem là trung tâm tu tiên giới và Thánh địa tu luyện.","detail":"Đại Diễn Thần Quân nhiều lần hướng Hàn Lập tới Đại Tấn, nói nơi đây còn bảo tồn điển tịch cổ và có điều kiện tìm hiểu nguồn gốc yêu tộc, ma công, Cổ ma. Đại Tấn cũng được nhắc là nơi có manh mối Hạo Dương Điểu ở Nhạc Dương cung và cơ hội tìm Xích Hỏa Giao dễ hơn Thiên Nam, liên quan trực tiếp đến việc gom tài liệu luyện Tam Diễm Phiến.","nguon":["@c0858"]},{"id":"yeu-toc","name":"Yêu tộc","cn":"","type":"chung-toc-the-luc","typeLabel":"Chủng tộc / thế lực rộng","diaBan":"Nhân giới; có liên hệ được nhắc tới với Cổ ma giới","nhanVatChinh":["Linh Lung","Ngao Khiếu lão tổ","Tứ đại yêu vương Yêu Tộc"],"blurb":"Chủng tộc được nhắc qua truyền thừa chi bảo Phạm Thánh Chân Phiến và mối liên hệ nghi vấn với ma công, Cổ ma.","detail":"Đại Diễn Thần Quân cho rằng yêu tộc từng tiếp xúc Cổ ma sớm hơn nhân loại, đồng thời có một bộ phận yêu tộc ở nhân giới sau khi tu luyện ma công thì phi thăng tới Cổ ma giới. Hàn Lập liên tưởng điều này với Phạm Thánh Chân Phiến, một truyền thừa chi bảo của yêu tộc có công pháp ba đầu sáu tay giống thủ đoạn Cổ ma, nhưng chương chưa xác nhận quan hệ cụ thể.","nguon":["@c0858","@c1060"],"tabs":{"tienTrinh":[{"chuong":"@c1060","loai":"nhắc tới","importance":"normal","giaiDoan":"tầng cao Yêu Tộc","text":"Nguyên Sát nhắc Tứ đại yêu vương Yêu Tộc khi nhận ra Nghịch Tinh Bàn của Linh Lung.","anchor":"Ngươi cùng Tứ đại yêu vương Yêu Tộc có quan hệ như thế nào"}]},"thanhVien":[{"ten":"Ngao Khiếu lão tổ","chucVu":"yêu vương","tuChuong":"@c1060","trangThai":"đang thuộc"},{"ten":"Linh Lung","chucVu":"đại công chúa bộ tộc Ngân Nguyệt","tuChuong":"@c1060","trangThai":"đang thuộc"}]},{"id":"tam-tong-van-mong-son","name":"Tam tông Vân Mộng Sơn","cn":"","type":"lien-minh","typeLabel":"Nhóm tông môn","diaBan":"Vân Mộng Sơn mạch","nhanVatChinh":["Hàn Lập","Trình sư huynh","Lữ Lạc","Lão giả Kết Đan cầm đầu Bách Xảo Viện"],"blurb":"Nhóm ba môn phái cùng tồn tại trong Vân Mộng Sơn mạch. Chương này nhắc tới bối cảnh ba môn cùng chung một dãy núi và có liên hệ qua việc Hàn Lập sang Bách Xảo Viện dự lễ.","detail":"Tam tông Vân Mộng Sơn được nhắc qua việc ba môn phái cùng chung một dãy núi, từng có Thí Kiếm Đại Hội và nay Bách Xảo Viện tổ chức buổi lễ khiến Hàn Lập, Trình sư huynh và Lữ Lạc cùng tới dự.","trangThai":"đang tồn tại","capNhatToi":"@c0862","nguon":["@c0862"]},{"id":"thai-chan-mon","name":"Thái Chân Môn","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"không rõ","nhanVatChinh":["Chí Dương Thượng Nhân"],"blurb":"Thái Chân Môn là tông môn được Chí Dương Thượng Nhân xưng danh khi đến bái phỏng Bách Xảo Viện.","detail":"Chí Dương Thượng Nhân tự xưng là người Thái Chân Môn khi từ xa đăng môn bái phỏng Liệt Hỏa đạo hữu, qua đó xác định thân phận tông môn của một trong tam đại tu sĩ.","thanhVien":[{"ten":"Chí Dương Thượng Nhân","chucVu":"cao nhân trong môn","tuChuong":"@c0865","trangThai":"đang hoạt động"}],"tabs":{"tienTrinh":[{"chuong":"@c0865","loai":"nhắc tới","importance":"normal","giaiDoan":"Chí Dương xưng danh","text":"Thái Chân Môn được nêu trong lời xưng danh khi Chí Dương Thượng Nhân đến Bách Xảo Viện bái phỏng Liệt Hỏa lão quái.","anchor":"Thái Chân Môn Chí Dương đăng môn bái phỏng. Liệt hỏa đạo hữu có ở đây?"}]},"nguon":["@c0865"]},{"id":"chan-cuc-mon","name":"Chân Cực môn","cn":"","type":"tong-mon","typeLabel":"Đạo môn cổ đại","diaBan":"Đại Tấn tu tiên giới","nhanVatChinh":["Chí Dương Thượng Nhân","Ô Ích"],"blurb":"Chân Cực môn là một trong ba đại đạo môn cổ đại tại Đại Tấn tu tiên giới. Thái Chân môn ở Thiên Nam được tiết lộ là một nhánh của thế lực này, được cử đi trông coi Thượng cổ Phong ấn pháp trận.","detail":"Chí Dương Thượng nhân nói Thái Chân môn thời cổ vốn bắt nguồn từ Chân Cực môn, một trong ba đại đạo môn tại Đại Tấn tu tiên giới. Một nhánh của Chân Cực môn được cử tới Thiên Nam để trông coi Thượng cổ Phong ấn pháp trận dưới Đại tuyền qua.","nguonGoc":"Đạo môn cổ đại tại Đại Tấn tu tiên giới.","quyMo":"Một trong ba đại đạo môn cổ đại Đại Tấn.","quanHe":"Thái Chân môn là nhánh được cử tới Thiên Nam trông coi phong ấn.","trangThai":"không rõ","capNhatToi":"@c0870","tabs":{"tienTrinh":[{"chuong":"@c0870","loai":"nhắc tới","importance":"major","giaiDoan":"Nguồn gốc Thái Chân môn","text":"Chí Dương Thượng nhân tiết lộ Thái Chân môn tại Thiên Nam vốn là một nhánh của Chân Cực môn, thế lực thuộc hàng ba đại đạo môn cổ đại ở Đại Tấn tu tiên giới.","anchor":"Thời cổ đại bổn môn là một trong ba đại đạo môn tại Đại Tấn tu tiên giới “Chân Cực môn”"},{"chuong":"@c0941","loai":"nhắc tới","importance":"normal","giaiDoan":"Liên hệ Ô Ích","text":"Chân Cực môn được nhắc khi Cát Thiên Hào đối đáp với Ô Ích và tỏ ý muốn thỉnh giáo thần thông của môn phái này.","anchor":"Cát mỗ đã sớm muốn thỉnh giáo thần thông của Chân Cực môn"}]},"nguon":["@c0870","@c0941"],"thanhVien":[{"ten":"Ô Ích","chucVu":"Lão đạo","tuChuong":"@c0941","trangThai":"đang hoạt động"}]},{"id":"cuc-chan-mon","name":"Cực Chân Môn","cn":"","aliases":[],"type":"tong-mon","typeLabel":"Tông môn truyền thừa cũ","diaBan":"Đại Tấn","nhanVatChinh":[],"blurb":"Cực Chân Môn được nhắc như truyền thừa cũ có liên hệ xa xưa với Thái Chân Môn. Đến thời điểm hiện tại, phần lớn pháp quyết Thái Chân Môn đã không còn quan hệ với truyền thừa này.","detail":"Trong cuộc nói chuyện về nguồn gốc Thái Chân Môn, Chí Dương thượng nhân cho biết Thái Chân Môn xuất thân Đại Tấn nhưng truyền thừa cũ đã đoạn tuyệt lâu năm. Cực Chân Môn là đầu mối truyền thừa được nhắc tới, song hiện chỉ còn vài công pháp đặc biệt của Thái Chân Môn có thể coi là lưu lại từ xưa.","trangThai":"truyền thừa cũ đã đoạn tuyệt với Thái Chân Môn hiện thời","capNhatToi":"@c0871","tabs":{"tienTrinh":[{"chuong":"@c0871","loai":"nhắc tới","importance":"normal","giaiDoan":"Liên hệ truyền thừa được hé lộ","text":"Cực Chân Môn được nhắc như truyền thừa cũ liên quan tới Thái Chân Môn, nhưng phần lớn pháp quyết hiện tại của Thái Chân Môn đã không còn quan hệ với nguồn này.","anchor":"đại bộ phận pháp quyết hiện tại của bổn môn cùng truyền thừa sớm cùng Cực Chân Môn không hề có quan hệ nữa"}]},"nguon":["@c0871"]},{"id":"chinh-dao-minh","name":"Chính Đạo Minh","cn":"","type":"lien-minh","typeLabel":"Liên minh chính đạo","diaBan":"Khuê Quốc và Thiên Nam","nhanVatChinh":["Chí Dương thượng nhân"],"blurb":"Thế lực được Chí Dương thượng nhân nhắc tới qua hệ thống nội tuyến tại Khuê Quốc. Tin tức từ nội tuyến cho thấy Hàn Lập không có dấu hiệu tranh đoạt hay khống chế địa bàn.","detail":"Trong đánh giá của Chí Dương thượng nhân về Hàn Lập, Chính Đạo Minh có nội tuyến ở Khuê Quốc theo dõi tình hình. Những tin tức này khiến ông tin rằng Hàn Lập tuy có thần thông đủ mạnh nhưng không hề lộ dã tâm tranh bá hay khống chế thế lực.","thanhVien":[{"ten":"Chí Dương thượng nhân","chucVu":"đại tu sĩ liên quan Chính Đạo Minh","tuChuong":"@c0872","trangThai":"đang hoạt động"}],"capNhatToi":"@c0872","nguon":["@c0872"]},{"id":"that-dai-tong-mon-chiem-bay-dao","name":"Thất đại tông môn chiếm bảy đảo","cn":"","type":"lien-minh","typeLabel":"Nhóm tông môn chiếm đảo","diaBan":"Thất Linh Đảo","nhanVatChinh":[],"blurb":"Thất đại tông môn chiếm bảy đảo là nhóm tông môn bề ngoài phân chia bảy linh đảo. Thực chất các tông môn này thuộc ba thế lực lớn đứng sau.","detail":"Trong lời Chí Dương thượng nhân, bảy tòa tiểu đảo nhìn như do bảy đại tông môn phân chia, nhưng các tông môn đó đều thuộc ba thế lực lớn. Nhóm chiếm đảo có liên hệ trực tiếp với đại trận và nghĩa vụ bảo vệ phong ấn pháp trận.","quyMo":"Bảy tông môn chiếm bảy linh đảo","quanHe":"Thuộc sự chi phối của ba thế lực lớn","trangThai":"đang chiếm giữ các linh đảo","capNhatToi":"@c0873","tabs":{"tienTrinh":[{"chuong":"@c0873","loai":"nhắc tới","importance":"normal","giaiDoan":"Cơ chế chiếm đảo","text":"Bảy linh đảo bề ngoài do thất đại tông môn phân chia, nhưng các tông môn này thực chất thuộc ba thế lực lớn.","anchor":"mặc dù thoạt nhìn là bị thất đại tông môn phân chia, nhưng mấy cái tông môn này lại thuộc ba thế lực lớn chúng ta"}]},"nguon":["@c0873"]},{"id":"ba-the-luc-lon","name":"Ba thế lực lớn","cn":"","type":"lien-minh","typeLabel":"Ba thế lực lớn","diaBan":"Khu vực chi phối Thất Linh Đảo","nhanVatChinh":["Ngụy Vô Nhai","Chí Dương thượng nhân","Hợp Hoan lão ma"],"blurb":"Ba thế lực lớn là các thế lực đứng sau những tông môn chiếm bảy linh đảo. Họ có quyền quyết định phân phối tòa linh đảo còn dư cho Lạc Vân Tông.","detail":"Chí Dương thượng nhân nói các tông môn chiếm bảy linh đảo thực chất đều thuộc ba thế lực lớn. Ba thế lực này nắm quyền phân phối tòa linh đảo khó chia và đồng thuận chuyển nó cho Lạc Vân Tông sau khi Hàn Lập nhận nhiệm vụ nguy hiểm.","quyMo":"Chi phối các tông môn chiếm đảo trong Thất Linh Đảo","quanHe":"Đứng sau thất đại tông môn chiếm bảy đảo","trangThai":"đang chi phối việc phân phối linh đảo","capNhatToi":"@c0873","tabs":{"tienTrinh":[{"chuong":"@c0873","loai":"nhắc tới","importance":"normal","giaiDoan":"Quyền phân phối linh đảo","text":"Ba thế lực lớn được nêu là lực lượng đứng sau các tông môn chiếm đảo và có quyền phân phối tòa linh đảo dư.","anchor":"mấy cái tông môn này lại thuộc ba thế lực lớn chúng ta"}]},"nguon":["@c0873"]},{"id":"tu-tien-gioi-thien-nam","name":"Tu tiên giới Thiên Nam","cn":"","aliases":[],"type":"khu-vuc-the-luc","typeLabel":"Khu vực tu tiên tổng thể","diaBan":"Thiên Nam","nhanVatChinh":["Hàn Lập","Ngụy Vô Nhai","Chí Dương thượng nhân"],"blurb":"Không gian tu tiên rộng lớn ở Thiên Nam. Sau nhiều biến cố lớn, nơi này bước vào thời kỳ ổn định, các tông phái chuyển sang tĩnh dưỡng và bồi dưỡng đệ tử.","detail":"Sau chuỗi đại sự liên tiếp, tu tiên giới Thiên Nam bắt đầu ổn định trở lại. Các tông phái trong khu vực tập trung bồi dưỡng môn hạ đệ tử và tiến vào giai đoạn tĩnh dưỡng.","trangThai":"ổn định và tĩnh dưỡng","capNhatToi":"@c0875","tabs":{"tienTrinh":[{"chuong":"@c0875","loai":"nhắc tới","importance":"normal","giaiDoan":"Ổn định sau biến cố","text":"Tu tiên giới Thiên Nam bước vào thời kỳ ổn định, các tông phái tập trung bồi dưỡng đệ tử và tĩnh dưỡng.","trangThaiMoc":"ổn định","anchor":"tu tiên giới Thiên Nam liên tiếp trải qua việc lớn"}]},"nguon":["@c0875"]},{"id":"thuong-lo-bo","name":"Thương Lộ Bộ","cn":"","aliases":[],"type":"bo-lac","typeLabel":"Bộ lạc","diaBan":"Thiên Lan thảo nguyên","nhanVatChinh":["Anh Lộ","Anh San","Thố Mãnh","Hàn Lập"],"blurb":"Thương Lộ Bộ là bộ lạc nhỏ của người Đột Ngột, mới tách ra từ một đại bộ lạc. Bộ lạc có bảy tám vạn người nhưng chưa có tiên sư riêng, nên Anh Lộ phải đưa người có linh căn và cống phẩm tới Thiên Lan thánh điện.","detail":"Thương Lộ Bộ là bộ lạc nhỏ, dân số khoảng bảy tám vạn, địa vị yếu vì chưa bồi dưỡng được tiên sư của riêng mình. Anh Lộ dẫn đội xe đi xa nhiều tháng để tham gia khai linh nhật, hy vọng có người trong bộ lạc học được tiên thuật và trở về bảo vệ tộc nhân.","quyMo":"bảy tám vạn người","lanhDaoHienThoi":"Anh Lộ","trangThai":"Đang trên đường tới thánh điện, chưa có tiên sư trú nhập @c0878","capNhatToi":"@c0877","thanhVien":[{"ten":"Anh Lộ","chucVu":"Tộc trưởng","tuChuong":"@c0877","trangThai":"đang dẫn đội"},{"ten":"Anh San","chucVu":"Thành viên bộ lạc","tuChuong":"@c0877","trangThai":"đi theo đội xe"},{"ten":"Thô Mãnh","chucVu":"Thanh niên bộ lạc","tuChuong":"@c0877","trangThai":"đi theo đội xe"},{"ten":"Hàn Lập","chucVu":"Tiên sư được thuê hộ tống","tuChuong":"@c0878","trangThai":"tạm đi cùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0877","loai":"nhắc tới","importance":"normal","giaiDoan":"Đi khai linh nhật","text":"Thương Lộ Bộ được giới thiệu là bộ lạc nhỏ chưa có tiên sư riêng, phải dốc sức đưa người có linh căn và cống phẩm tới Thiên Lan thánh điện.","anchor":"Thương lộ bộ của lão giả thì còn không có cơ hội bồi dưỡng tiên sư của riêng bộ lạc","trangThaiMoc":"nhỏ yếu"},{"chuong":"@c0878","loai":"nhắc tới","importance":"normal","giaiDoan":"Thuê tiên sư hộ tống","text":"Thương Lộ bộ được giới thiệu là bộ lạc nhỏ chưa có tiên sư trú nhập, đang đi thánh điện triều cống nên Anh Lộ thuê Hàn Lập hộ tống đội xe.","anchor":"Thương Lộ bộ chúng ta chỉ là một bộ lạc nhỏ nên tạm thời còn chưa có tiên sư trú nhập","trangThaiMoc":"Chưa có tiên sư trú nhập, đang đi thánh điện"}]},"nguon":["@c0877","@c0878"]},{"id":"thien-lan-thanh-dien","name":"Thiên Lan thánh điện","cn":"","aliases":[],"type":"co-cau-tu-tien","typeLabel":"Cơ cấu tu tiên","diaBan":"Thiên Lan thảo nguyên","nhanVatChinh":["Thiên Lan thú","Trưởng lão mới thu nhận của Diệp gia","Lâm Ngân Bình"],"blurb":"Thiên Lan thánh điện là hệ thống thánh điện của người Đột Ngột, ban đầu dùng để cung phụng Thiên Lan thánh thú. Về sau nơi này trở thành cơ cấu bồi dưỡng tiên sư cấp thấp cho các bộ lạc.","detail":"Thiên Lan thánh điện giữ vai trò trung tâm khu vực cho hàng ngàn bộ lạc Đột Ngột. Người phàm có linh căn cần tới đây trong khai linh nhật để được khai mở và học tiên thuật, sau đó có thể trở về bộ lạc hoặc được tiên sư cấp cao thu làm đệ tử.","tonChi":"Cung phụng Thiên Lan thánh thú và bồi dưỡng tiên sư cấp thấp cho người Đột Ngột","quyMo":"mỗi thánh điện quản lý hàng ngàn bộ lạc khu vực","trangThai":"đang hoạt động","capNhatToi":"@c0877","tabs":{"tienTrinh":[{"chuong":"@c0877","loai":"nhắc tới","importance":"normal","giaiDoan":"Khai linh nhật","text":"Thiên Lan thánh điện được giải thích là nơi bồi dưỡng tiên sư cấp thấp cho tộc Đột Ngột và là đích đến của đội Thương Lộ Bộ.","anchor":"Thành nơi chuyên môn bồi dưỡng ra tiên sư cấp thấp cho tộc người Đột Ngột","trangThaiMoc":"trung tâm đào tạo tiên sư cấp thấp"},{"chuong":"@c0926","loai":"nhắc tới","importance":"normal","giaiDoan":"Liên quan trưởng lão mới Diệp gia","text":"Thiên Lan Thánh Điện được nhắc là thế lực mà vị tán tu từ Thiên Lan thảo nguyên từng đắc tội, khiến người này phải trốn ra ngoài tránh họa.","anchor":"bởi vì đắc tội Thiên Lan Thánh Điện, không thể không trốn ra mà tránh họa"},{"chuong":"@c0944","loai":"liên minh","importance":"normal","giaiDoan":"Hợp tác với Âm La Tông","text":"Thiên Lan Thánh Điện qua Lâm Ngân Bình tăng điều kiện để đổi lấy hợp tác truy sát Hàn Lập.","anchor":"Kể cả điều kiện trước kia thánh điện đã đáp ứng quý tông","trangThaiMoc":"liên minh tạm thời"}]},"nguon":["@c0877","@c0926","@c0944"],"thanhVien":[{"ten":"Lâm Ngân Bình","chucVu":"Thánh Nữ","tuChuong":"@c0944","trangThai":"đại diện thương lượng"}]},{"id":"thien-lan","name":"Thiên Lan","cn":"","type":"the-luc","typeLabel":"Thế lực","diaBan":"Thiên Lan thánh điện và thảo nguyên Thiên Lan","nhanVatChinh":["Hồn Hình","Quế tiên sư","Bạch diện lão giả","Lão giả hơi béo","Lão giả tóc bạc còn lại","Hô đại tiên sư","Thánh nữ Thiên Lan"],"blurb":"Thiên Lan là thế lực của các tiên sư đang truy xét Hàn Lập sau khi nhiều thượng giai tiên sư tử vong. Nhóm tiên sư trong mật thất bàn cách điều tra lai lịch Hàn Lập và bí mật nuôi dưỡng Phệ Kim Trùng của hắn.","detail":"Các tiên sư Thiên Lan xem Hàn Lập là ngoại tộc nhân cực kỳ nguy hiểm vì hắn đã sát hại nhiều thượng giai tiên sư. Họ dự tính dựa vào Thánh nữ Thiên Lan và khách nhân từ Đại Tấn gần Thiên Lan thánh điện để tra lai lịch, đồng thời muốn điều tra cách hắn đào tạo nhiều Phệ Kim Trùng.","trangThai":"đang truy xét Hàn Lập","thanhVien":[{"ten":"Hồn Hình","chucVu":"tiên sư","tuChuong":"@c0881","trangThai":"đang hoạt động"},{"ten":"Quế tiên sư","chucVu":"tiên sư","tuChuong":"@c0881","trangThai":"bị trọng thương"},{"ten":"Hô đại tiên sư","chucVu":"đại tiên sư","tuChuong":"@c0881","trangThai":"đang hoạt động"},{"ten":"Thánh nữ Thiên Lan","chucVu":"thánh nữ","tuChuong":"@c0881","trangThai":"đang đến gần thánh điện"}],"tabs":{"tienTrinh":[{"chuong":"@c0881","loai":"nhắc tới","importance":"normal","giaiDoan":"Truy xét ngoại tộc nhân","text":"Thiên Lan mất nhiều thượng giai tiên sư vì Hàn Lập và các tiên sư dự tính điều tra lai lịch cùng bí mật Phệ Kim Trùng của hắn.","anchor":"nếu đã sát hại nhiều thượng giai tiên sư của Thiên Lan chúng ta như vậy"}]},"nguon":["@c0881"]},{"id":"to-hong-lang-bo-lac","name":"Tố Hồng Lang bộ lạc","cn":"","type":"bo-lac","typeLabel":"Tiểu bộ lạc","diaBan":"Đại thảo nguyên","nhanVatChinh":["Đại hán họ Bạt","Phong tiên sư"],"blurb":"Tố Hồng Lang bộ lạc là tiểu bộ lạc có đoàn xe tiến cống gặp Thương Lộ bộ lạc trên đường tới trạm dừng chân của thánh điện. Bộ lạc này do đại hán họ Bạt dẫn đoàn và thuê Phong tiên sư tự do hộ tống.","detail":"Đoàn xe của Tố Hồng Lang bộ lạc nhập cùng đoàn Thương Lộ bộ lạc vì hai thủ lĩnh quen biết. Họ phải trả giá lớn mới thuê được một tiên sư tự do hộ tống, sau đó cùng bị ba con Viên Thứu uy hiếp trên đường đi.","quyMo":"tiểu bộ lạc","thanhVien":[{"ten":"Đại hán họ Bạt","chucVu":"thủ lĩnh đoàn xe","tuChuong":"@c0882","trangThai":"gan-bo"},{"ten":"Phong tiên sư","chucVu":"tiên sư hộ tống được thuê","tuChuong":"@c0882","trangThai":"danh-nghia"}],"trangThai":"đang tiến cống","tabs":{"tienTrinh":[{"chuong":"@c0882","loai":"liên minh","importance":"normal","giaiDoan":"Nhập đoàn với Thương Lộ","text":"Đoàn xe Tố Hồng Lang nhập cùng đoàn Thương Lộ bộ lạc trên đường tới trạm dừng chân của thánh điện.","anchor":"Đoàn xe là của tiểu bộ lạc Tố Hồng Lang","trangThaiMoc":"đang tiến cống"}]},"capNhatToi":"@c0882","nguon":["@c0882"]},{"id":"bo-lac-anh-lo","name":"Bộ lạc của Anh Lộ","cn":"","type":"bo-lac","typeLabel":"Bộ lạc Đột Ngột","diaBan":"trú địa trên Thiên Lan thảo nguyên","nhanVatChinh":["Anh Lộ","Đại hán trong đoàn thảo nguyên"],"blurb":"Bộ lạc nhỏ trên Thiên Lan thảo nguyên, cùng Hàn Lập đến trú địa do thánh điện chỉ định sau trận yêu cầm.","detail":"Bộ lạc không tổn thất người sau trận yêu cầm, chia tài liệu viên thứu rồi tiếp tục lên đường. Khi vào trú địa, vì quy mô nhỏ nên họ chỉ tìm được chỗ trú chân xa thánh điện hơn các bộ lạc lớn.","nguon":["@c0884"],"dinhDanh":"goc","quyMo":"bộ lạc nhỏ","trangThai":"an toàn đến trú địa","thanhVien":[{"ten":"Anh Lộ","chucVu":"người trong bộ lạc","tuChuong":"@c0884","trangThai":"đang đi cùng"},{"ten":"Đại hán trong đoàn thảo nguyên","chucVu":"người trong bộ lạc","tuChuong":"@c0884","trangThai":"đang đi cùng"}],"capNhatToi":"@c0884","tabs":{"tienTrinh":[{"chuong":"@c0884","loai":"nhắc tới","importance":"normal","giaiDoan":"Đến trú địa","text":"Bộ lạc của Anh Lộ vào trú địa, nhưng vì là bộ lạc nhỏ nên phải ở khu cách thánh điện xa nhất.","anchor":"Chuyện này cũng không trách được, đây chỉ là một bộ lạc nhỏ","trangThaiMoc":"an toàn đến trú địa"}]}},{"id":"phat-tong-dai-tan","name":"Phật tông Đại Tấn","cn":"","type":"tong-mon","typeLabel":"Truyền thừa Phật tông","diaBan":"Đại Tấn","nhanVatChinh":["Phong Nhạc","Hàn Lập","Đại Diễn Thần Quân"],"blurb":"Nhánh Phật tông tại Đại Tấn được Hàn Lập chú ý vì có thể liên quan tới Phong Nhạc và manh mối giải sát khí. Dấu hiệu cấm chế Phật môn trên ngọc bội của Phong Nhạc khiến hắn muốn hỏi rõ quan hệ này.","detail":"Sau khi phát hiện ngọc bội của Phong Nhạc có thất sắc linh quang và cấm chế Phật môn gia trì, Hàn Lập cho rằng cần hỏi rõ quan hệ giữa Phong Nhạc và Phật tông Đại Tấn. Đây là manh mối hắn không muốn bỏ qua vì sát khí trên người mình có thể cần tới bí thuật Phật tông để hóa giải.","nguonGoc":"Truyền thừa Phật tông tại Đại Tấn","quanHe":"Có liên hệ chưa rõ với Phong Nhạc qua ngọc bội khắc Trữ Trung Phùng.","trangThai":"Được nhắc như manh mối Hàn Lập cần điều tra","tabs":{"tienTrinh":[{"chuong":"@c0885","loai":"nhắc tới","importance":"normal","giaiDoan":"Manh mối Phong Nhạc","text":"Hàn Lập muốn làm Phong Nhạc tỉnh lại để hỏi rõ quan hệ giữa hắn và Phật tông Đại Tấn.","anchor":"không hỏi rõ quan hệ của hắn với Phật tông Đại Tấn"}]},"capNhatToi":"@c0885","nguon":["@c0885"]},{"id":"khong-gia","name":"Khổng gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"","nhanVatChinh":["Lão giả mắt ưng","Lão gù / chấp sự Khổng gia tại Tấn kinh","Lão tổ Khổng gia"],"blurb":"Khổng gia là thế lực được Phong Nhạc nhắc đến khi phát hiện mình trúng Khổ độc. Theo lời hắn, chỉ Khổng gia có loại độc dược này.","detail":"Phong Nhạc cho rằng tử bào lão giả đã đầu phục Khổng gia vì Khổ độc trong người hắn là loại độc chỉ Khổng gia có. Thông tin này biến Khổng gia thành manh mối thế lực đứng sau vụ hạ độc.","dacDiem":"Theo lời Phong Nhạc, Khổng gia sở hữu Khổ độc.","tabs":{"tienTrinh":[{"chuong":"@c0886","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị liên hệ với Khổ độc","text":"Phong Nhạc khẳng định tử bào lão giả đã đầu phục Khổng gia vì chỉ Khổng gia có Khổ độc.","anchor":"Lão tặc đúng là đã đầu phục Khổng gia, chỉ có Khổng gia là có loại độc dược này"},{"chuong":"@c0935","loai":"suy","importance":"normal","giaiDoan":"Biến cố lão tổ","trangThaiMoc":"Lão tổ bị quỷ chiếm xác và bị đánh gục","text":"Khổng gia bị lộ có chấp sự tại Tấn kinh từng khống chế Phùng chưởng quỹ. Gia tộc này còn chịu thiệt hại lớn sau khi lão tổ bị quỷ chiếm thân xác rồi bị tu sĩ cao tay đánh gục.","anchor":"Đúng như trước đây lão gù đã nói, hắn là chấp sự tại Tấn kinh của Khổng gia"}]},"capNhatToi":"@c0886","nguon":["@c0886","@c0935"],"trangThai":"chịu tổn thất sau biến cố lão tổ","thanhVien":[{"ten":"Lão gù / chấp sự Khổng gia tại Tấn kinh","chucVu":"Chấp sự tại Tấn kinh","tuChuong":"@c0935","trangThai":"tu-vong"},{"ten":"Lão tổ Khổng gia","chucVu":"Lão tổ","tuChuong":"@c0935","trangThai":"tu-vong"}]},{"id":"phung-gia","name":"Phùng gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Trữ Trung","nhanVatChinh":["Phong Nhạc"],"blurb":"Phùng gia là thế lực được nêu ra khi Hàn Lập truy hỏi thân phận Phong Nhạc. Cụm Trữ Trung, Phùng gia trở thành manh mối tiếp theo của cuộc tra hỏi.","detail":"Sau khi Phong Nhạc tháo chìa khóa bạc và ngọc bội, Hàn Lập nhắc đến Trữ Trung, Phùng gia và hỏi đó có phải hai thế lực rất lớn hay không. Chương này chưa giải thích rõ quy mô và quan hệ cụ thể của Phùng gia.","tabs":{"tienTrinh":[{"chuong":"@c0886","loai":"nhắc tới","importance":"normal","giaiDoan":"Manh mối thân phận","text":"Hàn Lập nhắc đến Trữ Trung, Phùng gia khi truy hỏi Phong Nhạc, cho thấy Phùng gia liên quan đến thân phận và vật Phong Nhạc giữ.","anchor":"Trữ trung Phùng? Trữ Trung, Phùng gia là hai thế lực rất lớn sao"}]},"capNhatToi":"@c0886","nguon":["@c0886"]},{"id":"thien-quang-tu","name":"Thiên Quang tự","cn":"","type":"tong-mon","typeLabel":"Phật tông tự viện","diaBan":"Từng ở Liêu châu","nhanVatChinh":["Tổ tiên Phùng gia"],"blurb":"Thiên Quang tự là phân chi của Kim La môn, từng có tổ tiên Phùng gia làm tục gia đệ tử. Tự viện này đã rời Liêu châu về bổn tông từ mấy trăm năm trước.","detail":"Phong Nhạc cho biết tổ tiên Phùng gia từng là tục gia đệ tử Thiên Quang tự, còn Thiên Quang tự là một phân chi của Phật môn đại tông Kim La môn. Sau khi Thiên Quang tự rời Liêu châu về bổn tông, Phùng gia mới đổi sang tu Nho gia công pháp.","nguon":["@c0887"],"trangThai":"đã rời Liêu châu về bổn tông","capNhatToi":"@c0887","tabs":{"tienTrinh":[{"chuong":"@c0887","loai":"nhắc tới","importance":"normal","giaiDoan":"Lộ quan hệ với Phùng gia","text":"Thiên Quang tự được nói là phân chi Kim La môn và là nơi tổ tiên Phùng gia từng làm tục gia đệ tử.","anchor":"Mà Thiên Quang tự là một phân chi của Phật môn đại tông Kim la môn"}]}},{"id":"kim-la-mon","name":"Kim La môn","cn":"","aliases":["Kim La tông"],"type":"tong-mon","typeLabel":"Phật môn đại tông","diaBan":"Đại Tấn","nhanVatChinh":[],"blurb":"Kim La môn là Phật môn đại tông ở Đại Tấn, được nói là một trong tứ đại tông môn Phật môn. Thiên Quang tự là một phân chi của thế lực này.","detail":"Thông qua lời Phong Nhạc, Kim La môn được xác nhận là đại tông Phật môn tại Đại Tấn và có phân chi Thiên Quang tự liên quan tới nguồn gốc Phật gia công pháp của Phùng gia.","nguon":["@c0887"],"quyMo":"Một trong tứ đại tông môn Phật môn Đại Tấn","capNhatToi":"@c0887","tabs":{"tienTrinh":[{"chuong":"@c0887","loai":"nhắc tới","importance":"normal","giaiDoan":"Xác nhận vị thế","text":"Kim La môn được xác nhận là Phật môn đại tông ở Đại Tấn và có phân chi Thiên Quang tự.","anchor":"Đây chính là là phật môn ở Đại Tấn,một trong tứ đại tông môn"}]}},{"id":"truong-gia","name":"Trương gia","cn":"","type":"gia-toc","typeLabel":"Tu tiên thế gia","diaBan":"Quan Trữ phủ, Liêu châu","nhanVatChinh":[],"blurb":"Trương gia là một trong tứ đại tu tiên thế gia ở Quan Trữ phủ. Khi Phùng gia suy yếu, Trương gia cùng Kim gia theo Khổng gia âm thầm đối phó Phùng gia.","detail":"Phong Nhạc nhắc Trương gia cùng Khổng gia, Kim gia và Phùng gia vốn là tứ đại tu tiên thế gia Quan Trữ phủ. Trong biến cố Phùng gia suy bại, Trương gia là một trong hai nhà liên hợp với Khổng gia xuống tay với Phùng gia.","nguon":["@c0887"],"trangThai":"tham gia liên hợp chống Phùng gia","capNhatToi":"@c0887","tabs":{"tienTrinh":[{"chuong":"@c0887","loai":"nhắc tới","importance":"normal","giaiDoan":"Tham gia tứ đại thế gia","text":"Trương gia được nhắc là một trong tứ đại tu tiên thế gia Quan Trữ phủ và tham gia liên hợp chống Phùng gia.","anchor":"Khổng gia cùng Trương gia, Kim gia, còn có Phùng gia chúng ta"}]}},{"id":"kim-gia","name":"Kim gia","cn":"","type":"gia-toc","typeLabel":"Tu tiên thế gia","diaBan":"Quan Trữ phủ, Liêu châu","nhanVatChinh":[],"blurb":"Kim gia là một trong tứ đại tu tiên thế gia ở Quan Trữ phủ. Khi Phùng gia suy yếu, Kim gia cùng Trương gia theo Khổng gia âm thầm đối phó Phùng gia.","detail":"Phong Nhạc nhắc Kim gia là một trong tứ đại thế gia Quan Trữ phủ. Trong thế cục Phùng gia suy bại, Kim gia cùng Trương gia liên hợp với Khổng gia để gây hại Phùng gia.","nguon":["@c0887"],"trangThai":"tham gia liên hợp chống Phùng gia","capNhatToi":"@c0887","tabs":{"tienTrinh":[{"chuong":"@c0887","loai":"nhắc tới","importance":"normal","giaiDoan":"Tham gia tứ đại thế gia","text":"Kim gia được nhắc là một trong tứ đại tu tiên thế gia Quan Trữ phủ và tham gia liên hợp chống Phùng gia.","anchor":"Khổng gia cùng Trương gia, Kim gia, còn có Phùng gia chúng ta"}]}},{"id":"thanh-dien-dot-ngot","name":"Thánh Điện Đột Ngột","cn":"","aliases":[],"type":"the-luc","typeLabel":"Thế lực","diaBan":"Thiên Lan Thảo Nguyên","nhanVatChinh":["Ưng tiền bối","Thánh nữ Đột Ngột","Đại tiên sư Đột Ngột"],"blurb":"Thánh Điện Đột Ngột là thế lực đứng sau kế hoạch truy bắt ngoại nhân vì phương pháp nuôi dưỡng Phệ Kim Trùng. Phe này bố trí tiên sư cao cấp tại các nơi nghỉ chân và chuẩn bị dùng thánh khí gọi phân thân Thánh thú.","detail":"Qua lời Ưng tiền bối, Thánh Điện xem phương pháp nuôi dưỡng Phệ Kim Trùng trên người ngoại tộc là mục tiêu bắt buộc phải đoạt. Kế hoạch bao gồm giăng lưới ở các điểm nghỉ chân, huy động thánh nữ và đại tiên sư sau nghi thức khai linh để tăng khả năng truy tung.","tonChi":"Đoạt phương pháp nuôi dưỡng Phệ Kim Trùng từ ngoại nhân","trangThai":"Đang truy bắt ngoại nhân","thanhVien":[{"ten":"Ưng tiền bối","chucVu":"Tiên sư cao cấp tại nơi nghỉ chân","tuChuong":"@c0888","trangThai":"đang hoạt động"},{"ten":"Thánh nữ Đột Ngột","chucVu":"Thánh nữ","tuChuong":"@c0888","trangThai":"sẽ tham gia vận dụng thánh khí"}],"tabs":{"tienTrinh":[{"chuong":"@c0888","loai":"khai chiến","importance":"major","giaiDoan":"Giăng lưới vì Phệ Kim Trùng","text":"Thánh Điện Đột Ngột quyết đoạt phương pháp nuôi dưỡng Phệ Kim Trùng, bố trí tiên sư cao cấp tại các nơi nghỉ chân và chờ dùng thánh khí gọi phân thân Thánh thú để lùng bắt ngoại nhân.","anchor":"Thánh Điện nhất định phải đạt được"}]},"capNhatToi":"@c0888","nguon":["@c0888"]},{"id":"bo-lac-hoa-lang","name":"Bộ lạc Hoả Lang","cn":"","aliases":[],"type":"bo-lac","typeLabel":"Bộ lạc","diaBan":"đoàn xe trên thảo nguyên","nhanVatChinh":["Phong Nhạc"],"blurb":"Bộ lạc Hoả Lang có xe ngựa nằm trong đoàn xe đang đi qua thảo nguyên. Phong Nhạc ngồi trong một xe ngựa của bộ lạc này để cố giải khổ độc.","detail":"Khi Hàn Lập dùng thần thức quan sát Phong Nhạc, mục tiêu nằm trong một xe ngựa của bộ lạc Hoả Lang. Chương này chưa nêu rõ cơ cấu bộ lạc, chỉ cho thấy xe ngựa của họ thuộc đoàn đang di chuyển và bị cuốn vào biến cố quanh Phong Nhạc.","trangThai":"đang hiện diện trong đoàn xe","capNhatToi":"@c0889","thanhVien":[{"ten":"Phong Nhạc","chucVu":"người đi trong xe","tuChuong":"@c0889","trangThai":"đang ở trong xe ngựa của bộ lạc"}],"tabs":{"tienTrinh":[{"chuong":"@c0889","loai":"nhắc tới","importance":"normal","giaiDoan":"Xe ngựa chứa Phong Nhạc","text":"Phong Nhạc đang ở trong một xe ngựa của bộ lạc Hoả Lang khi Hàn Lập dùng thần thức quan sát tình trạng trúng độc của hắn.","anchor":"đem một lũ thần thức vương tới một cái xe ngựa của bộ lạc Hoả Lang"}]},"nguon":["@c0889"]},{"id":"dot-ngot","name":"Đột Ngột","cn":"","aliases":[],"type":"toc-quan","typeLabel":"Tộc quần","diaBan":"Thiên Lam Thảo Nguyên","nhanVatChinh":["Thánh nữ Đột Ngột","Đại tiên sư","Thanh niên tiên sư hộ tống người Đột Ngột"],"blurb":"Đột Ngột là thế lực có các tiên sư hộ tống đoàn xe trên thảo nguyên. Trong chương này, tiên sư Đột Ngột đánh chết Thiết Đề Thú và cảnh giác khi dơi lớn lục quang xuất hiện.","detail":"Đoàn xe có các tiên sư Đột Ngột đi kèm. Khi hai Thiết Đề Thú cấp thấp xuất hiện, vài tiên sư dùng pháp khí oanh kích giết chết; về cuối chương, họ cũng ra khỏi xe nhìn lên khi dị vật dạng dơi lớn bọc lục quang bay tới.","trangThai":"đang hộ tống đoàn xe","capNhatToi":"@c0889","thanhVien":[{"ten":"Thanh niên tiên sư hộ tống người Đột Ngột","chucVu":"tiên sư hộ tống","tuChuong":"@c0889","trangThai":"đang đi trong đoàn xe"}],"tabs":{"tienTrinh":[{"chuong":"@c0889","loai":"nhắc tới","importance":"normal","giaiDoan":"Hộ tống đoàn xe","text":"Các tiên sư Đột Ngột hộ tống đoàn xe, dùng pháp khí đánh chết Thiết Đề Thú rồi ra khỏi xe quan sát khi dơi lớn lục quang xuất hiện.","anchor":"Kết quả bị mấy tên tiên sư Đột Ngột vui mừng đem vài món pháp khí oanh kích một trận"}]},"nguon":["@c0889"]},{"id":"cuu-tien-cung","name":"Cửu Tiên cung","cn":"","aliases":["Tiên cung"],"type":"tông môn","typeLabel":"Thế lực tu tiên Đại Tấn","diaBan":"","nhanVatChinh":["Cố thống lĩnh","Nữ tu Kết Đan Cửu Tiên cung","Giang Kiếm Anh","Cung chủ Cửu Tiên cung","Sáu tu sĩ Trúc Cơ Cửu Tiên cung"],"blurb":"Thế lực tu tiên xuất hiện qua nhóm Cố thống lĩnh truy bắt Giang Kiếm Anh trên Thiên Lan thảo nguyên. Cửu Tiên cung từng tài bồi Giang Kiếm Anh nhưng nay coi hắn là phản đồ vì mang Tuyết Tinh châu bỏ trốn.","detail":"Cửu Tiên cung phái nhóm tu sĩ cưỡi cự bức, gồm hai Kết Đan kỳ và sáu Trúc Cơ kỳ, truy bắt Giang Kiếm Anh vì Tuyết Tinh châu. Qua lời nữ tu, thế lực này từng nuôi dưỡng, cấp tài nguyên và cho Giang Kiếm Anh cưới vợ sinh con, nhưng cuộc truy bắt cũng hé lộ nghi vấn huyết tế liên quan băng linh căn và Tuyết Tinh châu.","trangThai":"đang truy bắt phản đồ","thanhVien":[{"ten":"Cố thống lĩnh","chucVu":"Thống lĩnh","tuChuong":"@c0890","trangThai":"đang hoạt động"},{"ten":"Nữ tu Kết Đan Cửu Tiên cung","chucVu":"Tu sĩ Kết Đan","tuChuong":"@c0890","trangThai":"đang hoạt động"},{"ten":"Sáu tu sĩ Trúc Cơ Cửu Tiên cung","chucVu":"Tu sĩ Trúc Cơ","tuChuong":"@c0890","trangThai":"đang hoạt động"},{"ten":"Giang Kiếm Anh","chucVu":"Tu sĩ được tài bồi","tuChuong":"@c0890","trangThai":"bị coi là phản đồ"},{"ten":"Cung chủ Cửu Tiên cung","chucVu":"Cung chủ","tuChuong":"@c0890","trangThai":"được nhắc tới"},{"ten":"môn hạ đệ tử Cửu Tiên Cung","chucVu":"đệ tử","tuChuong":"@c0917","trangThai":"được nhắc tới"}],"tabs":{"tienTrinh":[{"chuong":"@c0890","loai":"nhắc tới","importance":"normal","giaiDoan":"Truy bắt phản đồ","text":"Cửu Tiên cung phái Cố thống lĩnh cùng nhóm tu sĩ truy bắt Giang Kiếm Anh vì hắn mang Tuyết Tinh châu bỏ trốn, nhưng vẫn tránh gây thêm chuyện trên Thiên Lan thảo nguyên.","anchor":"Nơi này là Thiên Lan thảo nguyên, không phải Cửu Tiên cung chúng ta"},{"chuong":"@c0917","loai":"nhắc tới","importance":"normal","giaiDoan":"Liên quan Tuyết Tinh Châu","text":"Cửu Tiên Cung được nhắc qua việc môn hạ đệ tử từng tranh giành Tuyết Tinh Châu với Hàn Lập.","anchor":"cùng môn hạ đệ tử của Cửu Tiên Cung tranh giành Tuyết Tinh Châu","trangThaiMoc":"được nhắc tới"}]},"capNhatToi":"@c0890","nguon":["@c0890","@c0917"]},{"id":"tien-cung","name":"Tiên cung","cn":"","aliases":[],"type":"tong-mon","typeLabel":"Thế lực Đại Tấn","diaBan":"Đại Tấn","nhanVatChinh":["Cố thống lĩnh","Bạch y nữ tử Kết Đan Đại Tấn","Sáu gã Trúc Cơ kỳ tu sĩ Đại Tấn"],"blurb":"Tiên cung là thế lực Đại Tấn mà nhóm Cố thống lĩnh và bạch y nữ tử thuộc về. Trong chương này, người của Tiên cung vì Kim Diễm thạch mà quyết định diệt khẩu Đột Ngột nhân, rồi bị Hàn Lập giết sạch.","detail":"Bạch y nữ tử nhắc đến Tiên cung khi cân nhắc hậu quả với Thiên Lan thánh điện. Nàng cho rằng chỉ cần không còn nhân chứng thì đối phương sẽ không vì vài tiên sư cấp thấp và phàm nhân mà trở mặt, cùng lắm giảm giá giao dịch.","trangThai":"Nhóm tham chiến bị tiêu diệt @c0891","thanhVien":[{"ten":"Cố thống lĩnh","chucVu":"Thống lĩnh, tu sĩ Kết Đan","tuChuong":"@c0891","trangThai":"tu-vong"},{"ten":"Bạch y nữ tử Kết Đan Đại Tấn","chucVu":"Tu sĩ Kết Đan","tuChuong":"@c0891","trangThai":"tu-vong"},{"ten":"Sáu gã Trúc Cơ kỳ tu sĩ Đại Tấn","chucVu":"Tu sĩ Trúc Cơ","tuChuong":"@c0891","trangThai":"tu-vong"}],"quanHe":"Có giao dịch với Thiên Lan thánh điện nhưng người của Tiên cung định diệt khẩu Đột Ngột nhân để đoạt kỳ bảo.","tabs":{"tienTrinh":[{"chuong":"@c0891","loai":"nhắc tới","importance":"normal","giaiDoan":"Đoạt Kim Diễm thạch","text":"Người của Tiên cung quyết định diệt khẩu Đột Ngột nhân để che giấu việc đoạt Kim Diễm thạch, rồi bị Hàn Lập tiêu diệt toàn bộ nhóm tham chiến.","anchor":"cùng tiên cung chúng ta trở mặt"}]},"capNhatToi":"@c0891","nguon":["@c0891"]},{"id":"am-la-tong","name":"Âm La tông","cn":"","aliases":[],"type":"tong-mon","typeLabel":"Ma tông","diaBan":"Đại Tấn","nhanVatChinh":["Hàn Lập"],"blurb":"Âm La tông là ma tông có trấn tông chi bảo Âm La phiên. Cố thống lĩnh nhìn thấy phiên này liền nhận lầm Hàn Lập là chấp pháp trưởng lão Âm La tông.","detail":"Trong lúc Âm La phiên phóng ma khí cuốn pháp bảo pháp khí, Cố thống lĩnh nhận ra đây là trấn tông chi bảo của Âm La tông và hoảng sợ bỏ chạy. Bạch y nữ tử cũng liên hệ Ma Tông với tính cách có thù tất báo nên không tin đối phương sẽ tha mạng.","tranPhai":"Âm La phiên","dacDiem":"Được nhận biết qua trấn tông chi bảo Âm La phiên và tiếng có thù tất báo.","tabs":{"tienTrinh":[{"chuong":"@c0891","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị nhận lầm thân phận","text":"Cố thống lĩnh thấy Âm La phiên nên nhận lầm Hàn Lập là chấp pháp trưởng lão Âm La tông.","anchor":"phiên kỳ của đối phương là Âm La tông trấn tông chi bảo"},{"chuong":"@c0969","loai":"nhắc tới","importance":"normal","giaiDoan":"Mục tiêu giải chú","text":"Hàn Lập xác định phải đoạt phương pháp giải trừ Phong hồn chú từ Âm La tông.","anchor":"phải từ trong Âm la tông đoạt được phương pháp giải trừ phong hồn chú"}]},"capNhatToi":"@c0891","nguon":["@c0891","@c0969"],"trangThai":"bị Hàn Lập nhắm tới để lấy phương pháp giải chú"},{"id":"dot-ngot-nhan-tien-su","name":"Đột Ngột nhân tiên sư","cn":"","type":"tu-tien-gia","typeLabel":"Nhóm tiên sư Đột Ngột nhân","diaBan":"Thiên Lan thảo nguyên","nhanVatChinh":["Thiên Lan thánh nữ","Từ đạo hữu","Tôn tiên sứ"],"blurb":"Đột Ngột nhân tiên sư là nhóm tu tiên giả phía Đột Ngột nhân tham gia nghi thức triệu hoán và truy bắt Hàn Lập.","detail":"Trong chương, nhiều tiên sư Đột Ngột nhân có mặt tại quảng trường nghi thức; sau khi thánh thú phân thân được đúc linh thân, đội cấp cao rời thánh điện truy bắt kẻ ngoại tộc.","trangThai":"đang truy bắt Hàn Lập","thanhVien":[{"ten":"Thiên Lan thánh nữ","chucVu":"thánh nữ","tuChuong":"@c0893","trangThai":"đang hoạt động"},{"ten":"Từ đạo hữu","chucVu":"đại tiên sư","tuChuong":"@c0893","trangThai":"đang hoạt động"},{"ten":"Tôn tiên sứ","chucVu":"đại tiên sư","tuChuong":"@c0893","trangThai":"đang hoạt động"}],"tabs":{"tienTrinh":[{"chuong":"@c0893","loai":"khai chiến","importance":"normal","giaiDoan":"Truy bắt kẻ ngoại tộc","text":"Các tiên sư Đột Ngột nhân tham gia nghi thức và tổ chức đội truy bắt Hàn Lập sau khi phân thân thánh thú tạm thành.","anchor":"trong quảng trường mấy vị Đột Ngột nhân tiên sư"}]},"capNhatToi":"@c0893","nguon":["@c0893"]},{"id":"huyen-ngoc-dao","name":"Huyền Ngọc đạo","cn":"","type":"tong-mon","typeLabel":"Tông môn đạo môn","diaBan":"Liêu Châu","nhanVatChinh":["Tào Mộng Dung"],"blurb":"Huyền Ngọc đạo là môn phái của Tào Mộng Dung ở Liêu Châu. Nàng tự nhận đây chỉ là một tiểu phái vô danh, nên Hàn Lập không biết cũng không lạ.","detail":"Tào Mộng Dung giới thiệu mình là đệ tử Huyền Ngọc đạo khi gặp riêng Hàn Lập trên thuyền Tào gia. Môn này được mô tả là tiểu phái vô danh tại Liêu Châu.","nguonGoc":"Tiểu phái đạo môn ở Liêu Châu","quyMo":"Tiểu phái vô danh","trangThai":"Đang tồn tại","thanhVien":[{"ten":"Tào Mộng Dung","chucVu":"Đệ tử","tuChuong":"@c0899","trangThai":"đang thuộc"}],"tabs":{"tienTrinh":[{"chuong":"@c0899","loai":"nhắc tới","importance":"normal","giaiDoan":"Tào Mộng Dung tự giới thiệu","text":"Tào Mộng Dung nói mình là đệ tử Huyền Ngọc đạo và cho biết môn này chỉ là tiểu phái vô danh ở Liêu Châu.","anchor":"Bổn môn chỉ là vô danh tiểu phái ở Liêu Châu, Hàn đạo hữu không biết, cũng không ngạc nhiên"}]},"capNhatToi":"@c0899","nguon":["@c0899"]},{"id":"tao-gia-cua-huyen-uy-ho-tao","name":"Tào gia của huyện úy họ Tào","cn":"","type":"gia-toc","typeLabel":"Gia tộc/quan quyến phàm tục","diaBan":"Đại Tấn, trên đường đi nhậm chức","nhanVatChinh":["Huyện úy họ Tào","Tào Mộng Dung","Nguyên phối phu nhân Tào gia","Đại tiểu thư Tào gia","Tam công tử Tào gia","Hà Văn","Chu sư gia","Vương quản gia"],"blurb":"Tào gia của huyện úy họ Tào là đoàn gia quyến đi thuyền trên Thuấn Giang và đã cứu Hàn Lập khỏi khối băng giữa sông. Trên thuyền có phu nhân, công tử tiểu thư, gia sư, sư gia, quản gia, tiêu sư, tôi tớ và một nữ tu cấp thấp là Tào Mộng Dung.","detail":"Do huyện úy họ Tào thuyên chuyển vội nên đi nhậm chức trước, gia quyến đi sau bằng thuyền. Hàn Lập dùng thần thức và nghe ngóng để biết trong đoàn có Tào Mộng Dung là tu tiên giả cấp thấp, Vương quản gia có chân khí, và vài tôi tớ mang sát khí.","nguonGoc":"Gia quyến của một huyện úy họ Tào","quyMo":"Một đoàn thuyền gia quyến phàm tục có hộ vệ và người hầu","trangThai":"Đang di chuyển trên Thuấn Giang","thanhVien":[{"ten":"Huyện úy họ Tào","chucVu":"Chủ gia quyến","tuChuong":"@c0899","trangThai":"đang đi nhậm chức trước"},{"ten":"Tào Mộng Dung","chucVu":"Nhị tiểu thư","tuChuong":"@c0899","trangThai":"đi cùng thuyền"},{"ten":"Nguyên phối phu nhân Tào gia","chucVu":"Chính thất","tuChuong":"@c0899","trangThai":"đi cùng thuyền"},{"ten":"Đại tiểu thư Tào gia","chucVu":"Đại tiểu thư","tuChuong":"@c0899","trangThai":"được nhắc tới"},{"ten":"Tam công tử Tào gia","chucVu":"Tam công tử","tuChuong":"@c0899","trangThai":"được nhắc tới"},{"ten":"Hà Văn","chucVu":"Gia sư","tuChuong":"@c0899","trangThai":"đi cùng thuyền"},{"ten":"Chu sư gia","chucVu":"Sư gia","tuChuong":"@c0899","trangThai":"đi cùng thuyền"},{"ten":"Vương quản gia","chucVu":"Quản gia","tuChuong":"@c0899","trangThai":"đi cùng thuyền"},{"ten":"Vương Thiết Thương","chucVu":"Tiêu sư","tuChuong":"@c0899","trangThai":"hộ thuyền"},{"ten":"Một số tôi tớ có sát khí trên thuyền Tào gia","chucVu":"Tôi tớ","tuChuong":"@c0899","trangThai":"đi cùng thuyền"}],"tabs":{"tienTrinh":[{"chuong":"@c0899","loai":"nhắc tới","importance":"normal","giaiDoan":"Cứu Hàn Lập trên Thuấn Giang","text":"Đoàn gia quyến Tào gia trên thuyền được nhắc là nhóm đã cứu Hàn Lập lên từ giữa sông Thuấn Giang khi hắn sinh tử chưa rõ.","anchor":"Người trên thuyền tựa hồ là gia quyến của vị huyện úy họ Tào"}]},"capNhatToi":"@c0899","nguon":["@c0899"]},{"id":"te-linh-tong","name":"Tê Linh Tông","cn":"","aliases":[],"type":"tong-mon","typeLabel":"Tông môn","diaBan":"khu vực Ngũ Nguyên phủ, Đại Tấn","nhanVatChinh":["Ngô Hiểu Vũ","Mã Ngọc Lâm","Chưởng môn Tê Linh Tông"],"blurb":"Tê Linh Tông là tông môn có giao tình với Huyền Ngọc phái. Trong chương này, đệ tử Ngô Hiểu Vũ gây sức ép để cứu trọng phạm quan phủ, còn chấp pháp đệ tử Mã Ngọc Lâm thay hắn xuất thủ.","detail":"Tê Linh Tông và Huyền Ngọc phái có quan hệ giao tình nên trưởng bối Huyền Ngọc phái không tiện trực tiếp thiên vị Tào Mộng Dung. Ngô Hiểu Vũ, một đệ tử được chưởng môn coi trọng, muốn cứu trọng phạm quan phủ; Mã Ngọc Lâm lấy quan hệ họ hàng với Ngô Hiểu Vũ để thay mặt giao đấu.","quanHe":"Có giao tình với Huyền Ngọc phái nhưng phát sinh xung đột gián tiếp qua vụ khiêu chiến Tào Mộng Dung.","trangThai":"đang hoạt động","thanhVien":[{"ten":"Ngô Hiểu Vũ","chucVu":"đệ tử được coi trọng","tuChuong":"@c0900","trangThai":"đang hoạt động"},{"ten":"Mã Ngọc Lâm","chucVu":"chấp pháp đệ tử","tuChuong":"@c0900","trangThai":"đang hoạt động"},{"ten":"Chưởng môn Tê Linh Tông","chucVu":"chưởng môn","tuChuong":"@c0900","trangThai":"đang hoạt động"}],"tabs":{"tienTrinh":[{"chuong":"@c0900","loai":"nhắc tới","importance":"normal","giaiDoan":"Khiêu chiến liên quan trọng phạm","text":"Tê Linh Tông phát sinh va chạm với phía Tào Mộng Dung khi Ngô Hiểu Vũ muốn cứu trọng phạm và Mã Ngọc Lâm thay hắn xuất thủ.","anchor":"Ngô sư đệ cùng tại hạ có chút quan hệ họ hàng. Thay mặt xuất thủ, không hề vấn đề gì chứ."}]},"capNhatToi":"@c0900","nguon":["@c0900"]},{"id":"loi-linh-tong","name":"Lợi Linh tông","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Không rõ","nhanVatChinh":["Mã Ngọc Lâm","Ngô Hiểu Vũ"],"blurb":"Tông môn của Mã Ngọc Lâm và Ngô Hiểu Vũ, hai người từng tranh chấp với Hàn Lập rồi rút lui sau thất bại.","detail":"Hai đệ tử Lợi Linh tông là Mã Ngọc Lâm và Ngô Hiểu Vũ đối đầu Hàn Lập, nhưng sau khi Mã Ngọc Lâm dùng Liên Hoàng Phượng xoa vẫn thua, cả hai hậm hực hạ sơn.","thanhVien":[{"ten":"Mã Ngọc Lâm","chucVu":"Đệ tử","tuChuong":"@c0901","trangThai":"gan-bo"},{"ten":"Ngô Hiểu Vũ","chucVu":"Đệ tử","tuChuong":"@c0901","trangThai":"gan-bo"}],"tabs":{"tienTrinh":[{"chuong":"@c0901","loai":"nhắc tới","importance":"normal","giaiDoan":"Đệ tử rút lui","text":"Hai đệ tử Lợi Linh tông rút khỏi tranh chấp sau khi Mã Ngọc Lâm bại dưới tay Hàn Lập.","anchor":"Hai tên đệ tử Lợi Linh tông hậm hực hạ sơn"}]},"nguon":["@c0901"]},{"id":"giang-tru-tam-dai-gia","name":"Giang Trữ tam đại gia","cn":"","aliases":["Tam đại thế gia Giang Trữ"],"type":"lien-minh","typeLabel":"Liên minh gia tộc","diaBan":"Chuẩn Vân trấn, Tuyết Lăng sơn","nhanVatChinh":["Bạch bào thanh niên cao lớn đệ tử Khổng gia","Bạch bào thanh niên lùn đệ tử Khổng gia"],"blurb":"Liên minh ba nhà Khổng, Triệu, Đổng ở vùng Giang Trữ, đứng ra tổ chức Đại hội Tham Vương.","detail":"Giang Trữ tam đại gia gồm Khổng gia, Triệu gia và Đổng gia, liên hợp tổ chức Đại hội Tham Vương tại Tuyết Lăng sơn, cho tán tu và tiểu tông môn tham dự trao đổi dược liệu mà không thu phí.","quanHe":"Gồm Khổng gia, Triệu gia và Đổng gia","thanhVien":[{"ten":"Khổng gia","chucVu":"Thành viên liên minh","tuChuong":"@c0901","trangThai":"gan-bo"},{"ten":"Triệu gia","chucVu":"Thành viên liên minh","tuChuong":"@c0901","trangThai":"gan-bo"},{"ten":"Đổng gia","chucVu":"Thành viên liên minh","tuChuong":"@c0901","trangThai":"gan-bo"}],"tabs":{"tienTrinh":[{"chuong":"@c0901","loai":"nhắc tới","importance":"normal","giaiDoan":"Tổ chức Đại hội Tham Vương","text":"Giang Trữ tam đại gia liên hợp tổ chức Đại hội Tham Vương, đưa ra linh dược trăm năm và nhân sâm thiên niên để đấu giá, trao đổi.","trangThaiMoc":"Đang tổ chức đại hội","anchor":"Đại hội lần này là do chúng ta Giang Trữ tam đại gia liên hợp tổ chức"}]},"nguon":["@c0901"]},{"id":"trieu-gia","name":"Triệu gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"Chuẩn Vân trấn, vùng Giang Trữ","nhanVatChinh":[],"blurb":"Một trong ba gia tộc thuộc Giang Trữ tam đại gia.","detail":"Triệu gia cùng Khổng gia và Đổng gia hợp thành Giang Trữ tam đại gia, tham gia quản lý Chuẩn Vân trấn và tổ chức Đại hội Tham Vương.","nguon":["@c0901"]},{"id":"dong-gia","name":"Đổng gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"Chuẩn Vân trấn, vùng Giang Trữ","nhanVatChinh":[],"blurb":"Một trong ba gia tộc thuộc Giang Trữ tam đại gia.","detail":"Đổng gia cùng Khổng gia và Triệu gia hợp thành Giang Trữ tam đại gia, tham gia quản lý Chuẩn Vân trấn và tổ chức Đại hội Tham Vương.","nguon":["@c0901"]},{"id":"dien-duong-cho-thue-mat-that","name":"Điện đường cho thuê mật thất","cn":"","aliases":[],"type":"co-so-giao-dich","typeLabel":"Cơ sở giao dịch","diaBan":"Quan Trữ phủ","nhanVatChinh":["Nữ tử trung niên thanh sam Trúc Cơ kỳ của điện đường","Hàn Lập","Kim Nguyên"],"blurb":"Điện đường cho thuê mật thất là nơi Hàn Lập và Kim Nguyên đến để tìm chỗ trao đổi kín. Nơi này thu linh thạch, giao Thiên Cơ ốc cho khách sử dụng rồi thu hồi sau khi rời mật thất.","detail":"Điện đường cung cấp lựa chọn xem mật thuật pháp quyết hoặc thuê mật thất. Trong chương này, nữ tu phụ trách thu một linh thạch, giao Thiên Cơ ốc cho Hàn Lập và nói rõ sau khi rời mật thất thì bổn điện sẽ thu hồi vật này.","quyMo":"có nữ tu Trúc Cơ phụ trách và nhiều thạch ốc cho thuê","trangThai":"đang hoạt động","thanhVien":[{"ten":"Nữ tử trung niên thanh sam Trúc Cơ kỳ của điện đường","chucVu":"người phụ trách tiếp khách","tuChuong":"@c0903","trangThai":"đang hoạt động"}],"capNhatToi":"@c0903","tabs":{"tienTrinh":[{"chuong":"@c0903","loai":"nhắc tới","importance":"normal","giaiDoan":"Cho thuê mật thất","text":"Điện đường thu linh thạch, giao Thiên Cơ ốc cho Hàn Lập thuê làm mật thất và sẽ thu hồi sau khi khách rời đi.","anchor":"sau khi rời khỏi mật thất bổn điện sẽ thu hồi","trangThaiMoc":"đang hoạt động"}]},"nguon":["@c0903"]},{"id":"tu-dai-the-gia-quan-tru-phu","name":"Tứ đại thế gia Quan Trữ phủ","cn":"","aliases":[],"type":"the-gia","typeLabel":"Thế lực thế gia","diaBan":"Quan Trữ phủ","nhanVatChinh":["Kim Nguyên","Hàn Lập"],"blurb":"Tứ đại thế gia Quan Trữ phủ là cách gọi mới về thế cục thế gia địa phương theo lời Kim Nguyên. Cách gọi này thay cho tam đại thế gia cũ trong khoảng mười năm gần đây.","detail":"Kim Nguyên cho biết cách gọi tam đại thế gia của Quan Trữ đã lỗi thời, mười năm trở lại đây nên gọi là tứ đại thế gia. Trong thế cục này, Phùng gia từng bị ba nhà còn lại liên thủ tiêu diệt trong một đêm.","quyMo":"bốn thế gia lớn tại Quan Trữ phủ","trangThai":"được Kim Nguyên nhắc như thế cục hiện hành","quanHe":"Liên quan trực tiếp tới Phùng gia, Khổng gia và ba nhà còn lại của Quan Trữ phủ.","capNhatToi":"@c0903","tabs":{"tienTrinh":[{"chuong":"@c0903","loai":"nhắc tới","importance":"normal","giaiDoan":"Kim Nguyên kể thế cục","text":"Kim Nguyên nói Quan Trữ phủ hiện nên tính là tứ đại thế gia, không còn chỉ là tam đại thế gia như trước.","anchor":"mười năm trở lại đây nên đổi là tứ đại thế gia mới đúng","trangThaiMoc":"được nhắc tới"}]},"nguon":["@c0903"]},{"id":"phuong-tiem-son-song-ma","name":"Phương Tiêm sơn song ma","cn":"","type":"nhom-ma-tu","typeLabel":"Nhóm ma tu","diaBan":"Phương Tiêm sơn","nhanVatChinh":["Thiên Phong chân quân"],"blurb":"Nhóm ma tu gắn với Phương Tiêm sơn, được nữ tử trong mộ thất nhận xét là có danh tiếng không tốt. Thiên Phong chân quân thuộc nhóm này từng đề xuất biện pháp thu nguyên thần cho đại vương.","detail":"Phương Tiêm sơn song ma bị nhắc tới khi nữ tử lo ngại Thiên Phong chân quân không đơn giản và có thể có mưu đồ riêng. Biện pháp thu nguyên thần quy mô lớn mà đại vương đang dùng được nói là do Thiên Phong chân quân đề xuất, đổi lại hắn lấy đi tam lý huyết tâm hoàn; vì vậy nữ tử nghi hắn có ý dụ đại vương rời khỏi mộ thất.","nguon":["@c0906"]},{"id":"the-gia-tu-si-giang-ninh-phu","name":"Thế gia tu sĩ ở Giang Ninh phủ","cn":"","type":"lien-minh-the-gia","typeLabel":"Quần thể thế gia tu sĩ","diaBan":"Giang Ninh phủ","nhanVatChinh":["Qua tướng quân"],"blurb":"Các đại thế gia tu sĩ tại Giang Ninh phủ là mục tiêu khống chế của đại vương để phục vụ kế hoạch thu tinh hồn tu sĩ. Qua tướng quân đã hóa thân thao túng một thế gia và liên hợp các thế gia khác che giấu âm mưu.","detail":"Đại vương muốn nắm toàn bộ các đại thế gia ở Giang Ninh phủ trong tay để thực hiện kế hoạch thu tinh hồn tu sĩ nhân loại. Qua tướng quân đã hóa thân thành người có thể thao túng một thế gia tu sĩ, đồng thời liên hợp các thế gia khác tiêu diệt một gia tộc truyền thừa Phật tông sau khi tộc trưởng nhà đó nhìn ra sơ hở và định báo tin.","nguon":["@c0906"]},{"id":"gia-toc-truyen-thua-phat-tong-bi-tieu-diet","name":"Gia tộc truyền thừa Phật tông bị tiêu diệt","cn":"","type":"gia-toc-tu-si","typeLabel":"Gia tộc tu sĩ","diaBan":"Giang Ninh phủ","nhanVatChinh":[],"blurb":"Một gia tộc có truyền thừa Phật tông đã bị tiêu diệt để che giấu kế hoạch của đại vương tại Giang Ninh phủ. Nguyên nhân là tộc trưởng nhìn ra sơ hở và định mật báo cho môn phái Phật tông gần đó.","detail":"Gia tộc này có truyền thừa Phật tông và nằm trong tuyến âm mưu khống chế thế gia ở Giang Ninh phủ. Sau khi tộc trưởng phát hiện điểm bất thường và muốn báo tin cho môn phái Phật tông gần đó, Qua tướng quân đã thao túng, liên hợp các thế gia khác ra tay tiêu diệt gia tộc này trước để tránh kế hoạch bại lộ.","nguon":["@c0906"]},{"id":"van-yeu-coc","name":"Vạn Yêu cốc","cn":"","type":"the-luc-yeu-tu","typeLabel":"Thế lực yêu tu","diaBan":"Vạn Yêu cốc","nhanVatChinh":["Cốc chủ Vạn Yêu cốc","Phó cốc chủ hùng sư của Vạn yêu cốc","Vạn Năm Thi Hùng","Thi Hùng","Xa đạo hữu"],"blurb":"Vạn Yêu cốc là thế lực có cốc chủ được đại vương gọi là vạn năm thi hùng. Trong cốc có Vạn yêu phiên trấn giữ, khiến cả các đại tông môn chính ma cũng kiêng dè.","detail":"Vạn Yêu cốc được nhắc như nơi có cốc chủ là một vạn năm thi hùng, thuộc số ít tồn tại có thể luyện hóa Kim cương tráo bằng nguyệt hoa chi lực như đại vương. Đại vương nói trong cốc có Vạn yêu phiên dựng lên, đến mức nhân loại tu sĩ, kể cả thập đại chánh môn và thập đại ma tông, cũng không dám tùy tiện tiến vào.","nguon":["@c0906","@c0926","@c0945","@c1034","@c1052","@c1066"],"tabs":{"tienTrinh":[{"chuong":"@c0926","loai":"liên minh","importance":"normal","giaiDoan":"Phó cốc chủ nhận giúp Diệp gia","text":"Phó cốc chủ hùng sư của Vạn yêu cốc được mỹ phụ Diệp gia nói là nguyện vì hoàng tộc ra mặt khi cần.","anchor":"vạn yêu cốc phó cốc chủ hùng sư,cũng tình nguyện vì hoàng tộc chúng ta mà ra mặt","trangThaiMoc":"có thành viên cấp cao làm ngoại viện cho hoàng tộc"},{"chuong":"@c0945","loai":"khai chiến","importance":"normal","giaiDoan":"Công Tiểu Cực Cung","text":"Các lão yêu Vạn Yêu Cốc được nói là chủ động dẫn đầu yêu thú cấp cao Đại Tấn tấn công Tiểu Cực Cung để tranh Hàn tuỷ.","anchor":"mấy lão yêu quái Vạn Yêu Cốc sẽ chủ động dẫn đầu việc này"},{"chuong":"@c1052","loai":"nhắc tới","importance":"normal","giaiDoan":"Thi hùng ám toán họ Từ","text":"Vạn Yêu Cốc được nhắc qua Thi hùng ám toán Thanh niên họ Từ và Cốc chủ sở hữu Mê Hình Châu.","anchor":"Cốc chủ vạn yêu cốc sở hữu một viên dị bảo \"Mê hình châu\""},{"chuong":"@c1066","loai":"lien-minh","importance":"normal","giaiDoan":"Thi Hùng cam kết viện trợ chống Ma vật","trangThaiMoc":"Cam kết phái người trợ giúp đối phó Ma vật tại Côn Ngô Sơn","text":"Thi Hùng đại diện Vạn Yêu Cốc cam kết phái người trợ giúp đối phó Ma vật. Mời Linh Lung tới cốc chọn thân thể mới. Hướng Chi Lễ nhắc tới Xa đạo hữu mạnh mẽ trong cốc.","anchor":"Chúng ta Yêu Tộc cũng sẽ phái người trợ giúp các ngươi một tay"}]},"trangThai":"đang hoạt động","thanhVien":[{"ten":"Phó cốc chủ hùng sư của Vạn yêu cốc","chucVu":"Phó cốc chủ","tuChuong":"@c0926","trangThai":"nguyện giúp hoàng tộc"},{"ten":"Cốc chủ Vạn Yêu Cốc","chucVu":"Cốc chủ","tuChuong":"@c1052","trangThai":"khong-ro"},{"ten":"Vạn Năm Thi Hùng","chucVu":"thành viên hoặc thuộc hạ","tuChuong":"@c1052","trangThai":"đang hoạt động"},{"ten":"Thi Hùng","chucVu":"Thành viên","tuChuong":"@c1066","trangThai":"hoat-dong"},{"ten":"Xa đạo hữu","chucVu":"Thành viên mạnh, luôn bế quan","tuChuong":"@c1066","trangThai":"khong-ro"}]},{"id":"dau-gia-hoi-tai-thach-dien","name":"Đấu giá hội tại thạch điện","cn":"","type":"thuong-hoi","typeLabel":"Tổ chức giao dịch","diaBan":"Thạch điện đấu giá đối diện quảng trường","nhanVatChinh":["Hàn Lập","Lam bào trung niên nhân chủ trì đấu giá","Bạch bào tu sĩ canh cửa đấu giá hội","Bạch bào tu sĩ luyện khí kỳ dẫn đường hậu đường","Lão già đầu hói Trúc Cơ kỳ"],"blurb":"Đấu giá hội tại thạch điện là phiên giao dịch nơi Hàn Lập tham gia sau khi rời Thiên cơ ốc. Hội thu phí vào cửa, đánh số người dự bằng ngọc bàn và có hậu đường giao nhận vật phẩm.","detail":"Phiên đấu giá diễn ra trong một thạch điện đối diện quảng trường, có bạch bào tu sĩ thu ba khối linh thạch ở cửa, thông đạo dẫn vào đại sảnh chính và thiên môn tới hậu đường. Bên trong, lam bào trung niên nhân chủ trì bán linh dược, pháp khí và Hỏa dong tinh; người trúng giá tới hậu đường để giao linh thạch và nhận hàng.","quyMo":"Có người canh cửa, chủ trì đấu giá, người dẫn hậu đường, thị nữ và người giao vật phẩm @c0907","thanhVien":[{"ten":"Bạch bào tu sĩ canh cửa đấu giá hội","chucVu":"canh cửa thu phí","tuChuong":"@c0907","trangThai":"đang làm việc"},{"ten":"Lam bào trung niên nhân chủ trì đấu giá","chucVu":"chủ trì đấu giá","tuChuong":"@c0907","trangThai":"đang làm việc"},{"ten":"Bạch bào tu sĩ luyện khí kỳ dẫn đường hậu đường","chucVu":"dẫn đường hậu đường","tuChuong":"@c0907","trangThai":"đang làm việc"},{"ten":"Nữ tu thị nữ hậu đường","chucVu":"thị nữ hậu đường","tuChuong":"@c0907","trangThai":"đang làm việc"},{"ten":"Lão già đầu hói Trúc Cơ kỳ","chucVu":"giao vật phẩm hậu đường","tuChuong":"@c0907","trangThai":"đang làm việc"}],"tabs":{"tienTrinh":[{"chuong":"@c0907","loai":"nhắc tới","importance":"normal","giaiDoan":"Phiên đấu giá đang diễn ra","text":"Đấu giá hội tại thạch điện thu phí vào cửa, tổ chức bán vật phẩm trong đại sảnh và đưa người trúng giá tới hậu đường giao nhận hàng.","anchor":"Tất cả đều đi vào một căn thạch điện khác ở phía đối diện, tham gia đấu giá hội"}]},"capNhatToi":"@c0907","nguon":["@c0907"]},{"id":"dai-tan-the-gia-tu-tien","name":"Đại Tấn thế gia tu tiên","cn":"","type":"nhom-the-luc","typeLabel":"Nhóm thế gia tu tiên","diaBan":"Đại Tấn","nhanVatChinh":[],"blurb":"Các thế gia tu tiên tại Đại Tấn có quan hệ chặt với thế tục hơn mô hình gia tộc tu tiên Thiên Nam. Họ giao thiệp với phú hào, quan lại, tán tu và nắm tài sản liên quan tài nguyên tu luyện.","detail":"Đại Diễn Thần Quân giải thích rằng thế gia tu tiên Đại Tấn thường không tách rời phàm tục. Do triều đình phàm nhân nắm không ít linh dược, linh thạch và tài nguyên, các gia tộc tu tiên phải thông qua tài sản, nhân lực và quan hệ thế tục để duy trì lợi ích tu luyện.","dinhDanh":"goc","dacDiem":"gắn với thế tục, quan lại, phú hào và tài nguyên triều đình","tabs":{"tienTrinh":[{"chuong":"@c0910","loai":"nhắc tới","importance":"normal","giaiDoan":"Cơ chế thế gia","text":"Đại Diễn Thần Quân giải thích thế gia tu tiên Đại Tấn khác Thiên Nam vì gắn nhiều với tài sản và quan hệ phàm tục.","anchor":"Đại Tấn thế gia cùng Thiên Nam tu tiên gia tộc có chút bất đồng"}]},"capNhatToi":"@c0910","nguon":["@c0910"]},{"id":"trieu-dinh-pham-nhan-dai-tan","name":"Triều đình phàm nhân Đại Tấn","cn":"","type":"trieu-dinh","typeLabel":"Triều đình thế tục","diaBan":"Đại Tấn","nhanVatChinh":[],"blurb":"Triều đình phàm nhân mạnh tại Đại Tấn, nắm không ít tài nguyên có liên quan tu luyện. Thế lực tu tiên phải có thỏa thuận và kiểm soát để triều đình không bành trướng quá mức trong tu chân giới.","detail":"Theo lời Đại Diễn Thần Quân, nhiều linh dược, linh thạch và tài nguyên không nằm trong vùng hoang vu mà rơi vào tay phàm nhân, khiến triều đình Đại Tấn trở thành một đầu mối quan trọng. Triều đình có thể mời chào tán tu và bồi dưỡng tu chân hoàng tộc, nhưng vẫn chịu sự giám sát của các thế lực tu tiên.","dinhDanh":"goc","quyMo":"mạnh trong thế tục và nắm tài nguyên tu tiên","quanHe":"có thỏa thuận và bị các tông môn tu tiên kiểm soát","tabs":{"tienTrinh":[{"chuong":"@c0910","loai":"nhắc tới","importance":"normal","giaiDoan":"Tài nguyên triều đình","text":"Triều đình phàm nhân Đại Tấn được nhắc là nắm không ít linh dược, linh thạch và tài nguyên, nên liên quan trực tiếp tới lợi ích tu tiên.","anchor":"không ít linh dược linh thạch, tài nguyên không nằm trong những nơi hoang vu"}]},"capNhatToi":"@c0910","nguon":["@c0910"]},{"id":"cac-tong-mon-lon-nho-dai-tan","name":"Các tông môn lớn nhỏ Đại Tấn","cn":"","type":"tong-mon","typeLabel":"Nhóm tông môn tu tiên","diaBan":"Đại Tấn","nhanVatChinh":[],"blurb":"Các tông môn tu tiên Đại Tấn đứng sau nhiều thế lực thế tục để nắm nhân lực và tài nguyên. Họ đồng thời gây áp lực để triều đình phàm nhân không mở rộng tu chân lực quá mức.","detail":"Đại Diễn Thần Quân nói sau lưng vương gia, quý tộc và quận thủ tại Đại Tấn thường có bóng dáng tông môn hoạt động. Các tông môn vừa tranh đoạt lợi ích thế tục, vừa duy trì thỏa thuận kiểm soát với triều đình phàm nhân.","dinhDanh":"goc","dacDiem":"hoạt động sau lưng quan lại, quý tộc và địa phương","quanHe":"kiểm soát và thỏa thuận với triều đình phàm nhân Đại Tấn","tabs":{"tienTrinh":[{"chuong":"@c0910","loai":"nhắc tới","importance":"normal","giaiDoan":"Đứng sau thế tục","text":"Các tông môn lớn nhỏ Đại Tấn được nhắc là hoạt động sau lưng nhiều thế lực thế tục để chiếm nhân lực và tài nguyên tu luyện.","anchor":"cơ hồ điều xuất hiện bóng dáng các tông môn hoạt động sau lưng"}]},"capNhatToi":"@c0910","nguon":["@c0910"]},{"id":"mo-that-tuyet-lang-son-cua-dai-vuong","name":"Mộ thất Tuyết Lăng sơn của Đại vương","cn":"","type":"to-chuc-bi-an","typeLabel":"Ổ nhóm trong mộ thất","diaBan":"Mộ thất trong Tuyết Lăng sơn mạch","nhanVatChinh":["Nam tử trong thạch quan / Đại vương mộ thất Tuyết Lăng sơn","Nữ tử trong thạch quan khác / ái phi của Đại vương","Hai nhân ảnh lục sắc mộ thất Tuyết Lăng sơn"],"blurb":"Nhóm bí ẩn ẩn trong mộ thất Tuyết Lăng sơn, có Đại vương, ái phi, người gọi phụ vương và hai nhân ảnh lục sắc. Nhóm này bắt đầu nhắm vào Hàn Lập và các thế gia quanh Tuyết Lăng sơn.","detail":"Trong mộ thất có nhiều thạch quan và các tồn tại nghe lệnh Đại vương. Chương 910 cho thấy Đại vương sai hai nhân ảnh lục sắc truy sát Hàn Lập, ra lệnh dựng cấm chế sau khi hắn rời đi, đồng thời nói sẽ hỗ trợ tướng quân và xử lý nhân vật phiền toái của các thế gia.","dinhDanh":"goc","trangThai":"đang hoạt động @c0910","thanhVien":[{"ten":"Nam tử trong thạch quan / Đại vương mộ thất Tuyết Lăng sơn","chucVu":"Đại vương","tuChuong":"@c0910","trangThai":"rời mộ thất"},{"ten":"Nữ tử trong thạch quan khác / ái phi của Đại vương","chucVu":"ái phi","tuChuong":"@c0910","trangThai":"ở lại dựng cấm chế"},{"ten":"Hai nhân ảnh lục sắc mộ thất Tuyết Lăng sơn","chucVu":"thuộc hạ truy sát","tuChuong":"@c0910","trangThai":"truy tung Hàn Lập"}],"tabs":{"tienTrinh":[{"chuong":"@c0910","loai":"khai chiến","importance":"normal","giaiDoan":"Truy sát Hàn Lập","text":"Mộ thất Tuyết Lăng sơn của Đại vương phái hai nhân ảnh lục sắc truy sát Hàn Lập, đồng thời dựng cấm chế khi Đại vương rời đi.","anchor":"Sau khi ta rời đi, các người đem mộ thất dựng cấm chế"}]},"capNhatToi":"@c0910","nguon":["@c0910"]},{"id":"hai-the-gia-con-lai","name":"Hai thế gia còn lại","cn":"","type":"gia-toc","typeLabel":"Thế gia","diaBan":"khu vực quanh cổ mộ","nhanVatChinh":[],"blurb":"Hai thế gia bị phe Thiên Phong chân quân kéo vào kế hoạch vây sát Huyễn Vương.","detail":"Thiên Phong chân quân được nói đã âm thầm tiết lộ kế hoạch cho hai thế gia còn lại để họ cùng tông môn sau lưng chờ Huyễn Vương mắc bẫy.","trangThai":"bị kéo vào kế hoạch vây sát @c0911","quanHe":"Có tông môn đứng sau, liên quan kế hoạch đối phó Huyễn Vương.","tabs":{"tienTrinh":[{"chuong":"@c0911","loai":"liên minh","importance":"normal","giaiDoan":"Tham gia vòng vây Huyễn Vương","text":"Hai thế gia còn lại được Thiên Phong chân quân âm thầm tiết lộ kế hoạch để cùng chờ vây sát Huyễn Vương.","anchor":"đạo hữu đem kế hoạch âm thầm tiết lộ cho hai thế gia còn lại"}]},"capNhatToi":"@c0911","nguon":["@c0911"]},{"id":"tong-mon-dung-sau-hai-the-gia","name":"Tông môn đứng sau hai thế gia","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"không rõ","nhanVatChinh":[],"blurb":"Tông môn được suy đoán đã được hai thế gia mời tới để chờ Huyễn Vương mắc bẫy.","detail":"Trong kế hoạch vây sát Huyễn Vương, phe mai phục cho rằng hai thế gia đã âm thầm mời tông môn đứng sau họ tham gia chờ thời cơ.","trangThai":"được suy đoán tham gia phục kích @c0911","quanHe":"Đứng sau hai thế gia còn lại.","tabs":{"tienTrinh":[{"chuong":"@c0911","loai":"liên minh","importance":"normal","giaiDoan":"Chờ vây sát Huyễn Vương","text":"Tông môn đứng sau hai thế gia được suy đoán đã âm thầm tham gia kế hoạch phục kích Huyễn Vương.","anchor":"Nói vậy hai thế gia này cũng đã âm thầm mời tông môn đứng phía sau"}]},"capNhatToi":"@c0911","nguon":["@c0911"]},{"id":"dai-tong-mon-nam-chau","name":"Đại tông môn Nam Châu","cn":"","aliases":[],"type":"tong-mon","typeLabel":"Đại tông môn chưa nêu tên","diaBan":"Nam Châu","nhanVatChinh":["Hàn Lập"],"blurb":"Đại tông môn tại Nam Châu mà Hàn Lập dự tính trà trộn vào để mượn linh mạch tu luyện Minh Vương Quyết. Tên cụ thể của thế lực này chưa được nêu trong chương.","detail":"Hàn Lập muốn mượn phú thương Nam Châu do Phùng gia bồi dưỡng làm bình phong, từ đó bái nhập một đại tông môn ở Nam Châu. Mục tiêu của hắn là âm thầm tu luyện pháp quyết tại nơi có linh mạch tốt.","trangThai":"mục tiêu trà trộn của Hàn Lập","quanHe":"Hàn Lập dự định bái nhập bằng bình phong liên quan đường lui Phùng gia.","tabs":{"tienTrinh":[{"chuong":"@c0917","loai":"nhắc tới","importance":"normal","giaiDoan":"Mục tiêu trà trộn","text":"Hàn Lập dự tính dùng phú thương Nam Châu làm bình phong để bái nhập một đại tông môn tại Nam Châu.","anchor":"Có người này làm vật che chắn việc bái nhập vào nhất đại tông môn Nam Châu","trangThaiMoc":"chưa nêu tên"}]},"capNhatToi":"@c0917","nguon":["@c0917"]},{"id":"cam-gia","name":"Cam gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc thế tục","diaBan":"Bờ Tây Thái Xương thành","nhanVatChinh":["Cam Trì","Cam Dụ","Hàn Lập"],"blurb":"Cam gia là gia tộc phú thương trung lưu ở bờ Tây Thái Xương thành. Gia tộc này sở hữu hơn hai mươi tửu lâu, một cự trạch và có tuyến liên lạc bí mật với tu tiên giả.","detail":"Cam gia có địa vị trong nhóm phú thương Thái Xương phủ, do Cam Trì làm gia chủ và Cam Dụ là đại công tử. Sau khi Hàn Lập xuất trình nửa khối bạch ngọc, Cam Trì xác nhận tuyến liên lạc bí mật và từ đây chịu sự liên lạc, điều động của Hàn Lập trong phạm vi thân phận thế tục.","quyMo":"Phú thương trung lưu Thái Xương thành, có hơn hai mươi tửu lâu và vài chục nô bộc tùy tùng","thanhVien":[{"ten":"Cam Trì","chucVu":"gia chủ","tuChuong":"@c0919","trangThai":"đang tại vị"},{"ten":"Cam Dụ","chucVu":"đại công tử","tuChuong":"@c0919","trangThai":"đang ở Cam phủ"}],"quanHe":"Có tuyến liên lạc bí mật với tu tiên giả; từ chương này Hàn Lập tiếp quản liên lạc.","trangThai":"đang hoạt động","capNhatToi":"@c0919","tabs":{"tienTrinh":[{"chuong":"@c0919","loai":"nhắc tới","importance":"major","giaiDoan":"Hàn Lập tiếp quản liên lạc","text":"Cam gia được xác lập là gia tộc phú thương có tuyến liên lạc bí mật với tu tiên giả, và Hàn Lập trở thành người phụ trách liên lạc mới.","anchor":"Phú thương này tại Thái Xương phủ sở hữu hơn hai mươi tửu lâu"}]},"nguon":["@c0919"]},{"id":"hoc-vien-dai-tan-tai-quan-nay","name":"Học viện Đại Tấn tại quận này","cn":"","type":"the-tuc","typeLabel":"Hệ thống giáo dục thế tục","diaBan":"Quận giáp ranh Bắc bộ và Trung bộ Đại Tấn","nhanVatChinh":[],"blurb":"Hệ thống học viện trong quận được mô tả phát triển mạnh và phân tầng rõ rệt. Nó tạo đường tiến thân cho con em nghèo và đào tạo nho sinh được tầng lớp thượng lưu trọng vọng.","detail":"Từ học viện nhất đẳng giảng Tứ Thư Ngũ Kinh đến tư học phổ thông, hệ thống giáo dục thế tục trong quận có quy mô rộng từ phủ thành đến hương thôn, phản ánh phong khí trọng nho học trong vùng.","quyMo":"Phủ thành đến hương thôn","trangThai":"đang thịnh hành","capNhatToi":"@c0919","tabs":{"tienTrinh":[{"chuong":"@c0919","loai":"nhắc tới","importance":"normal","giaiDoan":"Giới thiệu hệ thống học viện","text":"Hệ thống học viện trong quận được giới thiệu là phân tầng rõ rệt và có vai trò nâng đỡ sĩ tử thế tục.","anchor":"Những học viện này được phân chia thành ba trăm sáu mươi chín đẳng cấp rõ rệt"}]},"nguon":["@c0919"]},{"id":"bach-lo-thu-vien","name":"Bạch Lộ thư viện","cn":"","type":"tong-mon","typeLabel":"Nho môn thư viện","diaBan":"Huyễn Vân phong, Ngọc Điền Sơn","nhanVatChinh":["Lỗ Đại tiên sinh","Thanh niên nho sam áo trắng"],"blurb":"Bạch Lộ thư viện bề ngoài là thư viện bậc trung ngoài thành Thái Xương, nhưng thực chất tọa lạc trên linh sơn nổi danh Ngọc Điền Sơn. Nơi này có lịch sử hơn nghìn năm, thu đệ tử thất thường và mang sắc thái thần bí.","detail":"Bạch Lộ thư viện được xây trên Huyễn Vân phong thuộc Ngọc Điền Sơn, quy mô từ sườn núi lên tới đỉnh núi và đủ dung nạp hơn nghìn người. Dù xung quanh có danh quán đại miếu, các tăng nhân đạo sĩ đều khách khí với thư sinh trong viện; người đọc sách vào viện cũng rất ít khi rời đại môn, khiến nơi này trở thành mục tiêu Hàn Lập muốn trà trộn để tu luyện trên linh mạch.","nguonGoc":"Tồn tại hơn nghìn năm trên Ngọc Điền Sơn","tonChi":"Nho môn tu hành và thu nhận đệ tử theo quy củ riêng","quyMo":"Có thể dung nạp hơn nghìn người","trangThai":"đang hoạt động","capNhatToi":"@c0920","thanhVien":[{"ten":"Lỗ Đại tiên sinh","chucVu":"tiên sinh trong thư viện","tuChuong":"@c0920","trangThai":"đang hoạt động"},{"ten":"Thanh niên nho sam áo trắng","chucVu":"tu sĩ canh cửa phụ","tuChuong":"@c0920","trangThai":"đang hoạt động"}],"tabs":{"tienTrinh":[{"chuong":"@c0920","loai":"nhắc tới","importance":"normal","giaiDoan":"Mục tiêu trà trộn của Hàn Lập","text":"Bạch Lộ thư viện được giới thiệu là thư viện thần bí trên Huyễn Vân phong, đồng thời trở thành nơi Hàn Lập nhắm tới để trà trộn tu luyện trên linh mạch.","trangThaiMoc":"đang hoạt động","anchor":"Bạch Lộ thư viện được tu kiến tại ngọn Huyễn Vân phong của dãy núi này"}]},"nguon":["@c0920"]},{"id":"bao-linh-tu","name":"Bảo Linh tự","cn":"","type":"tong-mon","typeLabel":"Phật tông tự viện","diaBan":"Ngọn núi lân cận Huyễn Vân phong","nhanVatChinh":[],"blurb":"Bảo Linh tự là phật tông nằm trên ngọn núi gần Huyễn Vân phong. Tự viện này sở hữu Thanh Thiền Chung, chiếc chuông được Nghiêm Nghiêu xem là bảo vật hiếm thấy.","detail":"Trên đường dẫn Hàn Lập lên Bạch Lộ thư viện, Nghiêm Nghiêu nhắc tới Thanh Thiền Chung của Bảo Linh tự. Hàn Lập nhân đó nhận ra chuông được coi là bảo vật này thực chất chỉ là một kiện thượng phẩm pháp khí.","trangThai":"đang hoạt động","capNhatToi":"@c0920","tranPhai":"Thanh Thiền Chung","tabs":{"tienTrinh":[{"chuong":"@c0920","loai":"nhắc tới","importance":"normal","giaiDoan":"Được nhắc khi lên núi","text":"Bảo Linh tự được nhắc tới qua Thanh Thiền Chung, bảo vật của tự viện mà Nghiêm Nghiêu giới thiệu với Hàn Lập.","trangThaiMoc":"đang hoạt động","anchor":"Thanh Thiền Chung này của Bảo Linh tự, thật đúng là một bảo vật hiếm thấy"}]},"nguon":["@c0920"]},{"id":"hoang-thanh-quan","name":"Hoàng Thanh quan","cn":"","aliases":[],"type":"dao-quan","typeLabel":"Đạo quán nữ tu","diaBan":"Dãy Ngọc Điền sơn","nhanVatChinh":["Hoa Liên tiên cô"],"blurb":"Hoàng Thanh quan là đạo quán trong dãy Ngọc Điền sơn, được Hoa Liên tiên cô đại diện xuất hiện tại Bạch Lộ thư viện. Tuy là nữ quan, nơi này vẫn có tu sĩ tại gia và nam tử môn nhân sống ngoài quan.","detail":"Hoàng Thanh quan đang chuẩn bị luyện chế vài món bảo vật và cần mượn một đệ tử bậc thấp hiểu luyện khí thuật làm trợ thủ. Hoa Liên tiên cô vì vậy đề nghị đưa Hàn Lập sang Hoàng Thanh quan, đồng thời giải thích đạo quán không chỉ có nữ tu mà còn có tu sĩ tại gia cùng nam tử môn nhân sống ngoài quan.","trangThai":"đang hoạt động","thanhVien":[{"ten":"Hoa Liên tiên cô","chucVu":"đạo cô","tuChuong":"@c0921","trangThai":"đang hoạt động"}],"quanHe":"Có giao tiếp với Bạch Lộ thư viện khi cần mượn người hiểu luyện khí thuật.","tabs":{"tienTrinh":[{"chuong":"@c0921","loai":"nhắc tới","importance":"normal","giaiDoan":"Muốn nhận Hàn Lập","text":"Hoa Liên tiên cô đại diện Hoàng Thanh quan đề nghị nhận Hàn Lập làm trợ thủ luyện chế bảo vật và giải thích đạo quán có cả tu sĩ tại gia cùng nam tử môn nhân.","anchor":"Hoàng Thanh quan mặc dù là nữ quan, nhưng bên trong cũng không phải không có tại gia tu sĩ cùng nam tử môn nhân gia nhập"}]},"capNhatToi":"@c0921","nguon":["@c0921"]},{"id":"tam-hoang-quan","name":"Tam Hoàng quan","cn":"","type":"dao-quan","typeLabel":"Đạo quan hệ phái","diaBan":"Đại Tấn","nhanVatChinh":["Hoa Liên tiên cô","Tứ sư thúc của Hoa Liên"],"blurb":"Tam Hoàng quan là hệ thống đạo quan gồm Hoàng Thanh quan và các nhánh khác như Hoàng Dương quan, Hoàng Thánh quan. Trong hệ này có cả nhánh do nam tu chủ trì, nên không thiếu pháp môn cho nam tu.","detail":"Hoa Liên tiên cô giới thiệu Hoàng Thanh quan chỉ là một tiểu nhánh của Tam Hoàng quan. Các nhánh khác như Hoàng Dương quan, Hoàng Thánh quan có đạo quán do nam tu chủ trì, trở thành lý do nàng dùng để thuyết phục Hàn Lập rằng nam tu vẫn có pháp môn thích hợp.","quyMo":"gồm nhiều nhánh đạo quan","thanhVien":[{"ten":"Hoa Liên tiên cô","chucVu":"môn nhân Hoàng Thanh quan","tuChuong":"@c0922","trangThai":"đang thuộc"},{"ten":"Tứ sư thúc của Hoa Liên","chucVu":"trưởng bối","tuChuong":"@c0922","trangThai":"được nhắc tới"}],"tabs":{"tienTrinh":[{"chuong":"@c0922","loai":"nhắc tới","importance":"normal","giaiDoan":"Lộ hệ thống nhánh","text":"Hoa Liên tiên cô giới thiệu Hoàng Thanh quan là một nhánh nhỏ trong Tam Hoàng quan và nhắc các nhánh khác có nam tu chủ trì.","anchor":"những nhánh khác là Hoàng Dương quan, Hoàng Thánh quan","trangThaiMoc":"đang tồn tại"}]},"capNhatToi":"@c0922","nguon":["@c0922"]},{"id":"nho-mon","name":"Nho môn","cn":"","type":"he-tu-luyen","typeLabel":"Hệ tu luyện","diaBan":"Đại Tấn","nhanVatChinh":["Lỗ Đại tiên sinh","Nghiêm Nghiêu"],"blurb":"Nho môn là hệ tu luyện chú trọng nhập thế và hạo nhiên chi khí. Trong chương 922, Nho môn được mô tả đối lập với ma đạo và không e ngại Hắc Dương tông như các tông môn nhỏ.","detail":"Lỗ Đại tiên sinh nói Nho môn vốn cùng ma đạo nước lửa bất dung, vì vậy không giống các tông môn nhỏ mà sợ trêu chọc thập đại ma tông. Nho môn công pháp cũng được so sánh với Đạo gia công pháp khi bàn chuyện Hàn Lập nên nhập Bạch Lộ thư viện hay Hoàng Thanh quan.","tonChi":"nhập thế, nghị luận triều chính, tu hạo nhiên chi khí","quanHe":"đối lập ma đạo","thanhVien":[{"ten":"Lỗ Đại tiên sinh","chucVu":"tu sĩ Bạch Lộ thư viện","tuChuong":"@c0922","trangThai":"đang thuộc"},{"ten":"Nghiêm Nghiêu","chucVu":"nho sinh","tuChuong":"@c0922","trangThai":"đang thuộc"}],"tabs":{"tienTrinh":[{"chuong":"@c0922","loai":"nhắc tới","importance":"normal","giaiDoan":"Đối lập ma đạo","text":"Lỗ Đại tiên sinh nêu Nho môn vốn đối lập ma đạo nên không e ngại Hắc Dương tông như các tông môn nhỏ.","anchor":"Chúng ta nho môn vốn cùng ma đạo nước lửa bất dung","trangThaiMoc":"đang tồn tại"}]},"capNhatToi":"@c0922","nguon":["@c0922"]},{"id":"hac-duong-tong","name":"Hắc Dương tông","cn":"","type":"ma-tong","typeLabel":"Ma tông","diaBan":"Đại Tấn","nhanVatChinh":["Ngưu Thiên Đức"],"blurb":"Hắc Dương tông là một trong thập đại ma tông được nhắc trong tuyến thù hận của Nghiêm gia. Ngưu Thiên Đức là ngoại sự chấp pháp của tông này.","detail":"Nho sinh họ Nghiêm lo nhiều tu sĩ không muốn vì một phàm nhân mà trêu chọc thập đại ma tông. Lỗ Đại tiên sinh xác nhận Ngưu Thiên Đức là ngoại sự chấp pháp Hắc Dương tông và nhận định hành vi của người này độc ác.","capBac":"một trong thập đại ma tông","thanhVien":[{"ten":"Ngưu Thiên Đức","chucVu":"ngoại sự chấp pháp","tuChuong":"@c0922","trangThai":"đang thuộc"}],"tabs":{"tienTrinh":[{"chuong":"@c0922","loai":"nhắc tới","importance":"normal","giaiDoan":"Lộ thân phận Ngưu Thiên Đức","text":"Hắc Dương tông được nhắc là thế lực ma đạo lớn đứng sau Ngưu Thiên Đức, khiến nhiều tu sĩ không muốn trêu chọc.","anchor":"Ngưu Thiên Đức nọ ngoại sự chấp pháp Hắc Dương tông","trangThaiMoc":"đang tồn tại"}]},"capNhatToi":"@c0922","nguon":["@c0922"]},{"id":"luyen-khi-dien","name":"Luyện Khí điện","cn":"","aliases":[],"type":"co-cau","typeLabel":"Cơ cấu thuộc Hoàng Thanh quan","diaBan":"Giữa núi Hoàng Thanh quan","nhanVatChinh":["Vi lão","Hàn Lập","Ba gã đệ tử Luyện Khí điện","Hai tu sĩ Luyện Khí kỳ trung niên của Luyện Khí điện"],"blurb":"Luyện Khí điện là biệt viện giữa núi của Hoàng Thanh quan, chuyên tiếp nhận việc luyện khí và tinh luyện tài liệu. Đây là nơi Hàn Lập được đưa vào làm trợ thủ cho Vi lão.","detail":"Luyện Khí điện gồm địa hỏa đại điện, vài luyện khí các và các động phủ dựa vào núi cho đệ tử sinh sống. Nhân sự trong điện có Vi lão, hai tu sĩ Luyện Khí kỳ trung niên làm trợ thủ và bốn đệ tử kể cả Hàn Lập.","lanhDaoHienThoi":"Vi lão","quyMo":"Một luyện khí sư chuyên trách, hai tu sĩ trung niên trợ thủ và bốn đệ tử","thanhVien":[{"ten":"Vi lão","chucVu":"Luyện khí sư phụ trách","tuChuong":"@c0923","trangThai":"đang ở"},{"ten":"Hàn Lập","chucVu":"Đệ tử trợ thủ","tuChuong":"@c0923","trangThai":"đang ở"},{"ten":"Ba gã đệ tử Luyện Khí điện","chucVu":"Đệ tử cấp thấp","tuChuong":"@c0923","trangThai":"đang ở"},{"ten":"Hai tu sĩ Luyện Khí kỳ trung niên của Luyện Khí điện","chucVu":"Trợ thủ luyện khí","tuChuong":"@c0923","trangThai":"đang ở"}],"tabs":{"tienTrinh":[{"chuong":"@c0923","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập gia nhập","text":"Luyện Khí điện được giới thiệu là biệt viện giữa núi của Hoàng Thanh quan và trở thành nơi Hàn Lập bắt đầu sinh hoạt.","anchor":"Cái gọi là Luyện Khí điện, kì thật chính là tại chính giữa ngọn núi của Hoàng Thanh quan"}]},"capNhatToi":"@c0923","nguon":["@c0923"]},{"id":"thien-thanh-vien","name":"Thiên Thanh viện","cn":"","type":"co-cau","typeLabel":"Cơ cấu trong Hoàng Thanh quan","diaBan":"Hoàng Thanh quan","nhanVatChinh":[],"blurb":"Thiên Thanh viện là nơi được nhắc trong Hoàng Thanh quan, có tu sĩ Nguyên Anh kỳ duy nhất của quán cư trú. Sự tồn tại của nơi này cho thấy Hoàng Thanh quan có cao tầng vượt trên bốn quán chủ Kết Đan kỳ.","detail":"Trong hồi tưởng của Hàn Lập, Hoàng Thanh quan trên danh nghĩa có bốn vị quán chủ Kết Đan kỳ, còn Thiên Thanh viện có một tu sĩ Nguyên Anh kỳ duy nhất.","thanhVien":[{"ten":"Tu sĩ Nguyên Anh kỳ duy nhất của Hoàng Thanh quan","chucVu":"cao tầng cư trú tại Thiên Thanh viện","tuChuong":"@c0924","trangThai":"được nhắc"}],"capNhatToi":"@c0924","tabs":{"tienTrinh":[{"chuong":"@c0924","loai":"nhắc tới","importance":"normal","giaiDoan":"hé lộ cơ cấu","text":"Thiên Thanh viện được nhắc là nơi có tu sĩ Nguyên Anh kỳ duy nhất của Hoàng Thanh quan.","trangThaiMoc":"được nhắc","anchor":"Trong quán còn có một cái Thiên Thanh viện"}]},"nguon":["@c0924"]},{"id":"vuong-phu-cua-luc-tu-quan-chua","name":"Vương phủ của Lục Tú quận chúa","cn":"","aliases":[],"type":"the-tuc","typeLabel":"Vương phủ","diaBan":"Không rõ","nhanVatChinh":["Lục Tú quận chúa"],"blurb":"Vương phủ của Lục Tú quận chúa là nơi nàng nhắc tới khi nói dù ở trong vương phủ vẫn từng nghe đại danh Vi đại sư. Chi tiết này xác nhận xuất thân quyền quý của nàng.","detail":"Vương phủ chưa được mô tả trực tiếp, nhưng lời Lục Tú quận chúa cho thấy nàng có thân phận vương phủ và tiếp xúc với danh tiếng của các luyện khí sư nổi danh.","thanhVien":[{"ten":"Lục Tú quận chúa","chucVu":"quận chúa","tuChuong":"@c0924","trangThai":"gắn bó"}],"capNhatToi":"@c0924","tabs":{"tienTrinh":[{"chuong":"@c0924","loai":"nhắc tới","importance":"bridge","giaiDoan":"hé lộ xuất thân","text":"Lục Tú quận chúa nhắc mình ở trong vương phủ nhưng vẫn từng nghe đại danh Vi đại sư.","trangThaiMoc":"được nhắc","anchor":"dù ở trong vương phủ nhưng đã nghe đại danh Vi đại sư"}]},"nguon":["@c0924"]},{"id":"dai-tan-tu-dai-tan-tu","name":"Đại Tấn tứ đại tán tu","cn":"","aliases":["Tứ đại tán tu"],"type":"nhom-cao-nhan","typeLabel":"Nhóm cao nhân tán tu","diaBan":"Đại Tấn","nhanVatChinh":["Tổ phụ của Lục Tú quận chúa"],"blurb":"Đại Tấn tứ đại tán tu là nhóm bốn cao nhân tán tu nổi danh tại Đại Tấn. Lục Tú quận chúa tiết lộ tổ phụ của nàng là một trong số đó.","detail":"Hàn Lập nhớ từng nghe Tào Mộng Dung nói về nhóm này, trong đó có cả tu sĩ Nguyên Anh hậu kỳ và Nguyên Anh trung kỳ. Mỗi người đều có thần thông vượt xa tu sĩ Nguyên Anh bình thường.","capBac":"nhóm tán tu cao giai","thanhVien":[{"ten":"Tổ phụ của Lục Tú quận chúa","chucVu":"một trong bốn tán tu","tuChuong":"@c0925","trangThai":"đang nhắc tới"}],"capNhatToi":"@c0925","tabs":{"tienTrinh":[{"chuong":"@c0925","loai":"nhắc tới","importance":"normal","giaiDoan":"Lộ liên hệ với Lục Tú","text":"Lục Tú quận chúa nói tổ phụ nàng là một trong Đại Tấn tứ đại tán tu, khiến Hàn Lập nhớ lại danh tiếng của nhóm cao nhân này.","anchor":"Tứ đại tán tu này, ban đầu hắn từ trong miệng Tào Mộng Dung nghe nói qua"}]},"nguon":["@c0925"]},{"id":"phat-dao-cac-the-luc","name":"Phật đạo các thế lực","cn":"","aliases":[],"type":"lien-minh-long-leo","typeLabel":"Các thế lực lớn","diaBan":"Đại Tấn","nhanVatChinh":[],"blurb":"Phật đạo các thế lực được đạo cô họ Diệp nêu như những đại thế lực mà hoàng tộc Diệp gia khó chống trực diện. Đây là một phần sức ép khiến kế hoạch mưu đoạt linh bảo trở nên nguy hiểm.","detail":"Đạo cô cho rằng dù hoàng tộc có thực lực ẩn tàng, nếu thật sự va chạm với các thế lực Phật và Đạo thì vẫn khó chịu nổi một kích. Trung niên mỹ phụ cũng thừa nhận Diệp gia lâu nay bị các thế lực lớn kìm kẹp.","capNhatToi":"@c0925","tabs":{"tienTrinh":[{"chuong":"@c0925","loai":"nhắc tới","importance":"normal","giaiDoan":"Sức ép lên Diệp gia","text":"Phật đạo các thế lực được nêu là những đối thủ mà Diệp gia khó đối đầu trực diện nếu kế hoạch bại lộ.","anchor":"nhưng nếu cùng phật đạo các thế lực thực sự va chạm"}]},"nguon":["@c0925"]},{"id":"vai-the-luc-lon-o-kinh-thanh","name":"Vài thế lực lớn ở kinh thành","cn":"","aliases":[],"type":"lien-minh-long-leo","typeLabel":"Các thế lực lớn","diaBan":"Kinh thành Đại Tấn","nhanVatChinh":[],"blurb":"Nhóm thế lực lớn ở kinh thành được Diệp gia nhắc như các phe đang bắt đầu nghi ngờ động thái của hoàng tộc. Họ tăng số tu sĩ Kết Đan kỳ đóng ở kinh thành nhưng chưa tăng rõ Nguyên Anh kỳ.","detail":"Trong cuộc bàn bạc, mỹ phụ Diệp gia nói vài thế lực lớn bỗng tăng nhiều tu sĩ Kết Đan kỳ ở kinh thành. Đạo cô nhận định các phe này có lẽ mới nghi ngờ chứ chưa phát giác kế hoạch thật của Diệp gia.","trangThai":"đang chú ý kinh thành","capNhatToi":"@c0926","tabs":{"tienTrinh":[{"chuong":"@c0926","loai":"nhắc tới","importance":"normal","giaiDoan":"Tăng tu sĩ tại kinh thành","text":"Vài thế lực lớn ở kinh thành được nhắc là đã tăng số tu sĩ Kết Đan kỳ đóng tại kinh thành, khiến Diệp gia phải cẩn trọng tai mắt.","anchor":"tu sĩ tới đóng ở kinh thành của vài thế lực lớn này bỗng chốc nhiều hơn rất nhiều","trangThaiMoc":"nghi ngờ động thái Diệp gia"}]},"nguon":["@c0926"]},{"id":"minh-kiem-tong","name":"Minh Kiếm tông","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Khai Long Phủ, Phong Châu","nhanVatChinh":[],"blurb":"Môn phái tại Khai Long Phủ, Phong Châu, xảy ra vụ mất trộm Linh giác của Thiết Giác tê trong tông môn.","detail":"Minh Kiếm tông là một môn phái ở Khai Long Phủ thuộc Phong Châu. Trong làn sóng các vụ tìm đoạt tài liệu quý tại Đại Tấn nam bộ, tông môn này bị mất Linh giác của Thiết Giác tê cất giữ trong nội bộ, không rõ người lấy.","nguon":["@c0927"]},{"id":"tong-binh-the-gia","name":"Tông Bình thế gia","cn":"","type":"the-gia","typeLabel":"Thế gia","diaBan":"Khúc quận","nhanVatChinh":["Tông Bình gia chủ","Hai Nguyên Anh đại trưởng lão Tông Bình gia","Đại hán xấu xí Nguyên Anh trung kỳ"],"blurb":"Đệ nhất thế gia Khúc quận, bị đại hán xấu xí Nguyên Anh trung kỳ ép giao Ngũ Quang mộc.","detail":"Tông Bình thế gia là đệ nhất thế gia ở Khúc quận, cất giữ Ngũ Quang mộc. Khi đại hán xấu xí Nguyên Anh trung kỳ tới ép đổi bảo vật bằng linh thảo ngàn năm và yêu đan thất cấp, gia chủ mời hai đại trưởng lão Nguyên Anh ra tay nhưng cả hai bị đóng băng bằng đại thần thông; cuối cùng gia chủ phải giao Ngũ Quang mộc, còn đại hán để lại vật trao đổi rồi rời đi.","nguon":["@c0927"]},{"id":"cac-tu-tien-tong-mon-dai-tan-nam-bo","name":"Các tu tiên tông môn Đại Tấn nam bộ","cn":"","type":"nhom-the-luc","typeLabel":"Nhóm thế lực","diaBan":"Đại Tấn nam bộ","nhanVatChinh":[],"blurb":"Nhóm tông môn tại Đại Tấn nam bộ bị cuốn vào các vụ mất trộm tài liệu và cưỡng ép giao dịch thiên tài địa bảo.","detail":"Tại Đại Tấn nam bộ, nhiều tu tiên tông môn bị chấn động bởi chuỗi vụ mất trộm nội khố và cưỡng ép giao dịch liên quan đến các tài liệu trân quý. Các tông môn nổi giận, liên tục phái môn hạ đệ tử và nhân thủ đi khắp nơi truy tìm đạo tặc hoặc thủ phạm thần bí.","nguon":["@c0927"]},{"id":"ma-moc-tong","name":"Ma Mộc Tông","cn":"","aliases":["Ma Mộc tông"],"type":"tong-mon","typeLabel":"Ma đạo tông môn","diaBan":"Lũng châu","nhanVatChinh":[],"blurb":"Một trong mười ma tông lớn của Đại Tấn. Tại Lũng châu, Ma Mộc Tông cùng Nhạc Dương Cung tạo thành cục diện hai thế lực mạnh cùng quản lý toàn châu.","detail":"Ma Mộc Tông được nhắc như thế lực ma đạo ngang hàng trong cục diện Lũng châu. Sự tồn tại của tông này khiến các thế lực nhỏ bản xứ khó tự lập, phải nương nhờ hai nhà lớn để được che chở.","trangThai":"cùng Nhạc Dương Cung khống chế Lũng châu","capNhatToi":"@c0928","tabs":{"tienTrinh":[{"chuong":"@c0928","loai":"nhắc tới","importance":"normal","giaiDoan":"Thế cục Lũng châu","text":"Ma Mộc Tông được nêu là một trong mười ma tông lớn và cùng Nhạc Dương Cung quản lý Lũng châu.","anchor":"Ma Mộc Tông, một trong mười ma tông lớn, nắm quyền quản lý"}]},"nguon":["@c0928"]},{"id":"cac-tong-phai-nho-ban-xu-lung-chau","name":"Các tông phái nhỏ bản xứ Lũng châu","cn":"","type":"lien-minh-long-leo","typeLabel":"Nhóm tông phái nhỏ","diaBan":"Lũng châu","nhanVatChinh":[],"blurb":"Các tông phái tu tiên bản xứ yếu hơn nhiều so với Nhạc Dương Cung và Ma Mộc Tông. Họ không thể uy hiếp hai siêu cấp tông môn và phải dựa vào hai nhà để tồn tại.","detail":"Trong thế cục Lũng châu, các tông phái nhỏ chỉ đóng vai trò phụ thuộc. Vì bên ngoài khó chen chân vào Lũng châu, những thế lực bản địa này càng không có khả năng thay đổi cục diện hai tông mạnh cùng khống chế.","trangThai":"phụ thuộc hai đại tông","capNhatToi":"@c0928","tabs":{"tienTrinh":[{"chuong":"@c0928","loai":"nhắc tới","importance":"bridge","giaiDoan":"Thế cục Lũng châu","text":"Các tông phái nhỏ bản xứ Lũng châu không đủ uy hiếp Nhạc Dương Cung và Ma Mộc Tông.","anchor":"các tông phái nhỏ không đáng nhắc đến, càng không thể tạo thành uy hiếp với hai tông môn siêu cấp này"}]},"nguon":["@c0928"]},{"id":"nhac-duong-cung-bi-dien","name":"Nhạc Dương cung bí điện","cn":"","type":"tong-mon","typeLabel":"Bí điện thuộc tông môn","diaBan":"Thiên Nhạc sơn mạch","nhanVatChinh":["Tử bào lão ẩu Nhạc Dương cung bí điện","Phương Chử","Hạo Dương điểu"],"blurb":"Nhạc Dương cung bí điện là bộ phận liên quan đến tử bào lão ẩu và Hạo Dương điểu.","detail":"Sau khi Hạo Dương điểu bị lấy lông đuôi trong sơn cốc, tử bào lão ẩu của bí điện cùng Phương Chử tới kiểm tra hiện trường. Việc bà nổi giận và truy dấu cho thấy linh cầm có quan hệ mật thiết với bí điện này.","thanhVien":[{"ten":"Tử bào lão ẩu Nhạc Dương cung bí điện","chucVu":"Tu sĩ bí điện","tuChuong":"@c0930","trangThai":"đang hoạt động"},{"ten":"Phương Chử","chucVu":"Người đi cùng tử bào lão ẩu","tuChuong":"@c0930","trangThai":"đang hoạt động"}],"quanHe":"Có nghi ngờ với Ma Mộc tông sau biến cố Hạo Dương điểu.","tabs":{"tienTrinh":[{"chuong":"@c0930","loai":"nhắc tới","importance":"normal","giaiDoan":"Truy tìm kẻ tập kích linh cầm","text":"Tử bào lão ẩu của Nhạc Dương cung bí điện tới sơn cốc sau khi Hạo Dương điểu bị lấy lông đuôi và truy dấu nghi phạm.","anchor":"người đó chính là Nhạc Dương cung bí điện tử bào lão ẩu"}]},"capNhatToi":"@c0930","nguon":["@c0930"]},{"id":"quan-phu-dai-tan-quoc","name":"Quan phủ Đại Tấn quốc","cn":"","aliases":[],"type":"trieu-dinh","typeLabel":"Quan phủ phàm tục","diaBan":"Tấn kinh và vùng phụ cận","nhanVatChinh":["Trụ Nam tướng quân"],"blurb":"Quan phủ Đại Tấn quốc là hệ thống quyền lực phàm tục khiến giới tu tiên cũng phải kiêng kị. Quanh Tấn kinh tồn tại quy định ngầm cấm tu tiên giả đánh nhau và phi hành.","detail":"Trong phạm vi ngàn dặm quanh Tấn kinh, giới tu tiên Đại Tấn có quy định ngầm cấm đánh nhau và phi hành. Việc tra xét do tán tu được quan phủ thuê đảm nhiệm, cho thấy quan phủ Đại Tấn có liên hệ và sức ràng buộc nhất định với giới tu tiên.","quyMo":"Có ảnh hưởng tới trật tự phàm tục và quy tắc ngầm quanh Tấn kinh","quanHe":"Khiến tu sĩ Đại Tấn có phần kiêng kị","trangThai":"đang duy trì trật tự quanh Tấn kinh","thanhVien":[{"ten":"Trụ Nam tướng quân","chucVu":"Tướng quân trấn Nam Cương","tuChuong":"@c0932","trangThai":"đang phục vụ"}],"tabs":{"tienTrinh":[{"chuong":"@c0932","loai":"nhắc tới","importance":"normal","giaiDoan":"Quy định quanh Tấn kinh","text":"Quan phủ Đại Tấn quốc được nhắc như thế lực khiến tu tiên giả kiêng kị và liên quan tới quy định cấm đánh nhau, phi hành quanh Tấn kinh.","anchor":"Bât kì người tu tiên nào cũng đều có một chút kiên kị đối với quan phủ đại Tấn quốc"}]},"capNhatToi":"@c0932","nguon":["@c0932"]},{"id":"doi-ky-binh-giap-bac-duoi-co-chu-vuong","name":"Đội kỵ binh giáp bạc dưới cờ chữ Vương","cn":"","aliases":[],"type":"quan-doi","typeLabel":"Quân đội phàm tục","diaBan":"Nam Cương Đại Tấn và tuyến đường về Tấn kinh","nhanVatChinh":["Trụ Nam tướng quân","Binh sĩ mặc giáp bạc của Trụ Nam tướng quân","Hai giáp sĩ dắt xe ngựa của Hàn Lập"],"blurb":"Đội kỵ binh giáp bạc dưới cờ chữ Vương là đoàn quân tinh nhuệ khoảng ba bốn trăm người do Trụ Nam tướng quân dẫn đầu. Họ đi cùng xe bích ngọc chở Tào Mộng Dung và Vương tiểu thư trên đường về Tấn kinh.","detail":"Đội quân xuất hiện trên quan đạo với vó ngựa dồn dập, giáp bạc, cờ chữ Vương và khí sát phạt nặng. Hàn Lập nhận định họ giống chiến sĩ thường xuyên trải qua sát phạt hơn quân thủ thành thông thường, giữa đoàn còn có xe bích ngọc pháp khí chở tu sĩ Luyện Khí.","quyMo":"Khoảng ba bốn trăm người","lanhDaoHienThoi":"Trụ Nam tướng quân","trangThai":"đang hộ tống về Tấn kinh","thanhVien":[{"ten":"Trụ Nam tướng quân","chucVu":"Người chỉ huy","tuChuong":"@c0932","trangThai":"đang chỉ huy"},{"ten":"Binh sĩ mặc giáp bạc của Trụ Nam tướng quân","chucVu":"Binh sĩ","tuChuong":"@c0932","trangThai":"đang phục vụ"},{"ten":"Hai giáp sĩ dắt xe ngựa của Hàn Lập","chucVu":"Giáp sĩ","tuChuong":"@c0932","trangThai":"đang phục vụ"}],"tabs":{"tienTrinh":[{"chuong":"@c0932","loai":"nhắc tới","importance":"normal","giaiDoan":"Vượt qua Hàn Lập","text":"Đội kỵ binh giáp bạc khoảng ba bốn trăm người mang cờ chữ Vương vượt qua Hàn Lập trên quan đạo và dừng lại ở hàng nước phía trước.","anchor":"Đội ngũ binh lính có khoảng ba bốn trăm người"}]},"capNhatToi":"@c0932","nguon":["@c0932"]},{"id":"dai-tan","name":"Đại Tấn","cn":"","type":"quoc-gia","typeLabel":"Quốc gia phàm tục","diaBan":"Đại Tấn","nhanVatChinh":["Trụ Nam tướng quân","Vương tiểu thư"],"blurb":"Đại Tấn là quốc gia nơi tám đại tướng quân nắm giữ quân lực trọng yếu. Chương này cho thấy quyền lực phàm tục của Đại Tấn gắn chặt với giới tu tiên.","detail":"Tám đại tướng quân gần như đại diện cho triều đình Đại Tấn, nắm hơn phân nửa quân lực và trấn giữ các nơi quan trọng. Ngoài một số người thuộc hoàng tộc, nhiều đại tướng quân còn có liên quan đến các thế lực tu tiên lớn hoặc do chính các thế lực này nâng đỡ.","quyMo":"Tám đại tướng quân nắm hơn phân nửa quân lực triều đình @c0933","trangThai":"đang tồn tại","tabs":{"tienTrinh":[{"chuong":"@c0933","loai":"nhắc tới","importance":"normal","giaiDoan":"Quân quyền Đại Tấn","text":"Đại Tấn được mô tả có tám đại tướng quân nắm giữ hơn phân nửa quân lực, trong đó nhiều người liên hệ với các thế lực tu tiên lớn.","anchor":"Tám đại tướng quân, cơ hồ đại biểu cho triều đình đại Tấn"}]},"capNhatToi":"@c0933","nguon":["@c0933"]},{"id":"trieu-dinh-dai-tan","name":"Triều đình Đại Tấn","cn":"","type":"trieu-dinh","typeLabel":"Triều đình phàm tục","diaBan":"Đại Tấn","nhanVatChinh":["Trụ Nam tướng quân"],"blurb":"Triều đình Đại Tấn là bộ máy quyền lực phàm tục đứng sau các đại tướng quân. Chương này cho thấy triều đình chịu ảnh hưởng đáng kể từ các thế lực tu tiên qua mạng lưới các tướng quân.","detail":"Triều đình Đại Tấn có tám đại tướng quân nắm giữ quân đội trọng yếu. Hàn Lập nhận ra ngoài một số tướng quân xuất thân hoàng tộc, những người còn lại đều liên quan tới các thế lực tu tiên lớn, thậm chí có người được thế lực tu tiên nâng đỡ lên.","quanHe":"Có nhiều đại tướng quân liên quan hoặc được thế lực tu tiên lớn nâng đỡ @c0933","trangThai":"đang tồn tại","tabs":{"tienTrinh":[{"chuong":"@c0933","loai":"nhắc tới","importance":"normal","giaiDoan":"Tu tiên ảnh hưởng triều đình","text":"Triều đình Đại Tấn được mô tả bị các thế lực tu tiên lớn ảnh hưởng thông qua những đại tướng quân không thuộc hoàng tộc.","anchor":"còn lại đều có liên quan đến vài thế lực tu tiên lớn có liên quan"}]},"capNhatToi":"@c0933","nguon":["@c0933"]},{"id":"tam-dai-tuong-quan-dai-tan","name":"Tám đại tướng quân Đại Tấn","cn":"","type":"quan-su","typeLabel":"Nhóm quyền lực quân sự","diaBan":"Đại Tấn","nhanVatChinh":["Trụ Nam tướng quân"],"blurb":"Tám đại tướng quân Đại Tấn là nhóm tướng lĩnh nổi danh nhất, mỗi người nắm quân trên trăm vạn. Trụ Nam tướng quân là một thành viên trong nhóm này.","detail":"Mỗi đại tướng quân nắm trong tay đội quân trên trăm vạn, tổng cộng gần như đại diện cho hơn phân nửa quân lực triều đình Đại Tấn. Nhóm này vừa có người thuộc hoàng tộc, vừa có người liên quan đến thế lực tu tiên lớn.","quyMo":"Mỗi đại tướng nắm quân trên trăm vạn @c0933","thanhVien":[{"ten":"Trụ Nam tướng quân","chucVu":"Một trong tám đại tướng quân","tuChuong":"@c0933","trangThai":"đang tại vị"}],"trangThai":"đang tồn tại","tabs":{"tienTrinh":[{"chuong":"@c0933","loai":"nhắc tới","importance":"normal","giaiDoan":"Tướng quyền trọng yếu","text":"Tám đại tướng quân Đại Tấn được giới thiệu là nhóm tướng lĩnh nổi danh nhất, mỗi người nắm đội quân trên trăm vạn.","anchor":"Mỗi một vị đại tướng nắm trong tay đội quân trên trăm vạn"}]},"capNhatToi":"@c0933","nguon":["@c0933"]},{"id":"ba-nha-quan-ly-tham-vuong-dai-hoi","name":"Ba nhà quản lý Tham vương đại hội","cn":"","type":"lien-minh","typeLabel":"Liên minh thế lực","diaBan":"Ngọn núi tổ chức Tham vương đại hội","nhanVatChinh":["Hai gia chủ liên minh"],"blurb":"Ba nhà quản lý Tham vương đại hội là nhóm thế lực bị cuốn vào biến cố sau đại hội. Thành viên của họ bị Huyễn vương dùng quỷ trận vây khốn hơn một tháng.","detail":"Sau biến cố lão tổ Khổng gia, Huyễn vương nổi giận, thả thi vệ và lập quỷ trận vây thành viên ba nhà trong phạm vi hơn trăm dặm. Ba nhà chỉ dựa vào đại trận trên núi miễn cưỡng tự bảo vệ, sau khi được cao thủ Nguyên Anh giải vây thì quét sạch thế lực quanh vùng núi.","trangThai":"được giải vây sau biến cố quỷ trận","thanhVien":[{"ten":"Hai gia chủ liên minh","chucVu":"Gia chủ liên minh","tuChuong":"@c0935","trangThai":"khong-ro"}],"tabs":{"tienTrinh":[{"chuong":"@c0935","loai":"khai chiến","importance":"normal","giaiDoan":"Bị quỷ trận vây","trangThaiMoc":"Bị vây hơn một tháng rồi được giải vây","text":"Thành viên ba nhà trên ngọn núi tổ chức Tham vương đại hội bị Huyễn vương dùng quỷ trận vây khốn hơn một tháng, phải dựa vào đại trận để tự bảo vệ.","anchor":"Kết quả thành viên của ba nhà ở trên ngọn núi tổ chức Tham vương đại hội bị vây khốn"}]},"capNhatToi":"@c0935","nguon":["@c0935"]},{"id":"tam-thi-phe-huyen-vuong","name":"Tam thi / phe Huyễn vương","cn":"","type":"the-luc","typeLabel":"Thế lực thi quỷ","diaBan":"Tuyết Lăng sơn mạch","nhanVatChinh":["Huyễn Diệp vương","Hai thi yêu"],"blurb":"Tam thi / phe Huyễn vương là thế lực thi quỷ gồm Huyễn Diệp vương, hai thi yêu, thi vệ và các quỷ trận. Họ từng vây khốn tu sĩ ba nhà trước khi bị cao thủ Nguyên Anh đánh lui.","detail":"Huyễn Diệp vương thả hàng nghìn thi vệ Trúc Cơ, lập hoàng tuyền quỷ trận và cùng hai thi yêu tạo thế tam thi. Sau khi vây khốn tu sĩ ba nhà hơn một tháng, phe này bị một cao thủ Nguyên Anh ở phụ cận đánh lui và phải rút sâu vào Tuyết Lăng sơn mạch.","lanhDaoHienThoi":"Huyễn Diệp vương","trangThai":"rút sâu vào Tuyết Lăng sơn mạch","thanhVien":[{"ten":"Huyễn Diệp vương","chucVu":"Lãnh đạo","tuChuong":"@c0935","trangThai":"song"},{"ten":"Hai thi yêu","chucVu":"Đồng bọn trong tam thi","tuChuong":"@c0935","trangThai":"song"}],"tabs":{"tienTrinh":[{"chuong":"@c0935","loai":"khai chiến","importance":"normal","giaiDoan":"Vây ba nhà rồi rút lui","trangThaiMoc":"Bị cao thủ Nguyên Anh đánh lui","text":"Tam thi và phe Huyễn vương vây khốn tu sĩ ba nhà bằng quỷ trận, sau đó bị cao thủ Nguyên Anh đánh lui nên phải rút vào sâu trong Tuyết Lăng sơn mạch.","anchor":"thoáng cái đánh lui tam thi , làm chúng không thể không lui về vùng tuyết lăng sơn mạch sâu thẳm"}]},"capNhatToi":"@c0935","nguon":["@c0935"]},{"id":"thien-co-cac","name":"Thiên Cơ Các","cn":"","type":"thuong-cac","typeLabel":"Thương các","diaBan":"Tây Tấn phường thị","nhanVatChinh":["Trung niên áo bào trắng của Thiên Cơ Các","Sai vặt luyện khí kỳ của Thiên Cơ Các","Hai mỹ nữ tầng ba Thiên Cơ Các","Vương trưởng lão (Thiên Cơ các)","Hàn Lập","Lão giả họ Phú"],"blurb":"Thương các ba tầng nổi bật trong Tây Tấn phường thị, có cách tiếp đãi phân tầng và quan hệ với tu sĩ Nguyên Anh kỳ. Hàn Lập chọn nơi này để hỏi mua tài liệu hiếm trước đại đấu giá hội.","detail":"Thiên Cơ Các là tòa lầu ba tầng lớn hơn các thương hào xung quanh trong Tây Tấn phường thị. Tầng một có sai vặt Luyện Khí kỳ tiếp khách, tầng ba dùng để tiếp đãi khách cao giai bằng Vũ Linh trà; người phụ trách áo bào trắng nhận ra Hàn Lập có tu vi cao nên mời lên tầng ba và báo tin về khối nhỏ Lôi Linh thạch đang do một tiền bối Nguyên Anh kỳ giao hảo với bổn các sở hữu.","nguonGoc":"Thương các hoạt động trong Tây Tấn phường thị.","quyMo":"Lầu ba tầng, lớn hơn các thương hào xung quanh trong phường thị.","quanHe":"Có giao hảo với một tiền bối Nguyên Anh kỳ đang gửi hoặc liên hệ giao dịch Lôi Linh thạch.","trangThai":"đang hoạt động","thanhVien":[{"ten":"Trung niên áo bào trắng của Thiên Cơ Các","chucVu":"người phụ trách tiếp khách cao cấp","tuChuong":"@c0936","trangThai":"đang hoạt động"},{"ten":"Sai vặt luyện khí kỳ của Thiên Cơ Các","chucVu":"sai vặt tầng một","tuChuong":"@c0936","trangThai":"đang hoạt động"},{"ten":"Hai mỹ nữ tầng ba Thiên Cơ Các","chucVu":"người hầu tầng ba","tuChuong":"@c0936","trangThai":"đang hoạt động"},{"ten":"Vương trưởng lão (Thiên Cơ các)","chucVu":"trưởng lão","tuChuong":"@c0949","trangThai":"đang hoạt động"}],"capNhatToi":"@c0936","tabs":{"tienTrinh":[{"chuong":"@c0936","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập vào giao dịch","text":"Thiên Cơ Các tiếp Hàn Lập ở tầng ba, nhận danh sách tài liệu và tiết lộ tin về khối nhỏ Lôi Linh thạch.","anchor":"Tiền bối có thể đến Thiên Cơ các của chúng ta, thật là vinh hạnh"},{"chuong":"@c0949","loai":"nhắc tới","importance":"normal","giaiDoan":"Tiếp đãi Hàn Lập","trangThaiMoc":"đang hoạt động","text":"Hàn Lập tới Thiên Cơ các sau đấu giá hội và gặp lại Vương trưởng lão tại đây.","anchor":"Cùng lúc mấy người này tìm không thấy Hàn Lập mà có chút nghi hoặc thì Hàn Lập cũng tại Thiên Cơ các gặp lại vị kia Vương trưởng lão"}]},"nguon":["@c0936","@c0949"]},{"id":"cac-phuong-thi-dai-tan-lien-hop","name":"Các phường thị Đại Tấn liên hợp","cn":"","type":"lien-minh-thuong-mai","typeLabel":"Liên minh thương mại tạm thời","diaBan":"Đại Tấn","nhanVatChinh":[],"blurb":"Sự liên hợp của các phường thị Đại Tấn để tổ chức đại đấu giá hội quy mô lớn. Hội đấu giá này khó biết trước vật phẩm cụ thể nhưng thường có nhiều kỳ trân tài liệu quý hiếm.","detail":"Theo lời lão nho áo trắng, đại đấu giá hội sắp diễn ra là hoạt động do các phường thị Đại Tấn liên hợp tổ chức. Vì quy mô lớn và do nhiều phường thị cùng tham gia, vật phẩm đưa ra đấu giá khó dự đoán trước, nhưng theo kinh nghiệm thường có hơn trăm loại kỳ trân tài liệu xuất hiện.","tonChi":"Tổ chức đại đấu giá hội quy mô lớn giữa các phường thị tu tiên Đại Tấn.","quyMo":"Liên hợp nhiều phường thị Đại Tấn.","trangThai":"đang chuẩn bị đại đấu giá hội","capNhatToi":"@c0936","tabs":{"tienTrinh":[{"chuong":"@c0936","loai":"liên minh","importance":"normal","giaiDoan":"Chuẩn bị đại đấu giá hội","text":"Các phường thị Đại Tấn liên hợp tổ chức một phiên đại đấu giá hội, dự kiến có nhiều kỳ trân tài liệu quý hiếm.","anchor":"Vì phiên đấu giá lớn như vậy nhưng khi các phường thị Đại Tấn liên hợp lại"}]},"nguon":["@c0936"]},{"id":"ma-dao-ta-tong","name":"Ma đạo tà tông","cn":"","aliases":[],"type":"lien-minh","typeLabel":"Thế lực ma đạo","diaBan":"Tấn Kinh","nhanVatChinh":[],"blurb":"Nhóm thế lực ma đạo chủ trì giao dịch hội dưới lòng đất trong hệ thống đấu giá hội Tấn Kinh. Hội này không công khai với tu sĩ ngoài và có nhiều vật phẩm bị cấm cùng tài liệu quý hiếm.","detail":"Lão Phú nói đấu giá hội Tấn Kinh mười năm một lần chia làm Minh và Ám; tuyến Ám là hội giao dịch dưới lòng đất do ma đạo tà tông chủ trì. Nơi này thường dùng hình thức lấy vật đổi vật và có khả năng xuất hiện tài liệu mà Hàn Lập cần.","quanHe":[{"ten":"Chính đạo","quanHe":"đối ứng trong hệ thống giao dịch Minh–Ám tại Tấn Kinh"}],"trangThai":"chủ trì giao dịch hội dưới lòng đất","tabs":{"tienTrinh":[{"chuong":"@c0938","loai":"nhắc tới","importance":"normal","giaiDoan":"Chủ trì tuyến Ám","text":"Ma đạo tà tông được lão Phú nêu là bên chủ trì hội giao dịch dưới lòng đất tại Tấn Kinh.","anchor":"Ám (tối) thì là do ma đạo tà tông chủ chủ trì hội giao dịch dưới lòng đất"}]},"capNhatToi":"@c0938","nguon":["@c0938"]},{"id":"tu-dai-phat-tong-va-tam-dai-dao-mon","name":"Tứ đại phật tông và tam đại đạo môn","cn":"","aliases":[],"type":"lien-minh","typeLabel":"Liên minh Phật Đạo hậu thuẫn phường thị","diaBan":"Tấn Tây phường thị","nhanVatChinh":["Ô Ích","Tăng nhân xấu xí"],"blurb":"Tứ đại phật tông và tam đại đạo môn là các thế lực đứng sau Tấn Tây phường thị. Quy củ của họ nghiêm cấm tu sĩ động thủ trong phường thị và kẻ vi phạm có thể bị truy sát.","detail":"Hàn Lập viện dẫn uy danh các thế lực Phật Đạo đứng sau phường thị để ngăn nhóm Âm La Tông và Thiên Lan thánh nữ trực tiếp đấu pháp. Sự xuất hiện của Ô Ích và tăng nhân xấu xí cho thấy quy củ này có người đại diện thực thi tại chỗ.","tonChi":"Duy trì quy củ nghiêm cấm đấu pháp trong phường thị.","trangThai":"Đang duy trì ảnh hưởng tại Tấn Tây phường thị","tabs":{"tienTrinh":[{"chuong":"@c0941","loai":"nhắc tới","importance":"normal","giaiDoan":"Hậu thuẫn quy củ phường thị","text":"Hàn Lập nêu Tứ đại phật tông và tam đại đạo môn là thế lực sau lưng Tấn Tây phường thị, dùng quy củ cấm đấu pháp để kiềm chế đối phương.","anchor":"nếu vi phạm sẽ bị mấy thế lực sau lưng của phường thị là Tứ đại phật tông và tam đại đạo môn đuổi giết."}]},"capNhatToi":"@c0941","nguon":["@c0941"]},{"id":"tan-tu","name":"Tán tu","cn":"","type":"nhom-than-phan","typeLabel":"Nhóm thân phận","diaBan":"Không cố định","nhanVatChinh":["Tiểu lão đầu"],"blurb":"Tán tu là nhóm tu sĩ không thuộc tông môn cố định. Tiểu lão đầu tự nhận cũng là tán tu khi đối đáp với Hàn Lập ở Tấn Kinh.","detail":"Trong chương này, tiểu lão đầu dùng thân phận tán tu để tỏ ra không sợ bị Hàn Lập uy hiếp. Thân phận này đồng thời cho thấy lão hành động độc lập, dựa vào linh thú, đệ tử và thủ đoạn riêng để tống tiền.","thanhVien":[{"ten":"Tiểu lão đầu","chucVu":"Tán tu","tuChuong":"@c0943","trangThai":"tu vong"}],"tabs":{"tienTrinh":[{"chuong":"@c0943","loai":"nhắc tới","importance":"bridge","giaiDoan":"Tự nhận thân phận","text":"Tiểu lão đầu tự nhận là tán tu khi đối đáp với Hàn Lập.","anchor":"Ta cũng là tán tu, cũng không sợ đạo hữu uy hiếp như vậy"}]},"trangThai":"Tồn tại như nhóm thân phận rời rạc","capNhatToi":"@c0943","nguon":["@c0943"]},{"id":"thien-lan-thao-nguyen","name":"Thiên Lan Thảo Nguyên","cn":"","type":"the-luc","typeLabel":"Thế lực địa vực","diaBan":"Thiên Lan Thảo Nguyên","nhanVatChinh":["Lâm Ngân Bình"],"blurb":"Phía Thiên Lan có cừu oán không nhẹ với Hàn Lập. Cát Thiên Hào nhắc đến mối thù này khi thương lượng với Lâm Ngân Bình.","detail":"Thiên Lan Thảo Nguyên được nhắc là phía có ân oán sâu với Hàn Lập, khiến Lâm Ngân Bình lưu lại Đại Tấn nhiều năm. Trong chương này, yếu tố đó trở thành nền cho việc Thiên Lan hợp tác với Âm La Tông truy sát Hàn Lập.","quanHe":"Có cừu oán với Hàn Lập; hợp tác tạm thời với Âm La Tông thông qua Lâm Ngân Bình.","trangThai":"đang hoạt động","capNhatToi":"@c0944","tabs":{"tienTrinh":[{"chuong":"@c0944","loai":"nhắc tới","importance":"normal","giaiDoan":"Cừu oán với Hàn Lập","text":"Cát Thiên Hào nhắc Thiên Lan Thảo Nguyên có cừu oán không nhẹ với Hàn Lập.","anchor":"người này hình như cùng Thiên Lan Thảo Nguyên các ngươi có cừu oán cũng không nhẹ","trangThaiMoc":"đối địch Hàn Lập"}]},"nguon":["@c0944"]},{"id":"bac-da-tieu-cuc-cung","name":"Bắc Dạ Tiểu Cực Cung","cn":"","aliases":["Tiểu Cực Cung"],"type":"tong-mon","typeLabel":"Cung môn","diaBan":"Tây Bắc Đại Tấn","nhanVatChinh":["Bạch Dao Di","Liễu phu nhân"],"blurb":"Thế lực ở Tây Bắc Đại Tấn được Đại Diễn Thần Quân nhắc đến vì sở hữu Hàn tuỷ. Nghe nói nơi này có một bình nhỏ Hàn tuỷ làm trấn sơn chi bảo nhiều đời.","detail":"Khi nhận ra Hàn tuỷ, Đại Diễn Thần Quân nói vật này dường như chỉ có tại Bắc Dạ Tiểu Cực Cung ở Tây Bắc Đại Tấn. Ông còn cho biết cung này chỉ có một bình nhỏ được truyền làm trấn sơn chi bảo.","tranPhai":"Một bình nhỏ Hàn tuỷ làm trấn sơn chi bảo theo lời Đại Diễn Thần Quân.","trangThai":"đang được nhắc tới","capNhatToi":"@c0944","tabs":{"tienTrinh":[{"chuong":"@c0944","loai":"nhắc tới","importance":"normal","giaiDoan":"Sở hữu Hàn tuỷ","text":"Bắc Dạ Tiểu Cực Cung được nhắc là nơi hiếm hoi có Hàn tuỷ tại Tây Bắc Đại Tấn.","anchor":"chỉ có tại Bắc Dạ Tiểu Cực Cung ở Tây Bắc Đại Tấn","trangThaiMoc":"được nhắc tới"},{"chuong":"@c0998","loai":"nhắc tới","importance":"normal","giaiDoan":"Kiền lão ma nhận diện","text":"Kiền lão ma đoán Bạch Dao Di thuộc Bắc Dạ Tiểu Cực cung và nhắc Liễu phu nhân của cung này là người quen cũ.","anchor":"chẳng lẽ là tu sĩ Bắc dạ Tiểu Cực cung"}]},"nguon":["@c0944","@c0998"],"thanhVien":[{"ten":"Bạch Dao Di","chucVu":"tu sĩ","tuChuong":"@c0998","trangThai":"đang hoạt động"},{"ten":"Liễu phu nhân","chucVu":"không rõ","tuChuong":"@c0998","trangThai":"được nhắc tới"}]},{"id":"nghiep-gia","name":"Nghiệp gia","cn":"","aliases":[],"type":"gia-toc","typeLabel":"Gia tộc hoàng tộc Đại Tấn","diaBan":"Tấn kinh","nhanVatChinh":["Vân Dật","Nhị trưởng lão Nghiệp gia","Phụ nhân xinh đẹp từng xuất hiện tại Hoàng Thanh quán","Nghiệp trưởng lão","Hàn trưởng lão"],"blurb":"Thế lực gia tộc gắn với hoàng tộc Đại Tấn, có phủ đệ ở góc bắc Tấn kinh. Nghiệp gia đang lung lạc Hàn trưởng lão, thu thập ma khí cho hắn và chuẩn bị bí mật mua vật liệu cho kế hoạch đoạt bảo mấy năm sau.","detail":"Nghiệp gia có các trưởng lão trung tâm cùng bàn bạc trong phủ đệ tại Tấn kinh. Họ dùng Hàn trưởng lão như ngoại viện vì người này biết nhiều bí văn thượng cổ và hữu dụng cho hành trình mấy năm sau, nhưng cũng đề phòng vì hắn tà môn, che giấu thực lực và đòi thu thập ma khí. Nhị trưởng lão yêu cầu việc mua vật liệu ở đại hội đấu giá phải bí mật để phục vụ luyện chế pháp khí đoạt bảo.","lanhDaoHienThoi":"Nhị trưởng lão Nghiệp gia","trangThai":"đang chuẩn bị kế hoạch đoạt bảo","thanhVien":[{"ten":"Vân Dật","chucVu":"Trưởng lão","tuChuong":"@c0946","trangThai":"hoạt động"},{"ten":"Nhị trưởng lão Nghiệp gia","chucVu":"Nhị trưởng lão","tuChuong":"@c0946","trangThai":"hoạt động"},{"ten":"Phụ nhân xinh đẹp từng xuất hiện tại Hoàng Thanh quán","chucVu":"Thành viên bàn việc","tuChuong":"@c0946","trangThai":"hoạt động"},{"ten":"Hàn trưởng lão","chucVu":"Ngoại viện trưởng lão","tuChuong":"@c0946","trangThai":"được lung lạc"}],"tabs":{"tienTrinh":[{"chuong":"@c0946","loai":"nhắc tới","importance":"normal","giaiDoan":"Lung lạc Hàn trưởng lão","trangThaiMoc":"đang chuẩn bị đại sự","text":"Nghiệp gia cam kết điều kiện với Hàn trưởng lão, đồng thời họp kín để dùng hắn cho đại sự nhưng vẫn đề phòng.","anchor":"Nghiệp gia chúng ta nếu đáp ứng Hàn trưởng lão, sẽ tuyệt đối không nuốt lời"}]},"capNhatToi":"@c0946","nguon":["@c0946"]},{"id":"thai-nhat-mon","name":"Thái Nhất môn","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"","nhanVatChinh":["Huyền Thanh","Huyền Thanh Tử","Hướng Chi Lễ"],"blurb":"Một trong hai thế lực lớn gây sức ép với Nghiệp gia vì Bình Sơn ấn. Huyền Thanh của Thái Nhất môn được nhắc đã cùng Thất Diệu đột nhập vào cung.","detail":"Thái Nhất môn cùng Thiên Ma tông chú ý tới Bình Sơn ấn sắp luyện thành, khiến Nghiệp gia phải dùng bảo vật này làm mồi ngoài sáng. Huyền Thanh của phe này còn khiến Nghiệp gia cảnh giác nguy cơ trưởng lão bị ám toán dò thần thức.","thanhVien":[{"ten":"Huyền Thanh","chucVu":"lão quái","tuChuong":"@c0947","trangThai":"được nhắc tới"},{"ten":"Huyền Thanh Tử","chucVu":"tu sĩ Nguyên Anh hậu kỳ","tuChuong":"@c1033","trangThai":"đang thi hành bí lệnh"},{"ten":"Hướng Chi Lễ","chucVu":"","tuChuong":"@c1065","trangThai":"dang-hoat-dong"}],"quanHe":"Cùng Thiên Ma tông gây sức ép với Nghiệp gia quanh Bình Sơn ấn.","trangThai":"can dự phong ấn Côn Ngô Sơn","tabs":{"tienTrinh":[{"chuong":"@c0947","loai":"nhắc tới","importance":"normal","giaiDoan":"Dòm ngó Bình Sơn ấn","text":"Thái Nhất môn cùng Thiên Ma tông được nói là đến vì Bình Sơn ấn và khiến Nghiệp gia phải lấy bảo vật làm mồi ngoài sáng.","anchor":"Thái Nhất môn cùng Thiên Ma tông tại sao đột nhiên lại phái Huyền Thanh","trangThaiMoc":"gây sức ép"},{"chuong":"@c1033","loai":"nhắc tới","importance":"normal","giaiDoan":"Hạ bí lệnh","text":"Thái Nhất Môn có một tồn tại đặc thù hạ bí lệnh cho Huyền Thanh Tử ngăn tu sĩ vào phong ấn và chờ liên thủ tiến vào.","anchor":"một mệnh lệnh bí mật từ trong tông môn truyền ra"},{"chuong":"@c1065","loai":"xuất hiện","importance":"normal","giaiDoan":"Xuất hiện lần đầu","text":"Được nhắc tới khi Hướng Chi Lễ nói môn đồ Thái Nhất Môn mang Phá Giới Phù tới.","anchor":"mấy tên môn đồ Thái Nhất Môn của ta mang Phá Giới Phù tới đây"}]},"capNhatToi":"@c0947","nguon":["@c0947","@c1033","@c1065"],"aliases":["Thái Nhất Tông"]},{"id":"thien-ma-tong","name":"Thiên Ma tông","cn":"天魔宗","type":"tong-mon","typeLabel":"Tông môn","diaBan":"","nhanVatChinh":["Thất Diệu chân nhân","Bảy tám tu sĩ Thiên Ma Tông Nguyên Anh kỳ"],"blurb":"Thế lực cùng Thái Nhất môn dòm ngó Bình Sơn ấn. Thất Diệu chân nhân thuộc Thiên Ma tông có Diệu Âm bảo kính được Âm La tông mượn để đối phó Hàn Lập.","detail":"Thiên Ma tông gây sức ép với Nghiệp gia quanh Bình Sơn ấn. Thất Diệu chân nhân của tông này được nhấn mạnh am hiểu bí thuật, đồng thời Diệu Âm bảo kính của ông trở thành công cụ Âm La tông trông cậy để phá ngụy trang của Hàn Lập.","thanhVien":[{"ten":"Thất Diệu Chân Nhân","chucVu":"chấp pháp trưởng lão","tuChuong":"@c0947","trangThai":"đang hoạt động"},{"ten":"Bảy tám tu sĩ Thiên Ma Tông Nguyên Anh kỳ","chucVu":"ma tu Nguyên Anh","tuChuong":"@c1034","trangThai":"đang hoạt động"}],"quanHe":"Có giao tình với Đột Ngột nhân và cùng Thái Nhất môn gây sức ép với Nghiệp gia.","trangThai":"dòm ngó Bình Sơn ấn","tabs":{"tienTrinh":[{"chuong":"@c0947","loai":"nhắc tới","importance":"normal","giaiDoan":"Liên quan Bình Sơn ấn và bảo kính","text":"Thiên Ma tông vừa dòm ngó Bình Sơn ấn vừa có Thất Diệu chân nhân cho mượn Diệu Âm bảo kính để Âm La tông đối phó Hàn Lập.","anchor":"Đột Ngột nhân cùng Thiên Ma tông cũng có chút giao tình","trangThaiMoc":"tham dự thế cục hội đấu giá"},{"chuong":"@c1033","loai":"nhắc tới","importance":"normal","giaiDoan":"Liên thủ phong ấn","text":"Thất Diệu Chân Nhân của Thiên Ma Tông được bí lệnh yêu cầu liên thủ với Huyền Thanh Tử tiến vào phong ấn.","anchor":"Thất Diệu Chân Nhân của Thiên Ma Tông liên thủ cùng tiến vào bên trong"},{"chuong":"@c1034","loai":"liên minh","importance":"normal","giaiDoan":"Phong tỏa vết nứt","text":"Thiên Ma Tông cùng Thái Nhất Môn công khai ngăn tu sĩ khác tiến vào vết nứt và điều người dựng cấm chế đại trận.","anchor":"chúng ta Thiên Ma Tông cùng Thái Nhất Tông chính là không cho các vị đạo hữu đi vào","trangThaiMoc":"liên thủ phong tỏa"}]},"capNhatToi":"@c0947","nguon":["@c0947","@c1033","@c1034","@c1090"]},{"id":"sau-linh-trai","name":"Sấu Linh trai","cn":"","type":"thuong-hoi","typeLabel":"Hãng buôn","diaBan":"Gần Thiên Cơ các trong phường thị","nhanVatChinh":["Chủ nhân Sấu Linh trai","Lão giả họ Phú","Hàn Lập"],"blurb":"Sấu Linh trai là hãng buôn gần Thiên Cơ các, do hảo hữu của lão giả họ Phú làm chủ. Trong lầu có truyền tống trận tạm thời giúp Hàn Lập rời phường thị.","detail":"Cơ sở này có truyền tống trận tạm thời được phép bố trí vì nguyên nhân đặc thù. Chủ nhân Sấu Linh trai là trận pháp đại sư danh tiếng, khiến Hàn Lập sinh ý muốn kết giao.","thanhVien":[{"ten":"Chủ nhân Sấu Linh trai","chucVu":"chủ nhân","tuChuong":"@c0949","trangThai":"đang hoạt động"}],"trangThai":"đang hoạt động","capNhatToi":"@c0949","tabs":{"tienTrinh":[{"chuong":"@c0949","loai":"nhắc tới","importance":"normal","giaiDoan":"Lộ truyền tống trận","trangThaiMoc":"đang hoạt động","text":"Lão giả họ Phú dẫn Hàn Lập tới Sấu Linh trai, nơi có truyền tống trận tạm thời trong lầu các.","anchor":"Nhà này là của hãng buôn Sấu Linh Trai"}]},"nguon":["@c0949"]},{"id":"cuu-u-tong","name":"Cửu U Tông","cn":"","type":"tong-mon","typeLabel":"Tông môn ma đạo","diaBan":"Đại Tấn","nhanVatChinh":["Lão giả họ Phú","Hàn Lập","Hắc y mỹ phụ"],"blurb":"Cửu U Tông là một đại tông ma đạo của Đại Tấn, nơi lão giả họ Phú giữ chức chấp pháp trưởng lão.","detail":"Cửu U Tông được lộ diện qua thân phận của lão giả họ Phú. Tông môn này có xích mích với Âm La Tông, nên lão giả họ Phú không ngại giúp Hàn Lập tránh nhóm Âm La Tông và khiến Cát Thiên Hào bất lợi. Hàn Lập cũng nhận ra đây là một ma đạo đại tông, không muốn vì việc trước mắt mà tiếp tục kết thêm thù với một thế lực lớn khác.","nguon":["@c0950","@c0969","@c0973"],"tabs":{"tienTrinh":[{"chuong":"@c0969","loai":"nhắc tới","importance":"normal","giaiDoan":"Ước hẹn Nam Cương","text":"Cửu U tông được nhắc qua lão giả họ Phú và cuộc hẹn với Hàn Lập tại Nam Cương.","anchor":"Mà ước hẹn giữa hắn cùng vị Cửu U tông họ Phú kia gặp mặt tại Nam Cương"},{"chuong":"@c0973","loai":"nhắc tới","importance":"normal","giaiDoan":"Ân oán nội bộ","text":"Cửu U tông được xác nhận là một trong thập đại ma tông, đồng thời có ân oán nội bộ khiến lão giả họ Phú không dám nhờ đa số đồng giai trong tông.","anchor":"Quý tông nguyên là một trong thập đại ma tông"}]},"thanhVien":[{"ten":"Lão giả họ Phú","chucVu":"tu sĩ trong tông","tuChuong":"@c0969","trangThai":"có ân oán với nhiều đồng giai"},{"ten":"Hắc y mỹ phụ","chucVu":"Thường sư muội","tuChuong":"@c0973","trangThai":"được lão giả họ Phú tin cậy"}]},{"id":"thap-dai-ma-dao-tong","name":"Thập đại Ma đạo tông","cn":"","type":"nhom-the-luc","typeLabel":"Nhóm đại tông ma đạo","diaBan":"Đại Tấn","nhanVatChinh":[],"blurb":"Thập đại Ma đạo tông là nhóm các đại tông ma đạo của Đại Tấn, được nhắc khi nói về địa vị của Cửu U Tông.","detail":"Cụm Thập đại Ma đạo tông xuất hiện như thước đo địa vị của Cửu U Tông trong ma đạo Đại Tấn. Khi biết lão giả họ Phú cũng là trưởng lão của một đại tông thuộc nhóm này, Hàn Lập thêm cảnh giác và không muốn vô cớ đắc tội thêm một thế lực lớn sau Âm La Tông.","nguon":["@c0950"]},{"id":"giao-dich-hoi-ngam","name":"Giao dịch hội ngầm","cn":"","type":"to-chuc-su-kien","typeLabel":"Hội giao dịch ngầm","diaBan":"Khu núi hoang cách Tấn kinh ba nghìn dặm","nhanVatChinh":["Lão giả họ Phú","Hàn Lập","Dịch Tẩy Thiên"],"blurb":"Giao dịch hội ngầm là hội giao dịch cao giai có lối vào giấu trong vách đá, dùng pháp khí thân phận để quản lý người tham dự.","detail":"Giao dịch hội ngầm đặt lối vào tại một khe núi hoang, được cấm chế che giấu và mở bằng vòng tròn pháp khí. Hai tu sĩ áo tía tu vi Kết Đan hậu kỳ canh giữ cửa vào, cấp thân phận pháp khí cho người đủ tư cách sau khi thu linh thạch. Theo lời giải thích tại cửa, hội năm trước có khoảng hơn hai trăm người tham gia, cho thấy đây là nơi tụ tập đông đảo tu sĩ cao giai và có quy củ riêng.","nguon":["@c0950"]},{"id":"phat-mon-tinh-tong","name":"Phật môn Tịnh tông","cn":"","type":"tong-mon","typeLabel":"Tông môn Phật môn","diaBan":"Đại Tấn","nhanVatChinh":["Bích Nguyệt thiền sư"],"blurb":"Phật môn Tịnh tông là nơi Bích Nguyệt thiền sư xuất thân, được nhắc như một thế lực Phật môn có nhân vật Nguyên Anh hậu kỳ nổi bật.","detail":"Phật môn Tịnh tông được nhắc qua Bích Nguyệt thiền sư. Vị thiền sư này chỉ mất bốn trăm năm tiến giai Nguyên Anh hậu kỳ và được giới tu tiên công nhận là kỳ tài vạn năm có một, đồng thời được xếp cùng Dịch Tẩy Thiên trong số những người có khả năng tiến giai Hóa Thần nhất của Đại Tấn.","nguon":["@c0950"]},{"id":"giao-dich-hoi-an-danh","name":"Giao dịch hội ẩn danh","cn":"","aliases":[],"type":"su-kien","typeLabel":"Tổ chức/sự kiện giao dịch","diaBan":"Đại sảnh giao dịch hội","nhanVatChinh":["Hàn Lập","Người chủ trì giao dịch hội trong ánh sáng trắng","Tu sĩ thủ vệ che mặt tại giao dịch hội"],"blurb":"Giao dịch hội dùng lá bùa đặc chế và trận pháp để che giấu thân phận người tham dự. Hội có phần đấu giá vật liệu quý hiếm, phần đổi vật, và năm nay có trọng bảo cuối phiên do khách hàng lớn ủy thác.","detail":"Người dự hội được truyền tống vào đại sảnh sau khi dán lá bùa đặc chế. Bên trong, quầng sáng phối hợp trận pháp ngăn thần thức dò xét, giúp các tu sĩ ẩn danh giao dịch.","tonChi":"Che giấu thân phận người tham dự khi giao dịch","trangThai":"đang diễn ra","tabs":{"tienTrinh":[{"chuong":"@c0951","loai":"nhắc tới","importance":"normal","giaiDoan":"Mở phiên đấu giá","text":"Giao dịch hội bắt đầu với quy tắc đấu giá vật liệu bằng linh thạch rồi lấy vật đổi vật, đồng thời công bố có trọng bảo cuối phiên.","anchor":"Giao dịch hội lần này vẫn giống như trước đây"}]},"capNhatToi":"@c0951","nguon":["@c0951"]},{"id":"dia-hoi-giao-dich","name":"Địa hội giao dịch","cn":"","type":"to-chuc-giao-dich","typeLabel":"Tổ chức giao dịch tạm thời","diaBan":"địa điểm giao dịch dưới sự chủ trì của Bạch Hà trung nhân","nhanVatChinh":["Bạch Hà trung nhân"],"blurb":"Địa hội giao dịch là nơi diễn ra phiên đấu giá và trao đổi tự do giữa nhiều tu sĩ. Nơi tổ chức chỉ cung cấp địa điểm, không đảm bảo thật giả hay thành bại của giao dịch.","detail":"Sau khi đấu giá kết thúc, Bạch Hà trung nhân đại diện địa hội tuyên bố người tham dự có thể tự trao đổi bảo vật. Địa hội thu mỗi bên một vạn linh thạch cho mỗi giao dịch thành công nhưng không chịu trách nhiệm về kết quả hay thật giả của vật phẩm.","quyMo":"tập hợp nhiều tu sĩ tham gia đấu giá và trao đổi bảo vật","lanhDaoHienThoi":"Bạch Hà trung nhân","trangThai":"đang mở phiên trao đổi tự do","capNhatToi":"@c0952","thanhVien":[{"ten":"Bạch Hà trung nhân","chucVu":"người chủ trì","tuChuong":"@c0952","trangThai":"đang chủ trì"},{"ten":"Tu sĩ áo bào tro che mặt","chucVu":"người đưa hộp ngọc","tuChuong":"@c0952","trangThai":"hỗ trợ giao dịch"}],"tabs":{"tienTrinh":[{"chuong":"@c0952","loai":"nhắc tới","importance":"normal","giaiDoan":"Mở giao dịch tự do","text":"Địa hội giao dịch mở giai đoạn trao đổi tự do sau đấu giá, cung cấp địa điểm và thu thủ tục phí nhưng không chịu trách nhiệm kết quả giao dịch.","anchor":"chúng ta chỉ có cung cấp nơi giao dịch","trangThaiMoc":"mở trao đổi tự do"}]},"dinhDanh":"goc","nguon":["@c0952"]},{"id":"huyet-the-mon","name":"Huyết Thê Môn","cn":"","type":"tong-mon","typeLabel":"Ma đạo tông môn","diaBan":"không rõ","nhanVatChinh":["Khôn Vô Cực"],"blurb":"Huyết Thê Môn là ma đạo tông môn được nhắc tại trao đổi hội. Khôn Vô Cực là đại trưởng lão của môn này và có tu vi Nguyên Anh hậu kỳ.","detail":"Khi thân phận Khôn Vô Cực bị nhận ra, hội trường xác định ông là đại trưởng lão Huyết Thê Môn. Danh vị này khiến các tu sĩ khác kiêng dè trong cuộc tranh đoạt Ma Tuỷ Toản.","capBac":"thuộc hàng chính ma thập đại tông môn","caoThuManhNhat":"Khôn Vô Cực","thanhVien":[{"ten":"Khôn Vô Cực","chucVu":"đại trưởng lão","tuChuong":"@c0953","trangThai":"đang thuộc"}],"tabs":{"tienTrinh":[{"chuong":"@c0953","loai":"nhắc tới","importance":"normal","giaiDoan":"Lộ thân phận trưởng lão","text":"Huyết Thê Môn được nêu ra khi Khôn Vô Cực bị nhận là đại trưởng lão của môn này tại trao đổi hội.","trangThaiMoc":"được nhắc qua thân phận Khôn Vô Cực","anchor":"Nguyên lai là Huyết Thê Môn đại trưởng lão, tiểu nữ thật là thất kính"}]},"capNhatToi":"@c0953","nguon":["@c0953"]},{"id":"linh-phong-mon","name":"Linh Phong môn","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Khu vực liên quan Tam Nguyên phường thị","nhanVatChinh":[],"blurb":"Linh Phong môn là thế lực gửi tối hậu thư ép Tam Nguyên phường thị sát nhập hoặc đóng cửa trong ba tháng. Động thái này đe dọa trực tiếp nguồn thu của Thiên Phù môn.","detail":"Linh Phong môn yêu cầu Tam Nguyên phường thị phải sát nhập với họ hoặc đóng cửa trong ba tháng. Nếu sát nhập, Thiên Phù môn chỉ được cấp một ngàn linh thạch mỗi năm, chưa tới một phần ba thu nhập trước đó từ phường thị.","nguon":["@c0957"],"trangThai":"gây áp lực lên Tam Nguyên phường thị","quanHe":"Đối đầu lợi ích với Thiên Phù môn trong biến cố phường thị.","tabs":{"tienTrinh":[{"chuong":"@c0957","loai":"mở rộng/mất địa bàn","importance":"normal","giaiDoan":"Ép sát nhập phường thị","text":"Linh Phong môn gửi tối hậu thư buộc Tam Nguyên phường thị sát nhập hoặc đóng cửa, khiến Thiên Phù môn bị đe dọa nguồn thu lớn.","anchor":"Linh phong môn đã hạ tối hậu thư cho môn chủ"}]},"capNhatToi":"@c0957"},{"id":"sat-duong-tong","name":"Sát Dương tông","cn":"","type":"tong-mon","typeLabel":"Trung đẳng tông môn","diaBan":"Không rõ","nhanVatChinh":[],"blurb":"Sát Dương tông là trung đẳng tông môn bị nghi đứng sau việc Linh Phong môn ép Tam Nguyên phường thị. Với Thiên Phù môn, đây là thế lực khó thể trêu chọc.","detail":"Theo lời đệ tử gác sơn môn Thiên Phù môn, việc ép phường thị không chỉ do Linh Phong môn mà tựa hồ còn có bàn tay Sát Dương tông. Danh tiếng trung đẳng tông môn của họ khiến Thiên Phù môn rơi vào thế yếu.","nguon":["@c0957"],"capBac":"Trung đẳng tông môn","trangThai":"bị nghi đứng sau áp lực phường thị","quanHe":"Gây sức ép gián tiếp lên Thiên Phù môn qua biến cố Tam Nguyên phường thị.","tabs":{"tienTrinh":[{"chuong":"@c0957","loai":"nhắc tới","importance":"normal","giaiDoan":"Bóng dáng sau biến cố","text":"Sát Dương tông bị nghi có bàn tay trong việc Linh Phong môn ép Tam Nguyên phường thị, làm Thiên Phù môn càng khó đối phó.","anchor":"tựa hồ còn có bàn tay của Sát Dương tông"}]},"capNhatToi":"@c0957"},{"id":"kim-ha-son","name":"Kim Hà sơn","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Khu vực liên quan Tam Nguyên phường thị","nhanVatChinh":[],"blurb":"Kim Hà sơn là một trong ba nhà cùng góp vốn Tam Nguyên phường thị với Thiên Phù môn và Minh Dương cốc. Chưởng môn Kim Hà sơn được mời lên núi Thiên Phù môn để bàn đối sách.","detail":"Khi Tam Nguyên phường thị bị Linh Phong môn ép sát nhập hoặc đóng cửa, Thiên Phù môn cho rằng Kim Hà sơn và Minh Dương cốc cũng khó đồng ý vì hai nhà cùng góp vốn vào phường thị và tình cảnh cũng không dư dả.","nguon":["@c0957"],"quanHe":"Cùng góp vốn Tam Nguyên phường thị với Thiên Phù môn và Minh Dương cốc.","tabs":{"tienTrinh":[{"chuong":"@c0957","loai":"liên minh","importance":"normal","giaiDoan":"Cùng bàn đối sách","text":"Kim Hà sơn được nhắc là một trong ba nhà liên quan Tam Nguyên phường thị và có chưởng môn được mời lên Thiên Phù môn bàn cách đối phó.","anchor":"Kim hà sơn cùng Minh dương cốc có thể đồng ý sao"}]},"capNhatToi":"@c0957"},{"id":"minh-duong-coc","name":"Minh Dương cốc","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Khu vực liên quan Tam Nguyên phường thị","nhanVatChinh":[],"blurb":"Minh Dương cốc là một trong ba nhà góp vốn Tam Nguyên phường thị. Thế lực này được nhắc cùng Kim Hà sơn trong cục diện chống sức ép từ Linh Phong môn.","detail":"Minh Dương cốc cùng Thiên Phù môn và Kim Hà sơn góp vốn vào Tam Nguyên phường thị. Vì tình cảnh hai nhà kia cũng không tốt hơn Thiên Phù môn bao nhiêu, họ khó dễ dàng bỏ nguồn thu từ phường thị.","nguon":["@c0957"],"quanHe":"Cùng góp vốn Tam Nguyên phường thị với Thiên Phù môn và Kim Hà sơn.","tabs":{"tienTrinh":[{"chuong":"@c0957","loai":"liên minh","importance":"normal","giaiDoan":"Cùng giữ phường thị","text":"Minh Dương cốc được nhắc là một bên cùng góp vốn Tam Nguyên phường thị và có lợi ích bị ảnh hưởng bởi tối hậu thư của Linh Phong môn.","anchor":"Ha nhà kia tình huống so với Thiên phù môn chúng ta cũng không tốt hơn bao nhiêu"}]},"capNhatToi":"@c0957"},{"id":"tam-nguyen-phuong-thi","name":"Tam Nguyên phường thị","cn":"","type":"co-so-giao-dich","typeLabel":"Phường thị","diaBan":"Không rõ, thuộc khu vực ảnh hưởng của Thiên Phù môn và hai nhà đồng minh","nhanVatChinh":["Nhạc Chân"],"blurb":"Tam Nguyên phường thị là nguồn thu gần một nửa của Thiên Phù môn và do ba nhà cùng góp vốn. Phường thị đang bị Linh Phong môn ép sát nhập hoặc đóng cửa trong ba tháng.","detail":"Tam Nguyên phường thị chiếm gần một nửa nguồn thu của Thiên Phù môn. Linh Phong môn đã ra tối hậu thư buộc phường thị sát nhập hoặc đóng cửa, còn sau sát nhập Thiên Phù môn chỉ được cấp một ngàn linh thạch mỗi năm.","nguon":["@c0957"],"trangThai":"bị ép sát nhập hoặc đóng cửa","quanHe":"Do Thiên Phù môn, Kim Hà sơn và Minh Dương cốc cùng góp vốn; bị Linh Phong môn gây áp lực.","tabs":{"tienTrinh":[{"chuong":"@c0957","loai":"suy","importance":"normal","giaiDoan":"Nguồn thu bị ép","text":"Tam Nguyên phường thị bị Linh Phong môn ép sát nhập hoặc đóng cửa, đe dọa gần một nửa nguồn thu của Thiên Phù môn.","anchor":"Tam nguyên phường thị cơ hồ chiếm một nửa nguồn thu của bổn môn"}]},"capNhatToi":"@c0957"},{"id":"thap-dai-chinh-mon","name":"Thập đại chính môn","cn":"","type":"nhom-the-luc","typeLabel":"Nhóm thế lực chính đạo","diaBan":"Đại Tấn","nhanVatChinh":[],"blurb":"Thập đại chính môn là hàng ngũ chính đạo hàng đầu ở Đại Tấn. Thiên Phù môn thời hưng thịnh từng suýt được liệt vào hàng này nhờ uy danh tam đại mật phù.","detail":"Trong phần nhắc lại lịch sử Thiên Phù môn, Thập đại chính môn được dùng làm mốc so sánh cho thời kỳ huy hoàng của môn phái, khi Thiên Phù chân nhân vẽ tam đại mật phù uy chấn Đại Tấn.","nguon":["@c0957"],"tabs":{"tienTrinh":[{"chuong":"@c0957","loai":"nhắc tới","importance":"bridge","giaiDoan":"Mốc danh vọng","text":"Thập đại chính môn được nhắc như hàng ngũ mà Thiên Phù môn từng suýt được liệt vào lúc hưng thịnh.","anchor":"người sáng lập ra môn phái này “Thiên Phù chân nhân” cũng đã từng vẽ ra tam đại mật phù"}]},"capNhatToi":"@c0957"},{"id":"thien-phu-mon","name":"Thiên Phù môn","cn":"","aliases":[],"type":"tong-mon","typeLabel":"Tông môn","diaBan":"Đại Tấn","nhanVatChinh":["Hướng Chi Lễ","Vân đạo hữu","Ôn lão giả","Dương sư điệt"],"blurb":"Thiên Phù môn là môn phái nhỏ ở Đại Tấn, nổi bật vì có nhiều điển tịch chế phù. Hướng Chi Lễ ẩn thân tại đây dưới dáng vẻ một đệ tử cấp thấp giữ tàng thư lầu.","detail":"Trong chương này, Thiên Phù môn là nơi Hàn Lập gặp lại lão giả giống Hướng Chi Lễ năm xưa. Môn phái có tàng thư lầu nhiều tầng, nơi lão giả đưa ngọc giản điển tịch chế phù cho Hàn Lập xem và cũng là nơi Hàn Lập bày cấm chế để phòng bị.","thanhVien":[{"ten":"Hướng Chi Lễ","chucVu":"đệ tử cấp thấp giữ tàng thư lầu","tuChuong":"@c0959","trangThai":"ẩn thân"}],"tabs":{"tienTrinh":[{"chuong":"@c0959","loai":"nhắc tới","importance":"normal","giaiDoan":"Lầu điển tịch chế phù","text":"Thiên Phù môn được giới thiệu là môn phái có nhiều điển tịch chế phù và là nơi Hướng Chi Lễ đang ẩn thân.","anchor":"“bổn môn được gọi là Thiên phù môn tất nhiên điển tịch có không ít”"}]},"trangThai":"đang tồn tại","capNhatToi":"@c0959","nguon":["@c0959"]},{"id":"ba-phai-thien-phu-mon-kim-ha-son-minh-duong-coc","name":"Ba phái Thiên Phù Môn/Kim Hà sơn/Minh Dương cốc","cn":"","type":"lien-minh","typeLabel":"Liên minh tiểu tông phái","diaBan":"Bạch Trúc sơn và khu vực liên quan tại Đại Tấn","nhanVatChinh":["Ôn lão giả","Thường đạo hữu","Tạ đạo hữu","Hàn Lập"],"blurb":"Liên minh ba tiểu tông phái gồm Thiên Phù Môn, Kim Hà sơn và Minh Dương cốc. Ba nhà cùng tiến cùng lui, chống đỡ lẫn nhau và muốn mời Hàn Lập làm khách khanh trưởng lão chung.","detail":"Ba phái đều là tiểu tông phái, nhờ liên kết nên có thể giúp nhau tự bảo vệ. Khi xác nhận Hàn Lập là tu sĩ Nguyên Anh không thuộc đại phái Đại Tấn, Ôn lão giả đại diện đưa ra lời mời khách khanh trưởng lão.","nguon":["@c0960"],"trangThai":"đang mời khách khanh Nguyên Anh","thanhVien":[{"ten":"Ôn lão giả","chucVu":"trưởng lão Thiên Phù Môn","tuChuong":"@c0960","trangThai":"đang hoạt động"},{"ten":"Thường đạo hữu","chucVu":"tu sĩ Kim Hà sơn","tuChuong":"@c0960","trangThai":"đang hoạt động"},{"ten":"Tạ đạo hữu","chucVu":"tu sĩ Minh Dương cốc","tuChuong":"@c0960","trangThai":"đang hoạt động"}],"tabs":{"tienTrinh":[{"chuong":"@c0960","loai":"liên minh","importance":"normal","giaiDoan":"Mời khách khanh","text":"Ba phái Thiên Phù Môn, Kim Hà sơn và Minh Dương cốc cùng đề nghị Hàn Lập làm khách khanh trưởng lão chung để có chỗ dựa Nguyên Anh.","anchor":"ba nhà tuy rằng đều là tiểu tông phái"}]},"capNhatToi":"@c0960"},{"id":"nam-hai-mon","name":"Nam Hải môn","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"khu vực ven biển Lâm Giang phủ và Quần Anh đảo","nhanVatChinh":[],"blurb":"Tông môn đứng ra đối phó đàn ác giao gần Lâm Giang phủ. Nam Hải môn mời nhiều cao giai tu sĩ tụ tập ở Quần Anh đảo để chuẩn bị đại hội đồ giao.","detail":"Trước biến cố ác giao bát cấp, Nam Hải môn từng cho vài trưởng lão liên thủ đánh lui đàn giao. Sau khi tình thế leo thang, môn này mời cao giai tu sĩ tới Quần Anh đảo để tổ chức đại hội đồ giao.","nguon":["@c0960","@c0961"],"trangThai":"tổ chức đại hội đồ giao","tabs":{"tienTrinh":[{"chuong":"@c0960","loai":"khai chiến","importance":"major","giaiDoan":"Chuẩn bị đồ giao","text":"Nam Hải môn mời nhiều cao giai tu sĩ tụ tập tại Quần Anh đảo để chuẩn bị đại hội đồ giao đối phó đàn ác giao.","anchor":"Nam Hải môn cũng vì việc này đã mời khá nhiều cao giai tu sĩ"},{"chuong":"@c0961","loai":"khai chiến","importance":"major","giaiDoan":"Mở đại hội đồ giao","text":"Nam Hải môn mở đại hội đồ giao, ban đầu huy động đông đảo tu sĩ nhưng sau đó bị đám ác giao kéo vào thế tiêu hao.","anchor":"đệ nhất tông môn tại Hoa Vân châu “Nam Hải môn” bắt đầu đại hội đồ giao","trangThaiMoc":"tổ chức đồ giao"}]},"capNhatToi":"@c0960","congNang":["Tổ chức đại hội đồ giao huy động nhiều tu sĩ Kết Đan và Nguyên Anh truy quét ác giao @c0961"]},{"id":"dan-ac-giao-hai-vuc-quynh-anh-dao","name":"Đàn ác giao hải vực Quỳnh Anh đảo","cn":"","type":"yeu-thu-quan-the","typeLabel":"Quần thể yêu thú","diaBan":"Hải vực phía tây Quỳnh Anh đảo","nhanVatChinh":["Xích Hỏa Giao","Bát cấp lam giao"],"blurb":"Quần thể ác giao hoạt động quanh hải vực Quỳnh Anh đảo. Trong lần phản vây đội tu sĩ, chúng có ít nhất hai bát cấp yêu thú cùng nhiều thất cấp ác giao phối hợp từ nhiều hướng.","detail":"Đàn ác giao không còn chỉ đánh lén lẻ tẻ mà chủ động tập hợp yêu vân từ bốn phương tám hướng để bao vây đội tu sĩ dò xét. Sự xuất hiện đồng thời của lam sắc yêu vân và hồng sắc yêu vân bát cấp khiến đội tu sĩ nhận ra tình thế nghiêm trọng hơn dự đoán.","quyMo":"Có ít nhất hai bát cấp yêu thú và nhiều thất cấp ác giao trong lần vây đội tu sĩ.","trangThai":"đang hoạt động","nguon":["@c0962"],"tabs":{"tienTrinh":[{"chuong":"@c0962","loai":"khai chiến","importance":"normal","giaiDoan":"Phản vây đội tu sĩ","text":"Đàn ác giao tập hợp yêu vân từ nhiều hướng, chủ động bao vây tổ tu sĩ dò xét thay vì chỉ đánh lén như trước.","anchor":"hiện tại không cần đánh lén nữa mà đã bao vây ý đồ tiêu diệt toàn bộ tổ tu sĩ này","trangThaiMoc":"chủ động phản vây"}]},"capNhatToi":"@c0962"},{"id":"hai-ngoai-tam-tien","name":"Hải ngoại tam tiên","cn":"","type":"nhom-cao-thu","typeLabel":"Nhóm cao thủ","diaBan":"Hải ngoại Đại Tấn","nhanVatChinh":["Khô trúc lão nhân"],"blurb":"Danh xưng dành cho ba cao thủ có uy danh lớn trong giới tu sĩ hải ngoại. Khô trúc lão nhân được xếp vào hàng này nhờ hàn trúc phi kiếm, thiên tang thần thụ và vạn mộc đại trận.","detail":"Hải ngoại tam tiên là cách giới tu sĩ hải ngoại nhìn nhận những cao thủ danh chấn vùng biển ngoài Đại Tấn. Khô trúc lão nhân, chủ Khô trúc đảo, được coi là một trong số đó nhờ pháp bảo và trận pháp trấn đảo.","thanhVien":[{"ten":"Khô trúc lão nhân","chucVu":"một trong hải ngoại tam tiên","tuChuong":"@c0965","trangThai":"danh nghĩa"}],"tabs":{"tienTrinh":[{"chuong":"@c0965","loai":"nhắc tới","importance":"normal","giaiDoan":"Khô trúc lão nhân","text":"Khô trúc lão nhân được hải ngoại tu sĩ coi là một trong hải ngoại tam tiên nhờ các chỗ dựa trên Khô trúc đảo.","anchor":"đã sớm được giới hải ngoại tu sĩ coi là một trong hải ngoại tam tiên"}]},"capNhatToi":"@c0965","nguon":["@c0965"]},{"id":"nam-cuong-doc-thanh-mon","name":"Nam Cương Độc Thánh môn","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Nam Cương","nhanVatChinh":[],"blurb":"Tông môn ở Nam Cương được Khô Trúc nhắc tới khi nghi khôi lỗi Lệ đạo hữu dùng Linh văn thuật. Môn này nổi danh với Linh văn thuật trong nhận định của Khô Trúc.","detail":"Trong lúc khôi lỗi hiện ký hiệu đủ màu và vòng bảo hộ ngũ sắc, Khô Trúc hỏi đối phương có xuất thân từ Nam Cương Độc Thánh môn hay không. Ông liên hệ biểu hiện đó với Linh văn thuật nổi danh của môn này, dù khôi lỗi phủ nhận.","dacDiem":"Nổi danh với Linh văn thuật theo lời Khô Trúc.","quanHe":[{"ten":"Khôi lỗi hình người","loai":"bị nghi liên quan","chuong":"@c0967"}],"tabs":{"tienTrinh":[{"chuong":"@c0967","loai":"nhắc tới","importance":"normal","giaiDoan":"Khô Trúc nghi ngờ khôi lỗi","text":"Khô Trúc nhắc Nam Cương Độc Thánh môn khi nghi khôi lỗi dùng Linh văn thuật của môn này.","anchor":"đạo hữu chẳng lẽ xuất thân từ Nam Cương độc Thánh môn"}]},"capNhatToi":"@c0967","nguon":["@c0967"]},{"id":"bach-xao-vien","name":"Bách Xảo Viện","cn":"","type":"tong-mon","typeLabel":"Tông môn luyện khí","diaBan":"Đại Tấn","nhanVatChinh":["Hàn Lập"],"blurb":"Bách Xảo Viện được nhắc qua phế hỏa mạch từng khiến Hàn Lập chú ý. Sau biến cố ở Đại Tấn, hắn cho rằng không còn khả năng mượn nơi đó luyện linh liêu.","detail":"Khi chọn địa điểm luyện linh liêu cho Tam Diễm Phiến, Hàn Lập nhớ tới phế hỏa mạch của Bách Xảo Viện nhưng gạt bỏ vì tình thế hiện tại khiến việc mượn nơi đó không còn khả năng.","tabs":{"tienTrinh":[{"chuong":"@c0969","loai":"nhắc tới","importance":"normal","giaiDoan":"Không thể mượn hỏa mạch","text":"Hàn Lập loại khả năng dùng phế hỏa mạch Bách Xảo Viện để luyện linh liêu.","anchor":"chuyện này tự nhiên không còn khả năng rồi"}]},"capNhatToi":"@c0969","nguon":["@c0969"]},{"id":"cac-tong-mon-nam-cuong","name":"Các tông môn Nam Cương","cn":"","type":"lien-minh-khu-vuc","typeLabel":"Thế lực khu vực","diaBan":"Nam Cương","nhanVatChinh":["Vương sư tỷ","Bảy tám tu sĩ địa phương trên đỉnh Song Hạt Sơn"],"blurb":"Các tông môn Nam Cương gồm hơn mười thế lực cùng quản lý tài nguyên trong vùng. Họ thường tranh đấu nội bộ nhưng sẽ liên thủ chống thế lực ngoài, khiến các đại tông môn chính ma khó chen chân.","detail":"Nam Cương không thuộc riêng một đại tông môn nào mà do hơn mười tông môn địa phương chia sẻ lợi ích. Cấu trúc bài ngoại, pháp môn âm độc, độc thuật, côn trùng thuật, tà thuật và bùa chú khiến khu vực này gần như có tư thế riêng trong Đại Tấn.","quyMo":"Hơn mười tông môn địa phương","quanHe":"Bình thường tranh đấu lẫn nhau, khi có thế lực ngoài xâm nhập thì liên thủ đối phó.","trangThai":"đang tồn tại @c0970","nguon":["@c0970"],"tabs":{"tienTrinh":[{"chuong":"@c0970","loai":"nhắc tới","importance":"normal","giaiDoan":"Giới thiệu cấu trúc Nam Cương","text":"Các tông môn Nam Cương được giới thiệu là nhóm thế lực cùng quản lý tài nguyên, bài ngoại và có khả năng liên thủ chống xâm nhập.","anchor":"Những tông môn này mặc dù lúc bình thường thì không ngừng tranh đấu, nhưng một khi có thế lực khác xâm nhập Nam Cương"}]},"capNhatToi":"@c0970"},{"id":"chinh-ma-thap-dai-tong-mon-dai-tan","name":"Chính ma thập đại tông môn Đại Tấn","cn":"","type":"lien-minh-khac","typeLabel":"Các đại tông môn chính ma","diaBan":"Đại Tấn","nhanVatChinh":[],"blurb":"Chính ma thập đại tông môn Đại Tấn được nhắc như đối trọng với khu vực Nam Cương. Dù thế lực lớn, họ vẫn khó xâm nhập Nam Cương vì sự liên thủ bài ngoại của các tông môn địa phương và hệ pháp môn độc dị nơi đó.","detail":"Chương dùng chính ma thập đại tông môn để nhấn mạnh độ khép kín của Nam Cương. Ngay cả các thế lực hàng đầu của Đại Tấn cũng không thể dễ dàng đưa thế lực vào vùng này.","trangThai":"khó xâm nhập Nam Cương @c0970","quanHe":"Bị cấu trúc liên thủ của các tông môn Nam Cương ngăn cản khi muốn mở rộng ảnh hưởng vào vùng này.","nguon":["@c0970"],"tabs":{"tienTrinh":[{"chuong":"@c0970","loai":"nhắc tới","importance":"normal","giaiDoan":"Khó chen chân vào Nam Cương","text":"Chương nêu ngay cả chính ma thập đại tông môn cũng không thể đưa thế lực xâm nhập Nam Cương.","anchor":"Cho dù là chánh ma thập đại tông môn, cũng vô phương đem thế lực xâm nhập vào trong đó"}]},"capNhatToi":"@c0970"},{"id":"bac-minh-dao","name":"Bắc Minh đảo","cn":"","type":"dia-ban-the-luc","typeLabel":"Địa bàn thế lực","diaBan":"Bắc Minh đảo","nhanVatChinh":["Bạch Dao Di"],"blurb":"Bắc Minh đảo là nơi Bạch Dao Di dùng để giới thiệu thân phận khi gặp Hàn Lập.","detail":"Bạch Dao Di tự xưng là tu sĩ Bắc Minh đảo và đồng thời là ngoại sự trưởng lão Tiểu Cực cung. Trong chương này, Bắc Minh đảo gắn trực tiếp với thân phận của nàng khi đến nơi hẹn của lão giả họ Phú.","thanhVien":[{"ten":"Bạch Dao Di","chucVu":"Tu sĩ Bắc Minh đảo","tuChuong":"@c0971","trangThai":"gan-bo"}],"tabs":{"tienTrinh":[{"chuong":"@c0971","loai":"nhắc tới","importance":"normal","giaiDoan":"Bạch Dao Di tự giới thiệu","text":"Bạch Dao Di tự xưng đến từ Bắc Minh đảo khi hỏi Hàn Lập về ước hẹn của Phú đạo hữu.","anchor":"Thiếp thân là Bắc Minh đảo Bạch Dao Di"}]},"capNhatToi":"@c0971","nguon":["@c0971"]},{"id":"thien-ma-mon","name":"Thiên ma môn","cn":"","aliases":[],"type":"tong-mon","typeLabel":"Tông môn","diaBan":"Đại Tấn","nhanVatChinh":["Phong Thiên Hành"],"blurb":"Thiên ma môn được nhắc qua thân phận của Phong Thiên Hành. Người này là tiền lệ mà lão giả họ Phú dùng để răn đe về Minh hà chi trang.","detail":"Chương này chưa nêu thêm cấu trúc hay địa bàn cụ thể của Thiên ma môn, chỉ xác định Phong Thiên Hành thuộc thế lực này và cái chết của hắn liên quan lời cảnh báo về Minh hà chi trang.","thanhVien":[{"ten":"Phong Thiên Hành","chucVu":"không rõ","tuChuong":"@c0973","trangThai":"đã chết"}],"tabs":{"tienTrinh":[{"chuong":"@c0973","loai":"nhắc tới","importance":"bridge","giaiDoan":"Tiền lệ Minh hà chi trang","text":"Thiên ma môn được nhắc qua Phong Thiên Hành, người được dùng làm ví dụ cảnh báo về hậu quả liên quan Minh hà chi trang.","anchor":"Năm xưa Phong Thiên Hành của Thiên ma môn chết đi như thế nào"}]},"capNhatToi":"@c0973","nguon":["@c0973"]},{"id":"doc-thanh-mon","name":"Độc thánh môn","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Chưa rõ","nhanVatChinh":["Đại hán họ Nguyên","Độc Thánh môn tứ lão"],"blurb":"Độc thánh môn là tông môn của đại hán họ Nguyên. Chương này cho thấy môn phái có sở trường liên quan đến độc hoặc ích độc.","detail":"Khi lão giả họ Phú nhắc cần chuẩn bị bảo vật ích độc trước khi vào Vạn độc cốc, đại hán họ Nguyên nói việc này đối với Độc thánh môn chỉ là chuyện nhỏ. Điều đó xác lập thế mạnh của môn phái trong việc ứng phó độc vật.","dacDiem":"Có sở trường chuẩn bị thủ đoạn ích độc.","thanhVien":[{"ten":"Đại hán họ Nguyên","chucVu":"Tu sĩ trong môn","tuChuong":"@c0974","trangThai":"đang hoạt động"},{"ten":"Độc Thánh môn tứ lão","chucVu":"bốn lão tu sĩ","tuChuong":"@c1005","trangThai":"đang hành động riêng"}],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c0974","loai":"nhắc tới","importance":"normal","giaiDoan":"Sở trường ích độc","text":"Đại hán họ Nguyên cho biết chuẩn bị ích độc là chuyện nhỏ với Độc thánh môn.","anchor":"chuyện này đối với Độc thánh môn chúng ta mà nói chỉ là chuyện nhỏ"},{"chuong":"@c1005","loai":"nhắc tới","importance":"normal","giaiDoan":"Tứ lão bỏ nhóm","text":"Bốn lão của Độc Thánh môn lặng lẽ rời khỏi Tử Vi Tinh trận trước khi nhóm còn lại phát hiện.","anchor":"Bốn lão gia hỏa của Độc Thánh môn đâu! Bọn họ không ngờ lại biết trận này"}]},"nguon":["@c0974","@c1005"],"trangThai":"tứ lão đang tách khỏi nhóm phá trận @c1005"},{"id":"cac-dai-tong-mon-nam-xua","name":"Các đại tông môn năm xưa","cn":"","type":"lien-minh","typeLabel":"Các thế lực chưa nêu tên","diaBan":"Đại Tấn","nhanVatChinh":[],"blurb":"Các đại tông môn năm xưa là nhóm thế lực từng âm thầm nhắm vào Thất thúc Diệp gia. Tên cụ thể chưa được nêu trong chương này.","detail":"Theo lời quái nhân Diệp gia, các đại tông môn năm xưa nhận thấy ông có tiềm lực tiến giai hậu kỳ nên âm thầm ra tay. Việc này là một nguyên nhân khiến Diệp gia an bài cái chết giả để che giấu ông.","quanHe":"Từng đối địch ngầm với Diệp gia và nhắm vào Thất thúc Diệp gia.","tabs":{"tienTrinh":[{"chuong":"@c0974","loai":"nhắc tới","importance":"normal","giaiDoan":"Ám hại Thất thúc","text":"Các đại tông môn năm xưa từng âm thầm ra tay vì nhận thấy Thất thúc Diệp gia có tiềm lực tiến giai hậu kỳ.","anchor":"những đại tông môn năm xưa đối với ta âm thầm xuất thủ"}]},"nguon":["@c0974"]},{"id":"ha-gia","name":"Hà gia","cn":"","type":"gia-toc","typeLabel":"Tu tiên gia tộc","diaBan":"Nam Cương","nhanVatChinh":["Trung niên hoàng bào tu sĩ Hà gia"],"blurb":"Tu tiên gia tộc từng nhận quy thuận Âm La tông rồi đổi ý và trốn tới Nam Cương. Chương này Hà gia bị Âm La tông vây diệt, bảy mươi hai tu sĩ bị giết và phàm nhân còn lại cũng bị hạ lệnh diệt sạch.","detail":"Hà gia bị Đại trưởng lão Âm La tông xem là phản lại lời quy thuận, nên Âm La tông tổ chức vây công trang viên tại Nam Cương để giữ danh tiếng tông môn. Sau khi cấm chế bị phá, bảy mươi hai tu sĩ Hà gia bị tiêu diệt, ba trăm phàm nhân còn lại cũng bị ra lệnh giết sạch.","trangThai":"bị diệt","quyMo":"Bảy mươi hai tu sĩ và khoảng ba trăm phàm nhân được nhắc trong trận diệt tộc.","quanHe":"Từng đáp ứng quy thuận Âm La tông rồi đổi ý.","thanhVien":[{"ten":"Trung niên hoàng bào tu sĩ Hà gia","chucVu":"người cầm đầu trong trận vây diệt","tuChuong":"@c0979","trangThai":"tử vong"}],"tabs":{"tienTrinh":[{"chuong":"@c0979","loai":"diệt/sáp nhập","importance":"major","giaiDoan":"Bị Âm La tông diệt tộc","text":"Hà gia bị Âm La tông vây diệt tại Nam Cương, bảy mươi hai tu sĩ bị giết và phàm nhân còn lại cũng bị ra lệnh giết sạch.","anchor":"Hà gia tu sĩ bảy mươi hai người toàn bộ đã bị tiêu diệt","trangThaiMoc":"bị diệt"}]},"capNhatToi":"@c0979","nguon":["@c0979"]},{"id":"tu-si-ben-ngoai-bi-thien-tuong-kinh-dong","name":"Tu sĩ bên ngoài bị thiên tượng kinh động","cn":"","type":"nhom-tu-si","typeLabel":"Nhóm tu sĩ tiềm tàng","diaBan":"Đại Tấn","nhanVatChinh":[],"blurb":"Nhóm tu sĩ bên ngoài mà Diệp gia lo sẽ bị thiên tượng ở tiểu hồ Nam Cương kinh động kéo tới. Đại trưởng lão Diệp gia tuyên bố nếu họ gây trở ngại thì sẽ ra tay giết sạch.","detail":"Khi bạch sắc quang trụ và sáu quang trụ phụ lộ ra trên tiểu hồ Nam Cương, Diệp gia lo thiên tượng sẽ dẫn tu sĩ bên ngoài tới. Đại trưởng lão Diệp gia xem đây là nguy cơ có thể xử trí bằng sát thủ đoạn, tuyên bố cùng lắm đem đám tu sĩ mò đến giết sạch.","trangThai":"có nguy cơ kéo tới tiểu hồ Nam Cương","quanHe":[{"doiTuong":"Diệp gia","trangThai":"nguy cơ đối đầu"}],"tabs":{"tienTrinh":[{"chuong":"@c0989","loai":"nhắc tới","importance":"normal","giaiDoan":"Nguy cơ ngoại nhân kéo tới","text":"Diệp gia dự liệu tu sĩ bên ngoài có thể bị thiên tượng kinh động kéo tới và chuẩn bị giết sạch nếu cần.","anchor":"cùng lắm là đem đám tu sĩ mò đến đây giết sạch"}]},"capNhatToi":"@c0989","nguon":["@c0989"]},{"id":"su-mon-cua-nhom-tu-si-lam-bao","name":"Sư môn của nhóm tu sĩ lam bào","cn":"","type":"tong-mon","typeLabel":"Sư môn","diaBan":"Nam Cương","nhanVatChinh":["Tu sĩ ngăm đen cầm đầu nhóm lam bào","Dư sư đệ","Nhóm tu sĩ lam bào đầu quấn hồng sắc triền đầu"],"blurb":"Một sư môn ở Nam Cương có nhóm đệ tử lam bào đầu quấn hồng sắc triền đầu hoạt động gần nơi thiên tượng xuất hiện. Khi thấy quang trụ, nhóm này lập tức cử người về báo tin.","detail":"Thế lực này được nhắc qua hành động của nhóm tu sĩ lam bào. Người cầm đầu sai Dư sư đệ về báo cáo thiên tượng, báo hiệu tin Côn Ngô sơn lan tới thêm một thế lực địa phương.","thanhVien":[{"ten":"Tu sĩ ngăm đen cầm đầu nhóm lam bào","chucVu":"người cầm đầu nhóm đi ngoài","tuChuong":"@c0990","trangThai":"hoạt động"},{"ten":"Dư sư đệ","chucVu":"đệ tử đưa tin","tuChuong":"@c0990","trangThai":"hoạt động"}],"tabs":{"tienTrinh":[{"chuong":"@c0990","loai":"nhắc tới","importance":"normal","giaiDoan":"Nhận tin thiên tượng","text":"Nhóm tu sĩ lam bào cử Dư sư đệ về sư môn báo cáo thiên tượng quang trụ.","anchor":"Dư sư đệ, ngươi nhanh trở về sư môn báo cáo việc này"}]},"nguon":["@c0990"]},{"id":"cac-the-gia-an-tu-tan-tu-quanh-nam-cuong","name":"Các thế gia, ẩn tu, tán tu quanh Nam Cương","cn":"","type":"khac","typeLabel":"Quần thể tu sĩ","diaBan":"Nam Cương","nhanVatChinh":[],"blurb":"Các nhóm tu sĩ quanh Nam Cương bị thiên tượng và tin bảo khố hấp dẫn. Họ lần lượt bay về phía quang trụ, khiến cục diện Côn Ngô sơn nhanh chóng lan rộng.","detail":"Sau khi bảy đạo quang trụ xuất hiện và tin bảo khố lan ra, tu sĩ thế gia, ẩn tu và tán tu trong phạm vi rộng đều hướng về nơi phát sinh dị tượng.","tabs":{"tienTrinh":[{"chuong":"@c0990","loai":"nhắc tới","importance":"normal","giaiDoan":"Đổ về quang trụ","text":"Các thế gia, ẩn tu và tán tu quanh Nam Cương đều bị tin bảo khố cuốn vào và bay tới hướng quang trụ.","anchor":"bất luận là phụ cận tu sĩ của thế gia hay là ẩn tu, tán tu đều hướng về phía quang trụ phi độn mà đến"}]},"nguon":["@c0990"]},{"id":"cac-tong-mon-va-gia-toc-quanh-pho-van-phu","name":"Các tông môn và gia tộc quanh Phổ Vân phủ","cn":"","type":"khac","typeLabel":"Các thế lực địa phương","diaBan":"quanh Phổ Vân phủ","nhanVatChinh":[],"blurb":"Nhiều tông môn, gia tộc lớn nhỏ quanh Phổ Vân phủ nhận tin dị tượng phong ấn và phái người đến thăm dò.","detail":"Khi bảy cột sáng và phong ấn khổng lồ dưới tiểu hồ bị phát hiện, nhiều tu sĩ truyền tin về tông môn hoặc gia tộc của mình. Vì khu vực hẻo lánh, lúc này chưa có tu sĩ Nguyên Anh kỳ xuất hiện, nhưng hiện trường đã trở thành nơi long xà hỗn tạp.","quyMo":"nhiều thế lực lớn nhỏ trong khu vực","trangThai":"đang bị dị tượng phong ấn thu hút","capNhatToi":"@c0993","tabs":{"tienTrinh":[]},"nguon":["@c0993"]},{"id":"thuong-co-tu-si-con-ngo-son","name":"Thượng cổ tu sĩ Côn Ngô sơn","cn":"","type":"quần thể","typeLabel":"Quần thể tu sĩ thượng cổ","diaBan":"Côn Ngô sơn","nhanVatChinh":[],"blurb":"Quần thể thượng cổ tu sĩ từng tập trung tại Côn Ngô sơn theo lời Bạch Dao Di. Lão giả họ Phú suy đoán trong núi có thể còn động phủ của họ, nhưng phần lớn đã rời đi từ lâu.","detail":"Bạch Dao Di nói Côn Ngô sơn thời cổ đại là nơi các thượng cổ tu sĩ tập trung. Sau khi nhóm nhận ra nơi mình tới chính là linh sơn này, Lão giả họ Phú suy đoán trong núi có thể còn nhiều động phủ thượng cổ tu sĩ, dù chủ nhân các động phủ đã rời đi.","nguonGoc":"quần thể tu sĩ thượng cổ từng tụ tập ở Côn Ngô sơn","trangThai":"đã rời đi theo suy đoán","thanhVien":[],"tabs":{"tienTrinh":[{"chuong":"@c0994","loai":"nhắc tới","importance":"normal","giaiDoan":"Lai lịch Côn Ngô","text":"Bạch Dao Di nhắc Côn Ngô sơn là nơi thượng cổ tu sĩ tập trung, mở ra suy đoán về các động phủ còn sót lại trong núi.","anchor":"Là nơi các thượng cổ tu sĩ tập trung"}]},"capNhatToi":"@c0994","nguon":["@c0994"]},{"id":"con-ngo-tam-lao","name":"Côn Ngô Tam Lão","cn":"","type":"nhom-co-xua","typeLabel":"Nhóm nhân vật cổ xưa","diaBan":"Côn Ngô Sơn","nhanVatChinh":["Côn Ngô Tam Lão"],"blurb":"Nhóm cổ xưa gắn với Côn Ngô Sơn và tầng cấm chế cuối. Họ từng dùng vạn nhân chi lực bố trí cấm chế ngăn Nữ tử bí ẩn thoát ra.","detail":"Côn Ngô Tam Lão được Nữ tử bí ẩn nhắc tới khi giải thích vì sao nàng chưa thể rời khỏi nơi bị phong tỏa. Tầng cấm chế cuối do họ dùng vạn nhân chi lực bố trí vượt quá khả năng một mình nàng có thể xé bỏ.","nguonGoc":"Nhóm cổ xưa liên quan Côn Ngô Sơn.","trangThai":"được nhắc qua cấm chế để lại","tabs":{"tienTrinh":[{"chuong":"@c0995","loai":"nhắc tới","importance":"normal","giaiDoan":"Cấm chế cuối được hé lộ","text":"Côn Ngô Tam Lão được nhắc là nhóm dùng vạn nhân chi lực bố trí tầng cấm chế cuối.","anchor":"Côn Ngô Tam Lão dùng tới vạn nhân chi lực, bố trí cuối cùng một tầng cấm chế"}]},"capNhatToi":"@c0995","nguon":["@c0995"]},{"id":"chinh-ma-thap-dai-tong-mon","name":"Chính Ma thập đại tông môn","cn":"","type":"tong-mon","typeLabel":"Nhóm tông môn","diaBan":"Đại Tấn","nhanVatChinh":[],"blurb":"Nhóm các đại tông môn Chính Ma được Hoa Thiên Kỳ nhắc tới như thế lực có thể nhúng tay vào phong ấn nếu tin tức kéo dài lan rộng.","detail":"Hoa Thiên Kỳ lo rằng nếu Độc Thánh môn không nhanh chóng nắm thời cơ, các đại tông môn Chính Ma sẽ biết và chen vào cuộc tranh đoạt phong ấn Côn Ngô.","nguon":["@c0996"]},{"id":"hoa-tien-tong","name":"Hoá Tiên tông","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"gần khu vực phong ấn","nhanVatChinh":["Mộc phu nhân","Nữ tử tú lệ Hóa Tiên tông","Hai nữ tử Hóa Tiên Tông"],"blurb":"Tông môn được Kiền lão ma nhắc là có vẻ gần khu vực phong ấn hơn Độc Thánh môn. Tên này xuất hiện trong cuộc đối đáp giữa Kiền lão ma và Hoa Thiên Kỳ.","detail":"Kiền lão ma dùng Hoá Tiên tông để bác lập luận nơi phong ấn gần địa bàn Độc Thánh môn, qua đó biện minh cho việc mình nhúng tay vào cửa vào phong ấn.","nguon":["@c0996","@c1004","@c1014","@c1034"],"tabs":{"tienTrinh":[{"chuong":"@c1014","loai":"nhắc tới","importance":"major","giaiDoan":"Lộ lai lịch và trách nhiệm","text":"Mộc phu nhân hé lộ Hóa Tiên tông là tông môn nửa ẩn dật do hậu nhân Côn Ngô tam lão lập ra, có trách nhiệm trông coi phong ấn Côn Ngô Sơn.","anchor":"Tổ sư lập phái của bổn tông vốn chính là hậu nhân của Côn Ngô tam lão","trangThaiMoc":"can dự phong ấn Côn Ngô Sơn"}]},"trangThai":"đang can dự biến cố Côn Ngô Sơn","thanhVien":[{"ten":"Mộc phu nhân","chucVu":"tu sĩ Hóa Tiên tông","tuChuong":"@c1014","trangThai":"đang hoạt động"},{"ten":"Nữ tử tú lệ Hóa Tiên tông","chucVu":"sư muội của Mộc phu nhân","tuChuong":"@c1014","trangThai":"đang hoạt động"},{"ten":"Hai nữ tử Hóa Tiên Tông","chucVu":"nữ tu","tuChuong":"@c1034","trangThai":"được nhắc tới"}]},{"id":"ba-hau-nhan-con-ngo","name":"Ba hậu nhân Côn Ngô","cn":"","type":"nhom","typeLabel":"Nhóm hậu nhân","diaBan":"Côn Ngô Sơn","nhanVatChinh":["Phụ nhân áo đen","Ngân Sí Dạ Xoa","Sư cầm thú"],"blurb":"Nhóm hậu nhân Côn Ngô từng dùng Khốn Linh trận giam các yêu vật trong núi. Theo phụ nhân áo đen, mục đích của họ là buộc các yêu vật bảo hộ Côn Ngô Sơn.","detail":"Ba hậu nhân Côn Ngô được nhắc qua lời phụ nhân áo đen như những người đã giam giữ các yêu vật bằng Khốn Linh trận. Việc giam giữ này còn liên quan tới bổn mệnh bài khiến các yêu vật dù thoát trận vẫn chưa thể rời khỏi Côn Ngô Sơn.","nguon":["@c1002"],"trangThai":"được nhắc qua chuyện cũ @c1002","capNhatToi":"@c1002","tabs":{"tienTrinh":[{"chuong":"@c1002","loai":"nhắc tới","importance":"normal","giaiDoan":"Chuyện giam yêu vật","text":"Phụ nhân áo đen nói ba hậu nhân Côn Ngô từng dùng Khốn Linh trận giam các yêu vật để bắt bảo hộ núi.","anchor":"không phải là muốn bắt chúng ta thay bọn họ bảo hộ núi này sao chứ"}]}},{"id":"tu-di-tong","name":"Tu Di tông","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Nam Cương","nhanVatChinh":[],"blurb":"Đại tông ở Nam Cương, có trấn tông chi bảo là Tu Di Ngũ Hành Bích.","detail":"Tu Di tông được lão giả Diệp gia nhắc là một trong các đại tông của Nam Cương và có uyên nguyên với Độc Thánh môn. Trấn tông chi bảo Tu Di Ngũ Hành Bích của tông này xuất hiện trong tay Độc Thánh môn, được dùng để phong kín lối vào tầng kế tiếp và hóa giải kiếm quang của đại đầu quái nhân.","nguon":["@c1010"]},{"id":"thap-dai-tong-mon","name":"Thập đại tông môn","cn":"","type":"lien-minh","typeLabel":"Nhóm tông môn","diaBan":"Đại Tấn","nhanVatChinh":[],"blurb":"Nhóm thế lực lớn được nữ tử tú lệ dùng làm chuẩn so sánh khi nói về công pháp bí thuật của Hóa Tiên tông.","detail":"Nữ tử tú lệ cho rằng nếu chỉ luận công pháp bí thuật thì Hóa Tiên tông chưa chắc yếu hơn thập đại tông môn, qua đó dùng nhóm này làm thước đo thế lực ở Đại Tấn.","tabs":{"tienTrinh":[{"chuong":"@c1014","loai":"nhắc tới","importance":"bridge","giaiDoan":"Chuẩn so sánh thế lực","text":"Thập đại tông môn được nhắc như thước đo để nữ tử tú lệ so sánh công pháp bí thuật của Hóa Tiên tông.","anchor":"chỉ luận công pháp bí thuật, chỉ sợ không nhất định yếu hơn thập đại tông môn","trangThaiMoc":"được nhắc tới"}]},"nguon":["@c1014"]},{"id":"thanh-toc","name":"Thánh tộc","cn":"","type":"ma-toc","typeLabel":"Thánh giới ma tộc","diaBan":"Thánh giới","nhanVatChinh":["Cổ ma","Nguyên Sát thánh tổ","Nguyên Sát thánh tổ hóa thân"],"blurb":"Phe ma tộc được cổ ma gọi là thánh tộc. Cổ ma nói người được quán chú ma khí thành công về sau cũng sẽ trở thành một thành viên của thánh tộc.","detail":"Trong lời giải thích với Diệp Nguyệt Thánh, cổ ma giới thiệu Nguyên Sát thánh tổ là thánh tổ của thánh giới và từng là một trong ba thống lĩnh thánh tộc xuống nhân giới. Việc quán chú ma khí được đặt như cách chuyển hóa người ngoài thành thành viên thánh tộc.","nguon":["@c1016"],"nguonGoc":"Thánh giới","thanhVien":[{"ten":"Cổ ma","chucVu":"thành viên ma tộc","tuChuong":"@c1016","trangThai":"đang hoạt động"},{"ten":"Nguyên Sát thánh tổ","chucVu":"thánh tổ, thống lĩnh","tuChuong":"@c1016","trangThai":"được nhắc tới"}],"trangThai":"được hé lộ qua lời cổ ma","capNhatToi":"@c1016","tabs":{"tienTrinh":[{"chuong":"@c1016","loai":"nhắc tới","importance":"normal","giaiDoan":"Hé lộ thánh tộc","text":"Cổ ma nói người được quán chú ma khí sẽ trở thành thành viên thánh tộc và nhắc Nguyên Sát thánh tổ từng thống lĩnh thánh tộc xuống nhân giới.","anchor":"về sau cũng sẽ thành một thành viên của thánh tộc chúng ta"}]}},{"id":"bay-dai-yeu-vuong-linh-gioi","name":"Bảy đại yêu vương linh giới","cn":"","type":"nhom-cuong-gia","typeLabel":"Nhóm cường giả","diaBan":"Linh giới","nhanVatChinh":["Thiên Khuê Thần Lang"],"blurb":"Nhóm bảy yêu vương lớn của Linh giới, được nhắc qua thân phận Thiên Khuê Thần Lang. Lai lịch này làm nổi bật thân phận đặc biệt của Ngân Nguyệt yêu lang.","detail":"Hắc sắc lang thủ nói Thiên Khuê Thần Lang là một trong bảy đại yêu vương Linh giới, còn Ngân Nguyệt yêu lang là sủng phi của ông ta và là một trong số ít chân thân Linh giới phủ xuống Nhân giới.","thanhVien":[{"ten":"Thiên Khuê Thần Lang","chucVu":"yêu vương","tuChuong":"@c1017","trangThai":"được nhắc tới"}],"tabs":{"tienTrinh":[{"chuong":"@c1017","loai":"nhắc tới","importance":"normal","giaiDoan":"Lộ tuyến yêu vương Linh giới","text":"Bảy đại yêu vương Linh giới được nhắc qua thân phận Thiên Khuê Thần Lang và quan hệ với Ngân Nguyệt yêu lang.","anchor":"một trong linh giới bảy đại yêu vương Thiên Khuê Thần Lang"}]},"capNhatToi":"@c1017","nguon":["@c1017"]},{"id":"co-tu-nhan-loai-phong-an-con-ngo","name":"Cổ tu nhân loại phong ấn Côn Ngô","cn":"","type":"nhom-co-tu","typeLabel":"Nhóm cổ tu","diaBan":"Côn Ngô Sơn","nhanVatChinh":["Côn Ngô Tam lão"],"blurb":"Nhóm cổ tu nhân loại từng xử lý thân thể Ngân Nguyệt bị thánh tổ chiếm cứ và thiết lập phong ấn lâu dài ở Côn Ngô Sơn. Họ không thể bức thánh tổ ra khỏi thân thể nên dùng Trấn ma tháp, cung điện linh khí và cấm chế cả ngọn núi để duy trì thế giam giữ.","detail":"Theo lời hắc sắc lang thủ, cổ tu nhân loại biết thân thể Ngân Nguyệt có lai lịch đặc biệt nên không dám hủy diệt cả thân thể. Họ biến nơi phong ấn thành chỗ không linh khí, rút lang hồn thứ hai đặt vào cung điện linh khí sung túc để định kỳ trở lại tranh quyền khống chế, rồi về sau cấm chế cả Côn Ngô Sơn khi không thừa nhận tân hồn đã dung hợp.","thanhVien":[{"ten":"Côn Ngô Tam lão","chucVu":"cổ tu tham chiến phong ấn","tuChuong":"@c1017","trangThai":"được nhắc tới"}],"tabs":{"tienTrinh":[{"chuong":"@c1017","loai":"nhắc tới","importance":"normal","giaiDoan":"Phong ấn Côn Ngô","text":"Nhóm cổ tu nhân loại được nhắc là lực lượng đã phong ấn thánh tổ trong thân Ngân Nguyệt và cấm chế cả Côn Ngô Sơn.","anchor":"hoàn toàn đem toàn bộ cả quả núi này cấm chế"}]},"capNhatToi":"@c1017","nguon":["@c1017"]},{"id":"con-ngo-dien","name":"Côn Ngô Điện","cn":"","type":"di-tich","typeLabel":"Di tích","diaBan":"Côn Ngô Sơn","nhanVatChinh":["Côn Ngô tam lão","Mộc phu nhân","Hàn Lập"],"blurb":"Côn Ngô Điện là trung tâm di tích nơi các bảo vật trọng yếu được đặt trên bàn án. Chương này lộ rõ trong điện còn cấm chế cuối của Côn Ngô tam lão nhằm phòng yêu tà đoạt bảo.","detail":"Không chỉ là địa điểm đặt bảo vật, Côn Ngô Điện còn có hệ thống cấm chế, đường ngầm và cơ chế thần niệm liên hệ Tam nhân vọng nguyệt đồ. Cấm chế cuối được kích hoạt khi Mộc Khôi định đoạt bảo, cho thấy di tích này vẫn vận hành cơ chế phòng hộ do tiền nhân để lại.","tabs":{"tienTrinh":[{"chuong":"@c1020","loai":"nhắc tới","importance":"normal","giaiDoan":"Cấm chế cuối kích hoạt","text":"Côn Ngô Điện lộ cấm chế cuối do Côn Ngô tam lão bố trí để ngăn yêu tà đoạt các bảo vật trọng yếu.","anchor":"mà cố ý trong Côn Ngô Điện bố trí một đạo cấm chế cuối cùng"}]},"nguon":["@c1020"]},{"id":"con-ngo-tam-lao-nhom-tien-boi","name":"Côn Ngô tam lão","cn":"","type":"nhom-tien-boi","typeLabel":"Nhóm tiền bối","diaBan":"Côn Ngô Điện","nhanVatChinh":["Côn Ngô tam lão"],"blurb":"Côn Ngô tam lão là nhóm tiền bối để lại bố trí bảo vệ bảo vật trong Côn Ngô Điện. Họ lưu ngân bài khống chế cấm chế và thần niệm trong Tam nhân vọng nguyệt đồ.","detail":"Nhóm gồm ba hình tượng một đạo, một nho, một tăng trong Tam nhân vọng nguyệt đồ. Bố trí của họ vừa cho phép tạm khống chế một phần cấm chế bằng ngân bài, vừa kích hoạt thần niệm và bảo vật để diệt yêu tà chạm tới bảo vật.","thanhVien":[{"ten":"Côn Ngô tam lão","chucVu":"Ba tiền bối lưu thần niệm","tuChuong":"@c1020","trangThai":"chỉ hiện thần niệm"}],"tabs":{"tienTrinh":[{"chuong":"@c1020","loai":"nhắc tới","importance":"normal","giaiDoan":"Lộ bố trí trong điện","text":"Côn Ngô tam lão được xác nhận đã để lại ngân bài và thần niệm trong bức họa để bảo vệ bảo vật khỏi yêu tà.","anchor":"Nhìn kỹ thì thấy rõ ràng là ba người trong “Tam nhân vọng nguyệt đồ”"}]},"nguon":["@c1020"]},{"id":"tieu-cuc-cung","name":"Tiểu Cực Cung","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"chưa rõ trong chương","nhanVatChinh":["Bạch Dao Di"],"blurb":"Thế lực của Bạch Dao Di được Hàn Lập chủ động hỏi đường bái phỏng sau biến cố Trấn Ma tháp.","detail":"Trước khi chia tay, Hàn Lập hỏi Bạch Dao Di về việc muốn đến Tiểu Cực Cung bái phỏng. Bạch Dao Di đáp bổn cung hoan nghênh Hàn Lập tới, nhưng sau khi hắn đi thì nghi hoặc vì sao hắn muốn đến nơi này.","thanhVien":[{"ten":"Bạch Dao Di","chucVu":"tu sĩ của bổn cung","tuChuong":"@c1031","trangThai":"đang gắn bó"}],"quanHe":"Hàn Lập bày tỏ ý muốn bái phỏng Tiểu Cực Cung.","tabs":{"tienTrinh":[{"chuong":"@c1031","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập hỏi đường bái phỏng","text":"Hàn Lập chủ động hỏi Bạch Dao Di về việc muốn bái phỏng Tiểu Cực Cung, khiến nàng nhận lời nhưng sinh nghi về mục đích của hắn.","trangThaiMoc":"được nhắc tới","anchor":"Bổn cung đương nhiên hoan nghênh Hàn đạo hữu tới"},{"chuong":"@c1075","loai":"xuất hiện","importance":"major","trangThaiMoc":"hưng","giaiDoan":"Lần đầu giới thiệu chi tiết","text":"Lần đầu mô tả chi tiết Tiểu Cực cung — bắc địa đệ nhất tông, thực lực ngang thập đại tông Đại Tấn, hệ thống nội/ngoại cung, thử thách xuyên mười vạn lý cực hàn, đại trận Thận Lâu Thạch hộ sơn. Hàn Lập đang tìm đường tới đây.","anchor":"bắc dạ Tiểu Cực cung, được xưng là bắc địa đệ nhất tông"}]},"capNhatToi":"@c1031","nguon":["@c1031","@c1075"],"trangThai":"hưng thịnh","aliases":["bắc dạ Tiểu Cực cung","Bắc Tiên cung"]},{"id":"bich-lan-nhai","name":"Bích Lân Nhai","cn":"","aliases":[],"type":"the-luc","typeLabel":"Thế lực tu tiên","diaBan":"Đại Tấn","nhanVatChinh":["Vũ đạo hữu"],"blurb":"Thế lực của Vũ đạo hữu, người có độc công nổi danh Đại Tấn. Đại diện của họ xuất hiện ngoài vết nứt phong ấn Côn Ngô Sơn.","detail":"Vũ đạo hữu của Bích Lân Nhai xuất hiện trong lục vụ trước lối vào phong ấn, khiến Huyền Thanh Tử phải chú ý. Danh tiếng độc công của ông khiến thế lực này được nhắc trong bối cảnh các tu sĩ Đại Tấn tụ tập tranh cơ duyên.","thanhVien":[{"ten":"Vũ đạo hữu","chucVu":"tu sĩ độc công","tuChuong":"@c1033","trangThai":"có mặt ngoài vết nứt"}],"tabs":{"tienTrinh":[{"chuong":"@c1033","loai":"nhắc tới","importance":"normal","giaiDoan":"Đại diện xuất hiện","text":"Vũ đạo hữu của Bích Lân Nhai xuất hiện ngoài vết nứt phong ấn và gây thêm sức ép cho Huyền Thanh Tử.","anchor":"Nguyên Lai là Vũ đạo hữu của Bích Lân Nhai cũng đã đến"}]},"nguon":["@c1033"]},{"id":"ngan-nguyet-toc","name":"Ngân Nguyệt tộc","cn":"","type":"chung-toc","typeLabel":"Chủng tộc","diaBan":"Không rõ","nhanVatChinh":["Lung Mộng","Ngân Nguyệt","Lung nhi"],"blurb":"Ngân Nguyệt tộc là chủng tộc của Lung Mộng và Tuyết Linh. Tộc này có bí thuật vô thượng liên quan nguyên thần, từng khiến Lung nhi phân tách thành hai nguyên thần do luyện sai.","detail":"Lung Mộng tự nhận bí thuật vô thượng kia thuộc Ngân Nguyệt tộc chúng ta. Qua lời nàng, Lung nhi thuộc tộc này và vì ứng phó thiên kiếp thứ hai đã tu luyện bí thuật đó, dẫn tới sự phân tách giữa Lung Mộng và Tuyết Linh.","tonChi":"","capBac":"Không rõ","thanhVien":[{"ten":"Lung Mộng","chucVu":"Không rõ","tuChuong":"@c1036","trangThai":"đang hoạt động"},{"ten":"Ngân Nguyệt","chucVu":"Tuyết Linh","tuChuong":"@c1036","trangThai":"đang hoạt động"},{"ten":"Lung nhi","chucVu":"Trạng thái hợp nhất trước kia","tuChuong":"@c1036","trangThai":"đã phân tách"}],"quanHe":"Có liên hệ với Lang tộc qua thân phận Tuyết Linh.","tabs":{"tienTrinh":[{"chuong":"@c1036","loai":"nhắc tới","importance":"normal","giaiDoan":"Hé lộ bí thuật nguyên thần","text":"Lung Mộng nói bí thuật vô thượng khiến Lung nhi phân tách nguyên thần thuộc Ngân Nguyệt tộc.","anchor":"bí thuật vô thượng của Ngân Nguyệt tộc chúng ta"}]},"capNhatToi":"@c1036","nguon":["@c1036"]},{"id":"co-ma-xam-lan-nhan-gioi","name":"Cổ ma xâm lấn nhân giới","cn":"","type":"nhom-ma-toc","typeLabel":"Nhóm cổ ma","diaBan":"Nhân giới thời thượng cổ","nhanVatChinh":["Nguyên Sát thánh tổ","Nữ tử váy đen"],"blurb":"Nhóm cổ ma từng xâm lấn Nhân giới thời thượng cổ. Ngân Nguyệt cho biết tinh hồn đang chiếm thân thể cũ của nàng thuộc hàng một trong tam đại thống lĩnh của cuộc xâm lấn này.","detail":"Qua lời Ngân Nguyệt, luồng tinh hồn cổ ma thánh tổ trong nữ tử váy đen là một trong tam đại thống lĩnh của cổ ma khi xâm lấn Nhân giới. Cuộc xâm lấn này gắn với việc sát hại vô số cổ tu sĩ và là bối cảnh để Cửu Chân Phục Ma đại trận từng diệt sát thượng cổ yêu ma.","lanhDaoHienThoi":"Nguyên Sát thánh tổ phân hồn","capBac":"thống lĩnh cổ ma","quanHe":"Đối địch với tu sĩ Nhân giới thời thượng cổ và các thế lực đang ở Côn Ngô Sơn.","trangThai":"tàn dư tinh hồn hiện thân","thanhVien":[{"ten":"Nguyên Sát thánh tổ","chucVu":"một trong tam đại thống lĩnh","tuChuong":"@c1038","trangThai":"tinh hồn hiện thân qua nữ tử váy đen"}],"tabs":{"tienTrinh":[{"chuong":"@c1038","loai":"nhắc tới","importance":"normal","giaiDoan":"Lộ thống lĩnh cổ ma","text":"Ngân Nguyệt nói luồng tinh hồn trong nữ tử váy đen là cổ ma từng xâm lấn Nhân giới và thuộc hàng một trong tam đại thống lĩnh.","anchor":"cũng là cổ ma năm đó xâm lấn nhân giới, là một trong tam đại thống lĩnh","trangThaiMoc":"tàn dư tinh hồn hiện thân"}]},"capNhatToi":"@c1038","nguon":["@c1038"]},{"id":"linh-gioi-yeu-toc","name":"Linh giới Yêu Tộc","cn":"","type":"chung-toc","typeLabel":"Chủng tộc","diaBan":"Linh giới","nhanVatChinh":["Lung Mộng"],"blurb":"Linh giới Yêu Tộc được nhắc qua thân phận Hóa Thần hậu kỳ của Lung Mộng. Ở Nhân giới, thần thông cấp này cũng bị thiên địa nguyên khí đại biến hạn chế.","detail":"Hắc bào nữ tử dùng thân phận Linh giới Yêu Tộc của Lung Mộng để chỉ ra rằng ngay cả tồn tại Hóa Thần hậu kỳ đến từ Linh giới cũng khó phát huy trọn vẹn đại thần thông trong hoàn cảnh Nhân giới hiện tại.","trangThai":"được nhắc tới","capNhatToi":"@c1039","nguon":["@c1039"]},{"id":"mo-lan","name":"Mộ Lan","cn":"","type":"bo-toc","typeLabel":"Thế lực thảo nguyên","diaBan":"không rõ","nhanVatChinh":["Thanh niên họ Từ"],"blurb":"Mộ Lan là thế lực gắn với thanh niên họ Từ, người được gọi là Đại Tiên Sư của Mộ Lan trong biến cố Côn Ngô Sơn.","detail":"Trong lúc bị kẹt giữa ác phong của Hắc Phong Kỳ, Đại Tiên Sư của Mộ Lan cùng Lâm Ngân Bình tìm Hàn Lập để bàn cách liên thủ thoát khỏi nơi nguy hiểm.","thanhVien":[{"ten":"Thanh niên họ Từ","chucVu":"Đại Tiên Sư","tuChuong":"@c1040","trangThai":"đang hoạt động"}],"tabs":{"tienTrinh":[]},"capNhatToi":"@c1040","nguon":["@c1040"]},{"id":"co-ma-gioi","name":"Cổ Ma giới","cn":"","type":"gioi-dien","typeLabel":"Giới diện ma đạo","diaBan":"Cổ Ma giới","nhanVatChinh":[],"blurb":"Giới diện ma đạo được nhắc là nguồn truyền đến Chân Ma Chi Khí khi Cổ Ma mở thông đạo nối với Nhân Giới.","detail":"Theo lời Lung Mộng, Chân Ma Chi Khí dưới Tế Đàn rất có thể đến từ Cổ Ma giới sau khi Cổ Ma mở thông đạo nối với Nhân Giới. Loại khí này mang tính chất khác ma khí phổ thông, có thể ma hóa tu sĩ và về lâu dài chuyển hóa Nhân Giới thành tồn tại tương tự Cổ Ma giới.","nguon":["@c1056"]},{"id":"linh-gioi","name":"Linh Giới","cn":"","type":"gioi-dien","typeLabel":"Giới diện thượng giới","diaBan":"Linh Giới","nhanVatChinh":["Lung Mộng","Vạn Niên Thi Hùng"],"blurb":"Giới diện mà Lung Mộng và Vạn Niên Thi Hùng liên hệ, được xem là nơi có thể có biện pháp xử lý Chân Ma Chi Khí tốt hơn Nhân Giới.","detail":"Lung Mộng nói nếu ở Linh Giới có lẽ còn có cách thanh trừ Chân Ma Chi Khí. Vạn Niên Thi Hùng cũng muốn mượn nghịch linh thông đạo để phản hồi Linh Giới, nên bị Lung Mộng buộc phải tiếp tục hộ pháp cho kế hoạch thu hồi thân thể của nàng.","nguon":["@c1056"]},{"id":"nhan-gioi","name":"Nhân Giới","cn":"","type":"gioi-dien","typeLabel":"Giới diện","diaBan":"Nhân Giới","nhanVatChinh":[],"blurb":"Giới diện đang bị Chân Ma Chi Khí đe dọa ma hóa nếu phong ấn dưới Tế Đàn bị phá vỡ.","detail":"Lung Mộng cảnh báo Chân Ma Chi Khí không phải ma khí phổ thông; nếu tồn tại lâu dài, nó có thể chuyển hóa Nhân Giới thành tồn tại giống Cổ Ma giới. Nàng cũng cho rằng nếu loại khí này thật sự thoát ra, nhân loại tu sĩ hiện tại muốn phong ấn lại sẽ rất khó.","nguon":["@c1056"]},{"id":"bo-toc-ngan-nguyet","name":"Bộ tộc Ngân Nguyệt","cn":"","type":"chung-toc","typeLabel":"Yêu tộc","diaBan":"không rõ","nhanVatChinh":["Linh Lung"],"blurb":"Bộ tộc của Linh Lung, nơi nàng giữ thân phận đại công chúa.","detail":"Linh Lung tự xưng là đại công chúa bộ tộc Ngân Nguyệt, cho thấy thân phận thật của nàng cao hơn thân phận khí linh Ngân Nguyệt từng xuất hiện bên Hàn Lập.","nguon":["@c1060"],"thanhVien":[{"ten":"Linh Lung","chucVu":"đại công chúa","tuChuong":"@c1060","trangThai":"đang thuộc"}],"tabs":{"tienTrinh":[{"chuong":"@c1060","loai":"nhắc tới","importance":"normal","giaiDoan":"lộ thân phận đại công chúa","text":"Linh Lung công khai mình là đại công chúa của bộ tộc Ngân Nguyệt.","anchor":"Ta là đại công chúa bộ tộc Ngân Nguyệt, Linh Lung"}]},"capNhatToi":"@c1060"},{"id":"ngan-nguyet-lang-toc","name":"Ngân Nguyệt Lang Tộc","aliases":["Ngân Nguyệt đại tộc"],"cn":"银月狼族","type":"chung-toc","typeLabel":"Chủng tộc / Đại tộc","diaBan":"Linh giới","nhanVatChinh":["Linh Lung","Thiên Khuê Lang Vương"],"blurb":"Đại tộc ở Linh giới, Linh Lung là công chúa của tộc này. Trưởng lão trong tộc đã thiết lập pháp trận riêng cho nàng trở về.","detail":"Ngân Nguyệt Lang Tộc là đại tộc ở Linh giới. Linh Lung tự xưng là công chúa, phi tử của Thiên Khuê Lang Vương. Trưởng lão trong tộc đã thiết lập pháp trận chuyên môn cho Linh Lung, kích phát ấn ký Nghịch Tinh Bàn sẽ mở Nghịch Linh Thông Đạo nhỏ riêng cho nàng trở về Linh giới. Tộc sở hữu thiên phú thần thông riêng.","nguonGoc":"Đại tộc Linh giới","thanhVien":[{"ten":"Linh Lung","chucVu":"Công chúa, Vương Phi","tuChuong":"@c1066","trangThai":"hoat-dong"},{"ten":"Thiên Khuê Lang Vương","chucVu":"Lang Vương (phu quân Linh Lung)","tuChuong":"@c1066","trangThai":"khong-ro"}],"nguon":["@c1066"],"tabs":{"tienTrinh":[{"chuong":"@c1066","loai":"xuat-hien","importance":"major","giaiDoan":"Linh Lung tiết lộ thân phận","trangThaiMoc":"Linh Lung công chúa tiết lộ thân phận và ấn ký pháp trận tộc","text":"Linh Lung tự xưng là công chúa Ngân Nguyệt Lang Tộc, phi tử Thiên Khuê Lang Vương. Trưởng lão trong tộc đã lập pháp trận riêng cho nàng trở về Linh giới qua Nghịch Linh Thông Đạo nhỏ.","anchor":"Bản thân lại là công chúa của Ngân Nguyệt Lang Tộc"}]}},{"id":"ly-gia-tuyet-lien-phong","name":"Lý gia (Tuyết Liên Phong)","cn":"李家","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Tuyết Liên Phong, Sương Quận","nhanVatChinh":["Lý Trung Khiêm"],"blurb":"Gia tộc tu sĩ nhỏ ở Tuyết Liên Phong thuộc Sương Quận, tộc trưởng Lý Trung Khiêm (Kết Đan trung kỳ). Bị Hàn Lập đuổi khỏi lãnh địa.","detail":"Tiểu gia tộc tu tiên tọa lạc tại Tuyết Liên Phong trong Sương Quận. Tộc trưởng Lý Trung Khiêm tu vi Kết Đan trung kỳ, có hai trưởng bối Trúc Cơ hậu kỳ. Bị Hàn Lập (biến dạng thành lão giả mặt dê) phóng khí thế bao trùm toàn núi, ra lệnh rút toàn bộ trong nửa ngày.","nguonGoc":"Gia tộc tu sĩ tu luyện tại Sương Quận","lanhDaoHienThoi":"Lý Trung Khiêm","quyMo":"Tiểu gia tộc","trangThai":"Bị đuổi khỏi lãnh địa","thanhVien":[{"ten":"Lý Trung Khiêm","chucVu":"Tộc trưởng","tuChuong":"@c1071","trangThai":"hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c1071","loai":"mất địa bàn","importance":"major","giaiDoan":"Bị đuổi khỏi Tuyết Liên Phong","trangThaiMoc":"Mất lãnh địa","text":"Hàn Lập phóng khí thế bao trùm toàn bộ Tuyết Liên Phong, ra lệnh Lý gia rút toàn bộ trong nửa ngày để hắn tiếp nhận ngọn núi.","anchor":"Vãn bối là Lý Trung Khiêm là tộc trưởng của Lý gia ở ngọn núi Tuyết Liên Phong này"}]},"capNhatToi":"@c1071","nguon":["@c1071"]},{"id":"tuyet-lien-that-huu","name":"Tuyết Liên thất hữu","cn":"","type":"nhom","typeLabel":"Nhóm tu sĩ","diaBan":"Tuyết Liên sơn (đã mất)","nhanVatChinh":[],"blurb":"Bảy tu sĩ từng chiếm cứ linh mạch Tuyết Liên sơn trước khi bị Lý gia đánh bại và mất núi.","detail":"Nhóm bảy tu sĩ từng chiếm cứ Tuyết Liên sơn, sau đó bị Lý gia đánh bại và mất quyền kiểm soát linh mạch. Chỉ được nhắc qua lời lão tổ Lý gia.","nguon":["@c1072"]},{"id":"tru-gia-suong-quan","name":"Trữ gia sương quận","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Sương Quận","nhanVatChinh":[],"blurb":"Gia tộc tu tiên ở Sương Quận, nữ tu họ Trữ tự xưng xuất thân từ đây.","detail":"Nữ tu họ Trữ (Luyện Khí kỳ) tự xưng là đệ tử Trữ gia sương quận khi bị Hàn Lập chất vấn.","nguon":["@c1076"]},{"id":"hu-thien-dien","name":"Hư Thiên điện","cn":"虚天殿","type":"co-dai","typeLabel":"Tổ chức cổ đại","diaBan":"","nhanVatChinh":[],"blurb":"Thế lực hoặc tổ chức thượng cổ bí ẩn, Hàn Lập nghi vấn Tiểu Cực Cung có quan hệ với Hư Thiên điện khi phát hiện cự đỉnh giống Hư Thiên đỉnh.","detail":"Được Hàn Lập nhắc tới trong nội tâm khi phát hiện cự đỉnh chứa Kiền lam băng diễm trong đại sảnh Hàn Ly thượng nhân có hình dạng giống Hư Thiên đỉnh bảy tám phần. Hàn Lập không rõ Tiểu Cực Cung có quan hệ gì với Hư Thiên điện, nên quyết giấu kín bí mật về Hư Thiên đỉnh.","nguon":["@c1080"],"tabs":{"tienTrinh":[{"chuong":"@c1080","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập nghi vấn mối liên hệ với Tiểu Cực Cung","text":"Hàn Lập phát hiện cự đỉnh trong sảnh Hàn Ly giống Hư Thiên đỉnh bảy tám phần, nghi vấn Tiểu Cực Cung có quan hệ với Hư Thiên điện.","anchor":"không rõ Tiểu cực cung có quan hệ gì với Hư Thiên điện hay không"}]}},{"id":"huyen-bang-cung","name":"Huyền Băng Cung","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"","nhanVatChinh":[],"blurb":"Một thế lực được nhắc đến tại Bắc Minh đảo, đệ tử Huyền Băng Cung phát hiện vị trí Băng Linh Hoa nhưng bị Tuyết Hống thú đuổi đánh trọng thương.","detail":"Đệ tử Huyền Băng Cung phát hiện vị trí Băng Linh Hoa nằm trong sào huyệt Tuyết Hống thú, gần vượt phạm vi Bắc Minh đảo, bị Tuyết Hống thú đuổi đánh trọng thương.","nguon":["@c1082"]},{"id":"lien-minh-yeu-thu-bang-hai","name":"Liên minh yêu thú Băng Hải","cn":"","type":"lien-minh","typeLabel":"Liên minh","diaBan":"Băng Hải và phụ cận Bắc Minh đảo","nhanVatChinh":["Thanh Bối Thương Lang","Song Đầu Ô Giao"],"blurb":"Liên minh giữa phó cốc chủ Vạn Yêu Cốc Thanh Bối Thương Lang và mãnh thú Băng Hải Song Đầu Ô Giao, tập hợp nhiều yêu thú Hóa Hình cao giai từ Băng Hải và đại lục.","detail":"Bạch Dao Di phát hiện nhóm yêu thú Hóa Hình cao giai tụ hội gồm yêu thú Băng Hải lẫn đại lục, do Thanh Bối Thương Lang và Song Đầu Ô Giao cầm đầu. Hàn Ly Thượng Nhân kết luận Vạn Yêu Cốc và yêu thú Băng Hải đã liên thủ, đe dọa Tiểu Cực Cung.","nguon":["@c1085"],"tabs":{"tienTrinh":[{"chuong":"@c1085","loai":"lien-minh","importance":"major","giaiDoan":"Thành lập","text":"Bạch Dao Di phát hiện Thanh Bối Thương Lang cùng Song Đầu Ô Giao dẫn nhóm Hóa Hình yêu thú tụ hội. Hàn Ly xác nhận hai phe liên thủ, Tiểu Cực Cung chuyển sang phòng bị khẩn cấp.","anchor":"cầm đầu đúng là một vị phó cốc chủ Vạn Yêu Cốc Thanh Bối Thương Lang cùng mãnh thú Song Đầu Ô Giao tiếng tăm lừng lẫy trong Băng hải"}]}},{"id":"lieu-thuy-phai","name":"Liễu Thúy phái","cn":"柳翠派","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Không rõ","nhanVatChinh":["Long phu nhân"],"blurb":"Môn phái của Long phu nhân (đại trưởng lão), có công pháp đặc thù giúp nữ tu bảo trì thanh âm lúc trẻ.","detail":"Long phu nhân là đại trưởng lão Liễu Thúy phái, tu vi Nguyên Anh hậu kỳ. Phái có công pháp đặc thù cho phép bảo trì thanh âm trẻ trung dù ngoại hình đã già.","thanhVien":[{"ten":"Long phu nhân","chucVu":"Đại trưởng lão","tuChuong":"@c1086","trangThai":"tai-chuc"}],"nguon":["@c1086"]},{"id":"bang-uyen-dao","name":"Băng Uyên đảo","cn":"","type":"the-luc-yeu","typeLabel":"Thế lực yêu tu","diaBan":"Băng Uyên đảo","nhanVatChinh":["Phượng tiên tử"],"blurb":"Lãnh địa của Phượng tiên tử (thập cấp yêu thú). Phe nàng có hơn hai mươi bát cấp yêu thú, tạm liên minh với Vạn Yêu cốc để tấn công Tiểu Cực cung.","detail":"Thế lực yêu tu trên Băng Uyên đảo, do Phượng tiên tử cai quản. Nàng bế quan tại đảo hai ngàn năm, lần này tự mình xuất mã dẫn hơn hai mươi bát cấp yêu thú tấn công Tiểu Cực cung. Hai phe yêu thú (Băng Uyên đảo và Vạn Yêu cốc) thuỷ hoả bất dung nhưng tạm hợp tác vì mục tiêu chung liên quan tới phi thăng linh giới.","lanhDaoHienThoi":"Phượng tiên tử","quyMo":"Hơn hai mươi bát cấp yêu thú + một thập cấp (Phượng tiên tử)","quanHe":"Tạm liên minh với Vạn Yêu cốc, đối địch Tiểu Cực cung","trangThai":"dang-hoat-dong","thanhVien":[{"ten":"Phượng tiên tử","chucVu":"Đảo chủ","tuChuong":"@c1092","trangThai":"dang-hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c1092","loai":"khai chiến","importance":"major","giaiDoan":"Tấn công Tiểu Cực cung","text":"Phượng tiên tử dẫn hơn hai mươi bát cấp yêu thú tới Bắc Minh Đảo tấn công Tiểu Cực cung, tạm liên minh với Vạn Yêu cốc. Mục đích thật liên quan tới phi thăng linh giới và diệt nhất mạch tu sĩ Băng Phách tiên tử.","anchor":"sự tình mà liên quan tới việc phi thăng linh giới, bản đảo chủ làm sao có thể yên tâm cho thủ hạ đi làm được"}]},"nguon":["@c1092"]}]};
